CREATE TABLE `characters` (
  `name` varchar(100) NOT NULL,
  `rarity` int(11) DEFAULT NULL CHECK (`rarity` in (4,5)),
  `path` varchar(50) DEFAULT NULL,
  `element` varchar(50) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `version` float DEFAULT NULL,
  `novaflare` tinyint(1) DEFAULT 0,
  `eng_va` varchar(60) DEFAULT NULL,
  `jpn_va` varchar(60) DEFAULT NULL,
  `cn_va` varchar(60) DEFAULT NULL,
  `kr_va` varchar(60) DEFAULT NULL,
  `light_cone` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`name`),
  KEY `fk_characters_light_cone` (`light_cone`),
  CONSTRAINT `fk_characters_light_cone` FOREIGN KEY (`light_cone`) REFERENCES `light_cones` (`name`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
