INSERT INTO `characters` VALUES ('Acheron',5,'Nihilidad','Rayo','Acheron es un personaje 5★ del elemento <span class=\"element\">Rayo</span> que sigue la Via de la <span class=\"path\">Nihilidad</span>.<br><br>Una viajera que dice ser una Vigilante de la Galaxia.<br><br>Nadie sabe su verdadero nombre.<br><br>Deambula sola por el cosmos, llevando consigo una larga espada.',2.1,0,'Allegra Clark','沢城みゆき (Sawashiro Miyuki)','菊花花 (Juhuahua)','박지윤 (Park Ji-yoon)',NULL),('Aglaea',5,'Reminiscencia','Rayo','Aglaea es un personaje 5★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Reminiscencia</span>.<br><br>En esa ciudad sagrada besada por el amanecer, la tejedora acaricia el hilo dorado y conecta el destino.<br><br>Aglaea la Tejedora de Oro, la Heredera de Chrysos que porta la Llama del Núcleo del \"Romance\"...<br><br>Invocarás a los héroes de este mundo y los guiarás para que se embarquen una vez más en un viaje interminable donde derribarán a los dioses, devolverán el <span class=\"element\">Fuego</span> divino y concederán el renacimiento a la tierra moribunda de Amphoreus.',3,0,NULL,'Endou Aya (遠藤 綾)','Chu Yue (楚越)','Oh Ro-ah (오로아)',NULL),('Anaxa',5,'Erudición','Viento','Anaxa es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>La Arboleda de la Epifanía, donde florece el conocimiento y nacen los filósofos.<br><br>Sin embargo, aquí se encuentra Anaxágoras el blasfemo, el Heredero de Chrysos que desafía la Llama del Núcleo de la Razón: ¿De verdad abrazarías la infamia y desafiarías la profecía, clavando las espinas de la duda en el Árbol Sagrado de la sabiduría?',3.2,0,'Stephen Fu','Uchida Yuma (内田 雄馬)','Qian Wenqing (钱文青)','Lee Sang-jun (이상준)',NULL),('Archer',5,'Cacería','Cuántico','Archer es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>La desesperación se repite en ciclos del pasado y el futuro.<br><br>Innumerables grandes ideales fueron incinerados ante esa tela roja y sagrada.<br><br>Sin embargo, no dejes que esta mancha de cenizas te engañe...<br><br>Si alguien creara un dulce sueño fantasmal bajo la apariencia de falsos ideales, entonces arderá de nuevo, enfrentándose a los hipócritas del mundo hasta el final.<br><br>Sin importar dónde esté, siempre sigue siendo el fiel compañero de la justicia.',3.4,0,NULL,NULL,NULL,NULL,NULL),('Argenti',5,'Erudición','Físico','Argenti es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>Un caballero clásico de los Caballeros de la Belleza.<br><br>Directo y franco, este noble y admirable hombre vaga solo por el cosmos, siguiendo resueltamente la Vía de la Belleza.<br><br>Defender el buen nombre de la Belleza es el deber de Argenti.<br><br>Para cumplir con esta responsabilidad, uno debe ser piadoso al iniciar la batalla, y debe hacer que su oponente se rinda voluntariamente al atacar con su lanza.',1.5,0,'Adam Michael Gold','立花慎之介 (Tachibana Shinnosuke)','梁达伟 (Liang Dawei)','최승훈 (Choi Seung-hoon)',NULL),('Arlan',4,'Destrucción','Rayo','Arlan es un personaje 4★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>El poco articulado jefe del Departamento de Seguridad de la Estación Espacial Herta.<br><br>Aunque la investigación científica está más allá de su comprensión, Arlan está dispuesto a arriesgar su vida para proteger al personal que tanto valora la investigación.<br><br>Está acostumbrado al dolor y lleva sus cicatrices como insignias de honor.<br><br>Solo cuando sostiene a Peppy, el chico finalmente baja la guardia y muestra una sonrisa poco común.',1,0,'Dani Chambers','Shiraishi Ryoko (白石涼子)','Dian Tao (陶典)','김율',NULL),('Ashveil',5,'Cacería','Rayo','Ashveil es un personaje 5★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Actúa por capricho, con una deducción implacable...<br><br>Se basa puramente en la intuición, y sin embargo resuelve extraños casos una y otra vez.<br><br>Con un mono como asistente, la jubilación es su único objetivo.<br><br>En cuanto al detective que duerme en la nevera...<br><br>solo está esperando un bocado voluntario.<br><br>Bajo la Luna Fantasma, la vil bestia aúlla.<br><br>¿Cómo llegará a su fin su juego de persecución implacable?',4.1,0,'Blythe Melin','子安 武人 (Koyasu Takehito)','张沛 (Zhang Pei)','강수진 (Kang Soo-jin)',NULL),('Asta',4,'Armonía','Fuego','Asta es un personaje 4★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Una joven ferozmente inquisitiva y enérgica, es la Investigadora Principal de la Estación Espacial Herta.<br><br>Ya sea manejando a un personal obstinado o respondiendo de manera cortés pero firme al Gremio de Eruditos, Asta lo controla todo sin esfuerzo.<br><br>Después de todo...<br><br>¡dirigir una estación espacial es mucho más fácil que hacerse cargo de una empresa!',1,0,'Felecia Angelle','Akasaki Chinatsu (赤﨑千夏)','Guiniang (龟娘)','김현지',NULL),('Aventurine',5,'Conservación','Imaginario','Aventurine es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Conservación</span>.<br><br>Un alto directivo del Departamento de Inversión Estratégica de la CPI y uno de los Diez Corazones de Piedra.<br><br>Su piedra angular es \"Aventurina de las estratagemas\".<br><br>Posee un aire de frivolidad y no teme asumir riesgos.<br><br>Su sonrisa constante hace que sea difícil para la gente discernir sus verdaderos sentimientos.<br><br>Ganó su posición actual apostando contra el propio destino.<br><br>Ve la vida como una inversión de alto riesgo y alta rentabilidad, y juega esta apuesta en particular con una facilidad magistral.',2.1,0,'Camden Sutkowski','河西健吾 (Kawanishi Kengo)','杨超然 (Yang Chaoran)','박준원 (Park Jun-won)',NULL),('Bailu',5,'Abundancia','Rayo','Bailu es un personaje 5★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Abundancia</span>.<br><br>Una vivaz joven de la raza Vidyadhara, es conocida como la \"Dama Sanadora\" debido a su experiencia en medicina.<br><br>A menudo da recetas poco ortodoxas como \"Manténgase bien hidratado\" y \"Duerma bien por la noche\".<br><br>Bailu no puede soportar ver sufrir a la gente, y por eso la verás con los ojos fuertemente cerrados mientras cura las dolencias.<br><br>\"Mientras se curen, eso es todo lo que importa, ¿verdad?\"',1,0,'Su Ling Chan','Emiri Katō (加藤 英美里)','Duoduo Poi (多多poi)',NULL,NULL),('Black Swan',5,'Nihilidad','Viento','Black Swan es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>Una Guardamemorias del Jardín de los Recuerdos.<br><br>Una adivina misteriosa y elegante.<br><br>Luce una cálida sonrisa y está dispuesta a escuchar pacientemente a los demás, utilizando este medio como pretexto para adentrarse en sus \"recuerdos\" y comprender el flujo de toda la información.<br><br>Le apasiona coleccionar recuerdos únicos, pero los pensamientos que la guían son difíciles de descifrar.',2,1,'Arryn Zech','生天目仁美 (Hitomi Nabatame)','杨梦露 (Yang Menglu)','김하영 (Kim Ha-Young)',NULL),('Blade',5,'Destrucción','Viento','Blade es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Un espadachín que abandonó su cuerpo para convertirse en una espada.<br><br>Nombre de nacimiento desconocido.<br><br>Jura lealtad al Esclavo del Destino y posee una aterradora habilidad de autocuración.<br><br>Blade empuña una espada antigua plagada de grietas, al igual que su cuerpo y su mente.',1.2,1,'Daman Mills','Miki Shinichiro (三木眞一郎)','Liu Yijia (刘以嘉)','Kwak Yoon-sang (곽윤상)',NULL),('Boothill',5,'Cacería','Físico','Boothill es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Un vaquero cíborg que vaga entre las estrellas.<br><br>Extremadamente optimista y desenfrenado.<br><br>Es un miembro de los Vigilantes de la Galaxia que juró castigar a los malvados por todos los medios...<br><br>Sus acciones extravagantes y descaradas fueron todas para llamar la atención de la Corporación para la Paz Interastral, el objetivo de su venganza.',2.2,0,'Andrew Russell','小西克幸 (Konishi Katsuyuki)','彭博 (Peng Bo)','김단 (Kim Dan)',NULL),('Bronya',5,'Armonía','Viento','Bronya es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Heredera de la Guardiana Suprema de Belobog, es la joven y capaz comandante de la Guardia Crinargéntea.<br><br>Bronya recibió una educación rigurosa desde temprana edad y posee la elegancia y afinidad que se esperan de una heredera.<br><br>Sin embargo, después de presenciar las pésimas condiciones del Bajamundo, comenzaron a crecer semillas de duda en la mente de la futura líder de Belobog.<br><br>\"¿Podrá todo el entrenamiento que he recibido ayudarme realmente a guiar al pueblo hacia la vida que desea?\"',1,0,'Madeline Reiter','Asumi Kana (阿澄佳奈)','谢莹','이보희',NULL),('Castorice',5,'Reminiscencia','Cuántico','Castorice es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Reminiscencia</span>.<br><br>\"Sierva de la Muerte\" Castorice.<br><br>La tierra que venera a la muerte, Aidonia, donde la nieve cae sin cesar, se ha sumido hoy en un dulce sueño.<br><br>Castorice, hija del Río de las Almas, Heredera de Chrysos en busca de la Llama del Núcleo de la \"Muerte\", se pone en marcha.<br><br>Debes custodiar el lamento de las almas y abrazar la soledad del destino.<br><br>La vida y la muerte no son más que un viaje.<br><br>Cuando la mariposa se posa en la rama, lo que se marchita florecerá de nuevo.',3.2,0,'Melody Muze','Saitou Chiwa (斎藤 千和)','Ruan Congqing (阮从青)','Lee Serena (이세레나)',NULL),('Cerydra',5,'Armonía','Viento','Cerydra es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>El Imperio del Norte, una dinastía perdida, donde las tierras heladas arden con ambiciones de conquista.<br><br>Soberana Cerydra, Heredera de Chrysos que empuña la Llama del Núcleo de la \"Ley\", colocarás tus piezas, desafiarás a los dioses, juzgarás a los infieles y grabarás el camino de la Persecución de la Llama en el destino de este mundo.<br><br>\"Esto no es el final.<br><br>¡El camino de Amphoreus arderá a través de las estrellas!\"',3.5,0,NULL,'高尾 奏音 (Takao Kanon)','时欣蕾 (Shi Xinlei)','김윤채 (Kim Yun-chae)',NULL),('Cipher',5,'Nihilidad','Cuántico','Cipher es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>La ciudad perdida de los pícaros, Dolos, donde 300 Pícaros se deleitan en sus juegos, sin rendir cuentas a nadie.<br><br>Corre hacia adelante, veloz Estrella Ladrona Cifera, Heredera de Chrysos de la Llama del Núcleo del \"Engaño\", y que tu red de mentiras se extienda con la brisa por todas las tierras.',3.3,0,'Shea Fairaday','Ito Ayasa (伊藤 彩沙)','Wang Yaxin (王雅欣)','Mi So (미소)',NULL),('Clara',5,'Destrucción','Físico','Clara es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Una joven tímida y sin hogar, Clara no tuvo más remedio que unirse a los buscadores para sobrevivir.<br><br>Reactivó sin querer una reliquia inactiva de una civilización pasada: el robot Svarog.<br><br>\"Tener una familia\".<br><br>Esta es la respuesta de Clara cuando se le pregunta qué es lo que más desea.<br><br>Al poco tiempo, los buscadores, normalmente individualistas, se unieron bajo el liderazgo de Svarog.<br><br>Casi al mismo tiempo, un misterioso buscador fue visto en el Fragmentum, un espectro con capucha roja experto en recuperar reliquias raras de los lugares más peligrosos.<br><br>Los aterrorizados buscadores llaman a esta figura fantasmal...<br><br>el Conejo Sangriento.',1,0,'Emily Sun','Hidaka Rina (日高里菜)','Zisu (紫苏九月)','김예림',NULL),('Cyrene',5,'Reminiscencia','Hielo','Cyrene es un personaje 5★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Reminiscencia</span>.<br><br>Un meteoro surca el cielo nocturno, enviando ondas a través del río de la vida, brillando en trece tonos.<br><br>Hija de Aedes Elysiae, Heredera de Chrysos que nutre \"██\", siembra la Semilla de la Memoria, para que las flores del pasado puedan florecer en el mañana.<br><br>— \"Y juntos, escribiremos un verso como ningún otro antes ♪\"',3.7,0,'Aiden Dawn','Inoue Marina (井上 麻里奈)','Yanning (宴宁)','Jo Kyoung-i (조경이)',NULL),('Dan Heng',4,'Cacería','Viento','Dan Heng es un personaje 4★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Un joven frío y reservado que empuña una lanza conocida como Perforanubes.<br><br>Actúa como guardia del tren en su largo viaje de Trazacaminos.<br><br>Observa cuidadosamente los cambios en todo lo que le rodea, aunque con un comportamiento tranquilo que puede parecer indiferencia.<br><br>Registra fielmente todo lo que encuentran en su viaje en los archivos del Expreso.<br><br>Dan Heng nunca habla mucho de su pasado.<br><br>De hecho, se unió a la tripulación del Expreso para escapar de él.<br><br>Pero, ¿podrá realmente el Expreso alejarlo de su pasado?',1,0,'Nicholas Leung','Kento Itō (伊東健人)','Yú Dòng (魚凍)','Kim Hye-sung (김혜성)',NULL),('Dan Heng (Imbibitor Lunae)',5,'Destrucción','Imaginario','Dan Heng • Imbibitor Lunae es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>La verdadera forma de Dan Heng de su linaje Vidyadhara conlleva el poder residual dejado por su encarnación pasada, el Imbibitor Lunae.<br><br>Al aceptar los majestuosos cuernos sobre su corona, debe aceptar todos los méritos y culpas atribuidos a ese pecador.',1.3,0,'Nicholas Leung','Kento Itō (伊東健人)','Yú Dòng (魚凍)','Kim Hye-sung (김혜성)',NULL),('Dan Heng (Permansor Terrae)',5,'Conservación','Físico','Dan Heng • Permansor Terrae es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Conservación</span>.<br><br>El pecho de Georios y el cuerpo del dragón caminante cargan sobre sus hombros la tierra destrozada, soportando mil años de sufrimiento.<br><br>El Sin Nombre Dan Heng, Heredero de Chrysos que custodia la Llama del Núcleo de la Tierra, debes estabilizar el mundo mientras cae y guiar a toda la vida a lo largo de la tierra hacia un nuevo hogar más allá.',3.6,0,'Nicholas Leung','Kento Itō (伊東健人)','Yú Dòng (魚凍)','Kim Hye-sung (김혜성)',NULL),('Dr. Ratio',5,'Cacería','Imaginario','Dr.<br><br>Ratio es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Un miembro franco y egocéntrico del Gremio de Eruditos, que a menudo oculta su apariencia con una extraña escultura de yeso.<br><br>Demostró una inteligencia y talento incomparables desde su juventud, pero ahora se refiere a sí mismo como un \"Mundanita\".<br><br>Cree firmemente que el intelecto y la creatividad no se limitan a los genios.<br><br>Busca distribuir el conocimiento a todo el universo para curar la persistente enfermedad llamada ignorancia.',1.6,0,'Jordan Paul Haro','武内駿輔 (Takeuchi Shunsuke)','桑毓泽 (Sang Yuze)','이동훈 (Lee Donghoon)',NULL),('Evanescia',5,'Exultación','Físico','Evanescia es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Exultación</span>.<br><br>Una temporada de la Luna Fantasma en plenitud, una temporada de efimeridad mortal: ¡la misteriosa dama ha aparecido en Planarcadia una vez más! Los pétalos caídos se esparcen con facilidad, y su estancia no fue más que un instante fugaz.<br><br>Todo acerca de esta nueva era la cautiva, y no permitirá que nadie la lleve a la ruina...<br><br>Una cuchilla juzga el bien y el mal, pero ¿quién puede decir cuánto bien o mal reside dentro de uno mismo?',4.2,0,NULL,NULL,NULL,NULL,NULL),('Evernight',5,'Reminiscencia','Hielo','Evernight es un personaje 5★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Reminiscencia</span>.<br><br>En la recóndita Zona de los Recuerdos, la luz de las velas proyecta ecos del pasado, desvaneciéndose suavemente en la niebla.<br><br>Evernight, descendiente de la <span class=\"path\">Reminiscencia</span> nacido de la sombra, Heredero de Chrysos que oculta la Llama del Núcleo del Tiempo, agitarás la marea del Olvido, custodiando el deseo del alma reflejada.',3.6,0,'Skyler Davenport','Yui Ogura (小倉唯)','Nuò Yǎ (诺亚)','Jung Hye-Won (정혜원)',NULL),('Feixiao',5,'Cacería','Viento','Feixiao es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>La Garra de Merlín de la Xianzhou Yaoqing y una de los Siete Generales Árbitros.<br><br>Su personalidad es desinhibida y franca, audaz y directa.<br><br>Es experta en todas las formas de artes marciales y se ha perfeccionado hasta convertirse en un arma suprema.<br><br>Es muy adorada por los soldados y civiles de Xianzhou por igual como \"La Gran General\".<br><br>Sin embargo, soporta la carga de la aflicción de la Furia Lunar.<br><br>Si tuviera que cazar a todas las abominaciones en su limitada vida...<br><br>entonces el único enemigo que tendría Feixiao sería ella misma.',2.5,0,'Anairis Quinones','Mikako Komatsu (小松未可子)','Zhiqiu Ye (叶知秋)','Sohn Jeong Min (손정민)',NULL),('Firefly',5,'Destrucción','Fuego','Firefly es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Una miembro de los Cazadores de Estelaron y una joven enfundada en una armadura mecánica \"SAM\".<br><br>Nacida como un arma, padece la agonía del Síndrome de Pérdida Entrópica debido a una modificación genética.<br><br>Se unió a los Cazadores de Estelaron en busca del significado de la vida, persiguiendo implacablemente formas de desafiar al destino.',2.3,1,'Analesa Fisher & Adin Rudd','Kusunoki Tomori (楠木ともり) & Kasama Jun (笠間淳)','Song Yuanyuan (宋媛媛) & Gan Ziqi (淦子齐)','Yu Hye-ji (유혜지) & Jang Seo-hwa (장서화)',NULL),('Fu Xuan',5,'Conservación','Cuántico','Fu Xuan es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Conservación</span>.<br><br>La jefa de la Comisión de Adivinación del Luofu de Xianzhou.<br><br>Una sabia segura de sí misma y franca.<br><br>Usando su tercer ojo y la Matriz de la Presciencia, Fu Xuan calcula la ruta del Xianzhou y predice la fortuna de futuros eventos.<br><br>Cree firmemente que todo lo que hace es la \"mejor solución\" para la situación.<br><br>Fu Xuan está esperando la prometida \"abdicación\" del general.<br><br>Sin embargo, ese día todavía parece...<br><br>muy lejano.',1.3,0,'Sarah Wiedenheft','伊藤美来 (Miku Itō)','花玲 (Huā Líng)','이지현 (Lee Ji-hyeon)',NULL),('Fugue',5,'Nihilidad','Fuego','Fugue es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>Una discreta chica vulpina a la que le han robado la apariencia, el nombre y la identidad.<br><br>El destino le ha dejado un hilo de esperanza para sobrevivir, pero la marca de la <span class=\"path\">Destrucción</span> aún se retuerce de anticipación.<br><br>Aquella en estado de fuga que ha experimentado la vida y la muerte y a la que se le ha otorgado una nueva vida...<br><br>¿cuándo podrá regresar a casa?',2.7,0,'Anya Floris','高田 憂希 (Yūki Takada)','蒋丽 (Li Jiang)','이명호 (Lee Myeong-ho)',NULL),('Gallagher',4,'Abundancia','Fuego','Gallagher es un personaje 4★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Abundancia</span>.<br><br>Un oficial de seguridad de la Familia Sabueso en Colonipenal.<br><br>También es un coctelero desaliñado e indolente.<br><br>Aunque descuidado en su atuendo y casual en la forma en que prepara sus bebidas, siempre es cortés con los invitados, pero se mantiene alerta.<br><br>Parece ser un personaje con un pasado complicado, sin embargo, nunca menciona activamente ningún detalle.',2.1,0,'Erik Braa','三上哲 (Mikami Satohshi)','马语非 (Ma Yufei)','박상훈 (Park Sang-Hoon)',NULL),('Gepard',5,'Conservación','Hielo','Gepard es un personaje 5★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Conservación</span>.<br><br>Un capitán íntegro y noble de la Guardia Crinargéntea que lleva el nombre de la antigua familia Gepard.<br><br>En la ciudad de Belobog, azotada por las ventiscas, la defensa es mucho más desafiante que el ataque.<br><br>Gepard y la Guardia Crinargéntea que lidera sirven como la inquebrantable defensa de hierro de la Unión en este mundo hostil.<br><br>A veces es ridiculizado por su hermana y su ayudante por su actitud siempre escrupulosa, pero nadie puede negar que la gente de Belobog ha podido mantener la paz y la comodidad incluso con el invierno eterno a sus puertas...<br><br>Con la protección de Gepard, la ciudad puede continuar con su rutina diaria ordinaria.',1,0,'Bryson Baugus','Furukawa Makoto (古川慎)','Yang Ma (马洋)','민승우',NULL),('Guinaifen',4,'Nihilidad','Fuego','Guinaifen es un personaje 4★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>Una artista escénica de visita en el Luofu de Xianzhou, en otras palabras, una artista callejera.<br><br>Busca una nueva vida en el Luofu cuando no tiene que preocuparse por la comida y el refugio.',1.4,0,'Morgan Lauré','直田姫奈 (Suguta Hina)','小敢 (Xiaogan)','김수영 (Kim Soo-young)',NULL),('Hanya',4,'Armonía','Físico','Hanya es un personaje 4★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Una de las juezas de la Comisión de los Diez Líderes.<br><br>De los cuatro deberes de un juez (detención, encarcelamiento, castigo e interrogatorio), Hanya está a cargo de la última tarea.<br><br>Se especializa en leer el karma y los pecados de los criminales, y registra sus crímenes y castigos con el Pincel del Oráculo.<br><br>Como pasa sus días usando sueños para predecir ofensas kármicas y tiene que soportar el torrente de información sobre las acciones de los afectados por el mara, hace tiempo que se ha vuelto insensible a todas las cosas del mundo.<br><br>Solo cuando opera con su hermana y compañera jueza, Xueyi, Hanya revela momentáneamente su verdadera naturaleza.',1.5,0,'Suzie Yeung','铃代纱弓 (Suzushiro Sayumi)','张雨曦 (Zhang Yuxi)','v윤은서 (Yoon Eun-seo)',NULL),('Herta',4,'Erudición','Hielo','Herta es un personaje 4★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>La verdadera dueña de la Estación Espacial Herta.<br><br>Como la humana con el coeficiente intelectual más alto de El Azul, solo hace lo que le interesa, abandonando cualquier proyecto inmediatamente en el momento en que pierde el interés, siendo el mejor ejemplo la estación espacial.<br><br>Por lo general, aparece en forma de marioneta a distancia.<br><br>\"Se parece en un setenta por ciento a cómo me veía cuando era niña\".<br><br>— Herta',1,0,'PJ Mattson','Yamazaki Haruka (山崎はるか)','Hou Xiaofei (侯小菲)','Kim Seo-yeong (김서영)',NULL),('Himeko',5,'Erudición','Fuego','Himeko es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>Una científica aventurera que se encontró con el Expreso Astral cuando era niña al quedar varado en su mundo natal.<br><br>En ese momento, una existencia en el Expreso le reveló a esta joven todo un mundo fuera del suyo: el universo.<br><br>Años más tarde, Himeko finalmente reparó el tren y comenzó su viaje hacia las estrellas, pero se dio cuenta de que esto era solo el comienzo.<br><br>En la vía del Trazacaminos, necesitaría muchos más compañeros...<br><br>Aunque esos compañeros puedan tener diferentes destinos en mente, todos contemplan el mismo cielo estrellado.',1,0,'Cia Court','Tanaka Rie (田中理恵)','Lin Su (林簌)','김보나',NULL),('Hook',4,'Destrucción','Fuego','Hook es un personaje 4★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>¿Quién soy? Je, soy la jefa de por aquí, puedes llamarme...<br><br>¡La gran Hook la Oscura! No la subestimes, ¡es la jefa del escuadrón de aventuras Los Topos! Si destacas en tu aventura, tal vez la gran Hook la Oscura te invite a unirte a Los Topos.<br><br>Tendrás que descubrir por ti mismo qué clase de experiencia sería esa~',1,0,'Felecia Angelle','Tokui Sora (徳井青空)',NULL,NULL,NULL),('Huohuo',5,'Abundancia','Viento','Huohuo es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Abundancia</span>.<br><br>Una jueza en prácticas de la Comisión de los Diez Líderes del Luofu de Xianzhou, es una joven chica vulpina poseída por un heliobus.<br><br>Es una chica tímida y débil que tiene miedo de todo tipo de cosas extrañas, pero es responsable de atraer y someter a los espíritus malignos.',1.5,1,'Courtney Lin & Adam Michael Gold','長縄まりあ (Naganawa Maria) & 平林剛 (Hirabayashi Takeshi)','葛子瑞 (Ge Zirui ) & 刘北辰 (Liu Beichen)','김채린 (Kim Chae-rin) & 한복현 (Han Bok-hyun)',NULL),('Hyacine',5,'Reminiscencia','Viento','Hyacine es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Reminiscencia</span>.<br><br>A medida que la ciudad-estado en las nubes se desmorona a través del tiempo, el Patio del Crepúsculo abre sus puertas una vez más, trayendo un destello de luz a Evernight.<br><br>Tú, Médica Hyacinthia, Heredera de Chrysos que custodia la Llama del Núcleo del Cielo, debes heredar la voluntad de tus antepasados y remendar el tejido rasgado del anochecer y el amanecer.<br><br>Que la luz del arcoíris se derrame, disuelva todos los rencores y traiga de vuelta el amanecer a esta tierra.',3.3,0,'Holly Earl','Yomiya Hina (羊宮 妃那)','Jing Chen (静宸)','Kim Yeon-woo (김연우)',NULL),('Hysilens',5,'Nihilidad','Físico','Hysilens es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>Styxia, una ciudad costera de intoxicación y sueños, donde los ecos de viejas canciones aún flotan entre las olas.<br><br>Helektra, Hija del Mar, Heredera de Chrysos que purifica la Llama del Núcleo del Océano, disipa las turbias corrientes submarinas y organiza un festín de juerga para los héroes más allá del cielo: el espectáculo debe continuar.<br><br>Incluso si la esperanza es tan frágil como las burbujas, las olas seguirán avanzando con fuerza.',3.5,0,NULL,'石見 舞菜香 (Iwami Manaka)','浮梦若薇 (Fumeng Ruowei)','오은수 (Oh Eun-soo)',NULL),('Jade',5,'Erudición','Cuántico','Jade es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>Una alta gerente del Departamento de Inversiones Estratégicas de la CPI y una de los Diez Corazones de Piedra.<br><br>Su Piedra Angular es la \"Jade del Crédito\".<br><br>Una prestamista fría y elegante, experta en comprender el corazón humano, con un pasatiempo personal llamado \"Intercambio de Jade\".<br><br>Está dispuesta a esperar pacientemente por adquisiciones de alto valor y es experta en extraer valor de clientes aparentemente indigentes.',2.3,0,'Faye Mata','三石琴乃 (Kotono Mitsuishi)','张若瑜 (Zhang Ruoyu)','김순미 (Kim Soon-mi)',NULL),('Jiaoqiu',5,'Nihilidad','Fuego','Jiaoqiu es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>Un sanador vulpino de la Xianzhou Yaoqing y consejero.<br><br>A menudo saluda a la gente con una sonrisa, pero es bastante astuto.<br><br>Nacido en una prestigiosa familia de la Comisión de Alquimia, una vez se retiró de la práctica de la medicina debido a un corazón roto.<br><br>Sin embargo, regresó al campo para tratar a \"la Garra de Merlín\", la General Feixiao.<br><br>Experto en el estudio de prescripciones alquímicas que consideran la comida como medicina, especialmente aquellas que inducen una sensación de picante.<br><br>Inventó una fórmula medicinal basada en un caldero conocida como la \"cuadrícula de nueve cuadrados\".',2.4,0,'Mark Whitten','Toshiyuki Toyonaga (丰永利行)','Taikang Chenzhang (陈张太康)','Jeongmin Lee (이정민)',NULL),('Jing Yuan',5,'Erudición','Rayo','Jing Yuan es un personaje 5★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>Aunque su apariencia pueda ser de indolencia, el general de los Caballeros de la Nube que comanda el Luofu de Xianzhou es más meticuloso de lo que parece a simple vista.<br><br>No considera que salvar una situación al borde del desastre sea una muestra de sabiduría y, por lo tanto, es minucioso con los asuntos rutinarios para evitar cualquier problema potencial.<br><br>Gracias a su cuidadosa gestión, el Xianzhou ha disfrutado de muchos años de paz, y el comportamiento aparentemente perezoso de Jing Yuan le ha valido el apodo de \"General Inactivo\".',1,0,'Alejandro Saab','Ono Daisuke (小野大輔)','Sun Ye (孫曄)','Ryu Seung-gon (류승곤)',NULL),('Jingliu',5,'Destrucción','Hielo','Jingliu es un personaje 5★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Una de los héroes legendarios que integran el Quinteto de las Altas Nubes, y distinguida con el título de \"Destello Trascendente\".<br><br>Habiendo ascendido más allá de los conceptos mortales de victoria, eligió recorrer un camino diferente para obtener el poder capaz de aniquilar dioses.<br><br>A partir de entonces, una Campeona de la Espada del Luofu fue eliminada de los registros de Xianzhou, y se añadió una traidora borrada de los anales.',1.4,1,'AmaLee','桑岛法子 (Houko Kuwashima)','杜冥鸦 (Du Mingya)','박이서 (Park Yi-seo)',NULL),('Kafka',5,'Nihilidad','Rayo','Kafka es un personaje 5★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>En la lista de buscados de la Corporación para la Paz Interastral, la entrada de Kafka solo tiene dos cosas: su nombre y una única frase: \"Le gusta coleccionar abrigos\".<br><br>Poco se sabe sobre esta Cazadora de Estelaron, aparte de que es uno de los miembros de mayor confianza de Elio, el Esclavo del Destino.<br><br>Con el fin de alcanzar el futuro previsto por Elio, Kafka se pone manos a la obra.',1.2,1,'Cheryl Texiera','Itoh Shizuka (伊藤静)','Hui Xu (徐慧)','Sa Moon-young (사문영)',NULL),('Lingsha',5,'Abundancia','Fuego','Lingsha es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Abundancia</span>.<br><br>La nueva Maestra de la Caldera de la Comisión de Alquimia del Luofu de Xianzhou.<br><br>Una sanadora Vidyadhara inteligente y perspicaz.<br><br>Posee un agudo sentido del olfato que utiliza a menudo para diagnosticar enfermedades, además de emplear incienso para calmar la mente de los demás.<br><br>Es experta en lidiar con relaciones sociales complicadas.<br><br>Aunque por dentro pueda estar echando humo, su expresión permanece calmada y serena.',2.5,0,'Whitney Holland','Maeda Kaori (前田佳織里)','Rao Zijun (饶梓君)','Jang Ye-na (장예나)',NULL),('Luka',4,'Nihilidad','Físico','Luka es un personaje 4★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>Un luchador optimista y despreocupado con un brazo mecánico.<br><br>Experto en artes marciales mixtas y miembro de Llamarada.<br><br>Del cuadrilátero al campo de batalla, y de luchador a guerrero, Luka utiliza su fuerza para proteger a la gente del Inframundo.<br><br>Desea llevar esperanza a los demás precisamente porque él mismo ha experimentado la desesperación.',1.2,0,'Howard Wang','Kajiwara Gakuto (梶原岳人)','Xiao Zhai (萧翟)','Lee Joo-Seung (이주승)',NULL),('Luocha',5,'Abundancia','Imaginario','Luocha es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Abundancia</span>.<br><br>Un apuesto joven de cabello rubio que lleva un ataúd a la espalda.<br><br>Como miembro del gremio de comerciantes intergalácticos, lamentablemente se vio envuelto en la crisis del Estelaron del Luofu de Xianzhou.<br><br>De alguna manera, sus excelentes habilidades médicas seguramente serán de gran utilidad.',1.1,0,'Craig Lee Thomas','Ishida Akira (石田彰)','Lu Zhao (赵路)','신용우 (Shin Yong-woo)',NULL),('Lynx',4,'Abundancia','Cuántico','Lynx es un personaje 4★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Abundancia</span>.<br><br>\"En la familia Landau, las cosas son bastante simples: si quieres hacer algo, simplemente hazlo\".<br><br>La hija menor de la familia Landau y una de las mejores exploradoras de entornos extremos de Belobog.<br><br>Tiene una gran capacidad de acción a pesar de su aparente falta de motivación.<br><br>Solo parece introvertida y perezosa para evitar socializar innecesariamente.<br><br>En cuanto a lo que cuenta como socialización innecesaria: \"Etto...<br><br>¿acaso no es innecesaria toda socialización?\".',1.3,0,'Risa Mei','照井春佳 (Haruka Terui)','米糊','이은조 (Lee Eun-jo)',NULL),('March 7 (Hunt)',4,'Cacería','Imaginario','March 7th es un personaje 4★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Siete de Marzo con un atuendo al estilo de Xianzhou.<br><br>Una artista marcial experta en la espada.<br><br>Aprendiendo esgrima tanto de Yunli como de Yanqing, está ansiosa por crear más recuerdos hermosos en el Xianzhou.',2.4,0,'Skyler Davenport','Yui Ogura (小倉唯)','Nuò Yǎ (诺亚)','Jung Hye-Won (정혜원)',NULL),('March 7 (Preservation)',4,'Conservación','Hielo','March 7th es un personaje 4★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Conservación</span>.<br><br>Una joven animada y peculiar que está interesada en todas las cosas en las que las chicas de su edad deberían estarlo, por ejemplo, tomar fotos.<br><br>Despertó de un trozo de <span class=\"element\">Hielo</span> eterno a la deriva solo para descubrir que no sabe nada sobre sí misma ni sobre su pasado.<br><br>Aunque inicialmente estaba desanimada por su falta de identidad, decidió ponerse el nombre de la fecha en que llegó a esta nueva vida.<br><br>Y así, ese día nació Siete de Marzo.',1,0,'Skyler Davenport','Yui Ogura (小倉唯)','Nuò Yǎ (诺亚)','Jung Hye-Won (정혜원)',NULL),('Misha',4,'Destrucción','Hielo','Misha es un personaje 4★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Un adorable y atento botones del Hotel Fantasía.<br><br>Desea convertirse en un aventurero intergaláctico como su abuelo.<br><br>Es extremadamente trabajador y experto en reparar una gran variedad de máquinas.<br><br>También le gusta compartir rumores interestelares con los huéspedes.<br><br>Espera poder crecer más rápido y ansía embarcarse en su propio viaje a través de las estrellas.',2,0,'Cat Protano','松井惠理子 (Matsui Eriko)','柳知萧 (Liu Zhixiao)','박신희 (Park Shin-hee)',NULL),('Mortenax Blade',5,'Nihilidad','Fuego',NULL,4.3,0,NULL,NULL,NULL,NULL,NULL),('Moze',4,'Cacería','Rayo','Moze es un personaje 4★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Un Guardia de las Sombras de la Yaoqing.<br><br>Es reticente y silencioso, y siempre actúa por su cuenta.<br><br>Como experto en servicios de inteligencia y otros asuntos que deben permanecer en la sombra, Moze rara vez se muestra ante los demás.<br><br>El momento en que muestra sus verdaderas capacidades suele ser el momento en que sus enemigos se enfrentan a la muerte.<br><br>Posee un gran conocimiento sobre métodos de asesinato y parece tener una obsesión extraordinaria con el orden y la limpieza.',2.5,0,'Ben Balmaceda','Sakata Shogo (坂田将吾)','Huang Jinze (黄进泽)','Choi Hyun-sik (최현식)',NULL),('Mydei',5,'Destrucción','Imaginario','Mydei es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>¡Kremnos, engullida por la niebla! ¡Ciudad dividida entre el caos y la guerra! La sangre del parricidio fluye por su línea real, y su dios ostenta el título de calamidad.<br><br>El inmortal Mydeimos, el león apartado del resto.<br><br>Oh, Heredero de Chrysos que buscas la Llama del Núcleo de la Contienda, debes sufrir mil muertes, bañarte en sangre en el camino a casa y soportar solo la locura del destino, pues uno debe matar a un dios para convertirse en uno.<br><br>Los cascos de hierro golpean el desierto durante la campaña y, finalmente, deben empaparse en la sangre de su tierra natal.',3.1,0,NULL,'Yōhei Azakami (阿座上洋平)','Zhao Chengchen (赵成晨)','Ahn Hyo-min (안효민)',NULL),('Natasha',4,'Abundancia','Físico','Natasha es un personaje 4★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Abundancia</span>.<br><br>Una doctora meticulosa que siempre luce una curiosa sonrisa.<br><br>En el Inframundo, donde los recursos médicos son escasos, Natasha es una de las pocas doctoras a las que la gente puede acudir.<br><br>Incluso la revoltosa Hook la saludaría cortésmente...<br><br>\"Hola, tía Natasha\".',1,0,'Elizabeth Maxwell','Uchiyama Yumi (内山夕実)','秦紫翼','강은애',NULL),('Pela',4,'Nihilidad','Hielo','Pela es un personaje 4★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>La meticulosa oficial de inteligencia de la Guardia de Crin de Plata; aunque es joven, es innegablemente brillante.<br><br>Ya sea que se trate de maniobras de tropas, distribución de suministros o del terreno, Pela puede responder a cualquier problema con una certeza calmada.<br><br>En cuanto a la funda de su teléfono...<br><br>\"No tiene nada que ver con el trabajo, capitán\".',1,0,'Xanthe Huynh','Morohoshi Sumire (諸星すみれ)','宴宁','이다은',NULL),('Phainon',5,'Destrucción','Físico','Phainon es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Aedes Elysiae, una remota aldea fronteriza aislada del mundo, ahora solo vive en leyendas crípticas.<br><br>Héroe sin nombre █████, el Heredero de Chrysos que porta la Llama del Núcleo del \"Sostén del Mundo\", debes memorizar los ideales de todos los mundos, cargar con el destino de multitudes y traer la primera luz del amanecer al nuevo mundo: \"¡Pero si el amanecer nunca hubiera existido, que los fuegos de la rabia reduzcan este cuerpo a cenizas y lo transformen en el sol abrasador del mañana!\".',3.4,0,'Joshua Waters','日野 聡 (Hino Satoshi)','秦且歌 (Qin Qiege)','윤용식 (Yoon Yong-sik)',NULL),('Qingque',4,'Erudición','Cuántico','Qingque es un personaje 4★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>Una adivina promedio de la Comisión de Divinación que nunca flaquea cuando se trata de holgazanear.<br><br>Aprobó el examen de ingreso de la Comisión para complacer a sus padres, solo para descubrir que lo que originalmente pensó que sería un trabajo relajante de funcionaria pública era en realidad muy intensivo y la pesadilla de cualquier trabajador.<br><br>Tras varios años de experiencia, Qingque finalmente ha perfeccionado su arte: sin importar a qué departamento la cambien, sigue siendo la adivina de más bajo nivel.<br><br>\"Cuando no queda nada más por hacer, ¿por qué no sumergirse en un libro o jugar a las cartas? ¿Qué más podría pedir?\".',1,0,'Bryn Appril','Arisa Date (伊達 朱里紗)','Liu Shisi (刘十四)',NULL,NULL),('Rappa',5,'Erudición','Imaginario','Rappa es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>Una chica peculiar que aparece en Colonipenal como una granada cegadora en la hora más oscura de la noche, identificándose como ninja y atribuyendo todo en el mundo al \"ninjutsu\".<br><br>Manteniendo la recitación de mantras ninja, creando Sellos Ninja Deslumbrantes y dominando técnicas ninja, su Camino del Ninja incluye el rap, el grafiti y los cómics.<br><br>A través de una rigurosa autodisciplina, recorre las estrellas defendiendo la justicia y la rectitud.<br><br>Como miembro de los Vigilantes de la Galaxia, persigue implacablemente al villano conocido como el Ninja Malvado Osaru, cazándolo hasta los confines del cosmos.',2.6,0,'Kendell Byrd','Han Megumi (潘めぐみ)','Jin Na (金娜)','Kim Yurim (김유림)',NULL),('Robin',5,'Armonía','Físico','Robin es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Una cantante haloviana nacida en Colonipenal que alcanzó la fama cósmica.<br><br>Una joven elegante y recatada.<br><br>En esta ocasión, ha sido invitada a casa por La Familia para deleitar a todos con una canción en el Festival del Armonismo.<br><br>Puede usar el poder de la <span class=\"path\">Armonía</span> para difundir su música, manifestando una \"resonancia\" no solo entre sus fans, sino en toda clase de formas de vida.',2.2,0,'Alice Himora & Chevy','名冢佳织 (Nazuka Kaori) & Chevy','钱琛 (Qian Chen) & Chevy','신온유 (Shin On-yu) & Chevy',NULL),('Ruan Mei',5,'Armonía','Hielo','Ruan Mei es un personaje 5★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Una erudita elegante y de temperamento dulce.<br><br>Miembro número 81 de la Sociedad de Genios y experta en ciencias biológicas.<br><br>Se ganó la atención de Nous gracias a su talento y a una perseverancia aterradora, y comenzó su investigación sobre el origen de la vida en un rincón secreto del universo.<br><br>Por ello, fue invitada por Herta para colaborar con Screwllum y Stephen en el desarrollo del Universo Simulado.<br><br>En secreto, disfruta mucho del teatro tradicional y los postres, y también está muy interesada en el bordado.',1.6,0,'Emi Lo','大西沙织 (Onishi Saori)','张文钰 (Zhang Wenyu)','윤여진 (Yoon Yeo-jin)',NULL),('Saber',5,'Destrucción','Viento','Saber es un personaje 5★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>El Espíritu Heroico solitario que atraviesa la larga noche del destino.<br><br>El estandarte de la mesa redonda permanece desplegado en un sueño.<br><br>Ay, la reina de los caballeros de Camelot aún no ha alcanzado esa utopía siempre distante.<br><br>Aunque sigue siendo una joven doncella, ha atendido al llamado de esta iteración única de la Guerra del Santo Grial.<br><br>Con la Espada en la Piedra ofreciendo su elección una vez más, ¿cómo destrozará las ilusiones del pasado? \"Los deseos que no cumplí terminarán aquí\".',3.4,0,NULL,NULL,NULL,NULL,NULL),('Sampo',4,'Nihilidad','Viento','Sampo es un personaje 4★ del elemento <span class=\"element\">Viento</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>Un elocuente vendedor de lengua de plata; donde haya una ganancia que obtener, puedes estar seguro de que Sampo está cerca.<br><br>Los conocimientos únicos de Sampo hacen que sea difícil no acudir a él en busca de ayuda, pero convertirse en su \"cliente\" no es necesariamente algo bueno.<br><br>Después de todo, los \"clientes\" pueden convertirse rápidamente en \"mercancías\" por el precio adecuado.',1,0,'Roger Rose','Hirakawa Daisuke (平川大輔)','刘圣博','정재헌',NULL),('Seele',5,'Cacería','Cuántico','Seele es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Una valiente y animada miembro de Llamarada que creció en el peligroso Inframundo de Belobog.<br><br>Está acostumbrada a estar sola.<br><br>Como alguien que alguna vez dependió de otros para su protección, ahora busca la fuerza.<br><br>Por la verdad del subterráneo y el nombre de su familia, Seele puede soportar cualquier tipo de adversidad.<br><br>Los protectores y los protegidos, los opresores y los oprimidos...<br><br>El mundo en el que Seele creció era solo una simple dicotomía...<br><br>Eso fue hasta que apareció aquella joven.',1,1,'Molly Zhang','Nakahara Mai (中原麻衣)','Yajing Tang (唐雅菁)','송하림',NULL),('Serval',4,'Erudición','Rayo','Serval es un personaje 4★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>La hija mayor de la familia Landau, libre y rebelde, que en su día fue amiga cercana de Cocolia; sus intereses la han llevado ahora a ser mecánica.<br><br>En el Belobog perpetuamente azotado por el invierno, abrió un taller llamado \"Nunca de Invierno\" que suspende su actividad de vez en cuando para realizar actuaciones de rock \'n\' roll.<br><br>Y si alguien le pregunta por la rentabilidad del taller...<br><br>\"Esto es solo un pasatiempo, cariño.<br><br>No me falta el dinero\".',1,0,'Natalie Van Sistine','Aimi','穆雪婷','민아',NULL),('Silver Wolf',5,'Nihilidad','Cuántico','Silver Wolf es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>El universo es solo un juego más para esta súper hacker.<br><br>No importa qué tan espinoso sea el sistema de defensa, Silver Wolf puede hackearlo con facilidad.<br><br>Su batalla de hacking con Screwllum de la Sociedad de Genios se ha convertido en leyenda en el mundo de la informática.<br><br>¿Cuántos niveles más quedan por superar en el universo? Silver Wolf está ansiosa por descubrirlo.',1.1,1,'Melissa Fahn','Asumi Kana (阿澄佳奈)','Hanser','장미',NULL),('Silver Wolf (Lvl. 999)',5,'Exultación','Imaginario','Silver Wolf • Niv.<br><br>999 es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía del Júbilo.<br><br>¡Comienza una nueva temporada de Júbilo, con el regreso por tiempo limitado de la jugadora invencible \"Loba Plateada Niv.<br><br>999\"! Te has convertido en la mayor ganadora del universo y has desbloqueado todos los Logros Cósmicos existentes...<br><br>Entonces, ¿cuál es tu siguiente movimiento? \"¿Alcanzar la cima del \'Júbilo\'? Qué abu-rrido...<br><br>Ahora que tengo el cartucho, yo pongo las reglas~\".',4.2,0,'Melissa Fahn','Asumi Kana (阿澄佳奈)','Hanser','장미',NULL),('Sparkle',5,'Armonía','Cuántico','Sparkle es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Una integrante de los Bufones Enmascarados.<br><br>Inescrutable y sin escrúpulos.<br><br>Una peligrosa maestra del teatro absorta en la interpretación de papeles.<br><br>Una mujer de incontables máscaras y muchas caras.<br><br>Riqueza, estatus, poder...<br><br>Nada de esto le importa a Sparkle.<br><br>Lo único que puede despertar su interés es la \"diversión\".',2,1,'Lizzie Freeman','上田丽奈 (Ueda Reina)','赵爽 (Zhao Shuang)','성예원 (Sung Ye-won)',NULL),('Sparxie',5,'Exultación','Fuego','Sparxie es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Exultación</span>.<br><br>¡Me gusta! ¡Seguir! ¡Directo! ¡Visitas! ¡Fiesta hasta que el mundo se acabe! Sparxie y Sparkle, la Máscara y el Bufón, son fundamentalmente lo mismo.<br><br>¡Quien sea visto, quien sea querido, es la respuesta correcta!',4,0,'Lizzie Freeman','上田丽奈 (Ueda Reina)','赵爽 (Zhao Shuang)','성예원 (Sung Ye-won)',NULL),('Sunday',5,'Armonía','Imaginario','Sunday es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>El viajero cuyas alas fueron cortadas...<br><br>¿hacia dónde se dirigirán sus pasos?',2.7,0,NULL,'大塚剛央 (Otsuka Takeo)','徐翔 (Xu Xiang)','강성우 (Kang Seong-woo)',NULL),('Sushang',4,'Cacería','Físico','Sushang es un personaje 4★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Una recién llegada a los Caballeros de la Nube, ingenua y entusiasta, que empuña un mandoble.<br><br>Anhela las leyendas históricas de los Caballeros de la Nube y está ansiosa por convertirse ella misma en una figura legendaria.<br><br>Por ello, Sushang cree firmemente en las filosofías de \"estar siempre dispuesta a ayudar a los necesitados\" y \"hacer una buena acción al día y reflexionar sobre uno mismo tres veces al día\", lo que la lleva a pasar días ocupados ayudando a los demás.',1,0,'Anjali Kunapanen','Fukuen Misato (福圓美里)','Chen Tingting (陈婷婷)','Park Si-yoon (박시윤)',NULL),('The Dahlia',5,'Nihilidad','Fuego','The Dahlia es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>El dulce sueño consume la Mansión de la Llama Eterna, borrando cada fragmento de su existencia.<br><br><span class=\"path\">Destrucción</span>.<br><br><span class=\"path\">Reminiscencia</span>...<br><br>A lo largo de su camino, brotan y florecen flores de traición.<br><br>Para regresar al paisaje onírico que nadie recuerda, ¿quién será el encargado de prenderle <span class=\"element\">Fuego</span> de nuevo?',3.8,0,'Jennifer Losi','Sasaki Mikoi (佐々木未来)','Ruan Congqing (阮从青)','Kim Do Hee (김도희)',NULL),('The Herta',5,'Erudición','Hielo','La Herta es un personaje 5★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Erudición</span>.<br><br>Los escritores del Gremio de Intelectuales querían darme un título extra.<br><br>Algo como \"Herta Prime\" para separarme de mis marionetas.<br><br>Qué banal.<br><br>¿Acaso las marionetas no son \"yo\" también? Así que les di una sugerencia: si se atrevían a escribir eso, entonces me llamaría LA Herta.<br><br>Es corto, simple, directo al grano y elegante.<br><br>Estimada miembro número 83 de la Sociedad de Genios, humana, mujer, joven, hermosa, atractiva.<br><br>Se dice que vive en el confín más lejano del cosmos y que casi nunca sale de allí.<br><br>Parece que su aparición esta vez...<br><br>debe ser para ocuparse de un asunto que tiene que gestionar ella misma, ¿verdad?',3,0,'PJ Mattson','Yamazaki Haruka (山崎はるか)','Hou Xiaofei (侯小菲)','Kim Seo-yeong (김서영)',NULL),('Tingyun',4,'Armonía','Rayo','Tingyun es un personaje 4★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Una chica foxiana de lengua de plata, Tingyun es la representante jefa de las Llamas Silbantes, un gremio de comerciantes aprobado oficialmente por la Comisión de Vuelo de Cielo.<br><br>Tiene tal don de palabra que a menudo deja a su audiencia esperando ansiosamente más de sus cautivadoras historias.<br><br>Gracias a su supervisión, las ferias comerciales de Xianzhou son ahora conocidas en toda la galaxia.<br><br>\"Hacer todo lo posible por evitar el conflicto cuando sea posible y persuadir a quienes puedan ser persuadidos\", ese es el lema de Tingyun.',1,0,'Laci Morgan','高田 憂希 (Yūki Takada)','蒋丽 (Li Jiang)','이명호 (Lee Myeong-ho)',NULL),('Topaz & Numby',5,'Cacería','Fuego','Topaz & Numby es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>Topaz es la líder del Equipo de Piquete de Deudas Especiales y gerente de alto nivel del Departamento de Inversiones Estratégicas de la Corporación para la Paz Interastral.<br><br>Miembro de los \"Diez Corazones de Piedra\" desde joven, la especialidad fundamental de Topaz es la \"recuperación de deudas\".<br><br>Su compañero, el Chanchito de los Espacios \"Conti\", también es capaz de percibir con agudeza dónde se encuentran las \"riquezas\", asegurando que las tareas de seguridad, cobro de deudas y cálculos actuariales no supongan un gran desafío.<br><br>Actualmente viajan juntos por el cosmos, buscando todo tipo de disputas de responsabilidad que puedan estar afectando el progreso estable de los negocios de la CPI.',1.4,0,'Sam Slade','南條愛乃 (Nanjō Yoshino)','陆敏悦 (Mace)','방시우 (Bang Siu)',NULL),('Trazacaminos (Destruction)',5,'Destrucción','Físico','Trazacaminos • <span class=\"path\">Destrucción</span> es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Una joven o un joven que abordó el Expreso Astral.<br><br>Eligieron viajar con el Expreso Astral para eliminar los peligros planteados por el Estelaron.',1,0,'Rachael Chau | Caleb Yen','Ishikawa Yui (石川 由依) | Enoki Junya (榎木 淳弥)','Chen Tingting (陈婷婷) | Qin Juge (秦且歌)','Kim Ha-ru (김하루) | Kim Myung-jun (김명준)',NULL),('Trazacaminos (Elation)',5,'Exultación','Rayo','Trazacaminos • <span class=\"path\">Exultación</span> es un personaje 5★ del elemento <span class=\"element\">Rayo</span> que sigue la Vía de la <span class=\"path\">Exultación</span>.<br><br>¡Regocíjate, llora, maldice, alaba! En una era de euforia hasta la muerte, las calles bullen de ruido.<br><br>Convertirse en héroe o caer del altar toma solo una fracción de segundo.<br><br>De entre las mil máscaras de la <span class=\"path\">Exultación</span>, ¿cuál será la elegida al final?',4.2,0,'Rachael Chau | Caleb Yen','Ishikawa Yui (石川 由依) | Enoki Junya (榎木 淳弥)','Chen Tingting (陈婷婷) | Qin Juge (秦且歌)','Kim Ha-ru (김하루) | Kim Myung-jun (김명준)',NULL),('Trazacaminos (Harmony)',5,'Armonía','Imaginario','Trazacaminos • <span class=\"path\">Armonía</span> es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Una joven o un joven que abordó el Expreso Astral.<br><br>Eligieron viajar con el Expreso Astral para eliminar los peligros planteados por el Estelaron.',2.2,0,'Rachael Chau | Caleb Yen','Ishikawa Yui (石川 由依) | Enoki Junya (榎木 淳弥)','Chen Tingting (陈婷婷) | Qin Juge (秦且歌)','Kim Ha-ru (김하루) | Kim Myung-jun (김명준)',NULL),('Trazacaminos (Preservation)',5,'Conservación','Fuego','Trazacaminos • <span class=\"path\">Conservación</span> es un personaje 5★ del elemento <span class=\"element\">Fuego</span> que sigue la Vía de la <span class=\"path\">Conservación</span>.<br><br>Una joven o un joven que abordó el Expreso Astral.<br><br>Eligieron viajar con el Expreso Astral para eliminar los peligros planteados por el Estelaron.',1,0,'Rachael Chau | Caleb Yen','Ishikawa Yui (石川 由依) | Enoki Junya (榎木 淳弥)','Chen Tingting (陈婷婷) | Qin Juge (秦且歌)','Kim Ha-ru (김하루) | Kim Myung-jun (김명준)',NULL),('Trazacaminos (Rememberance)',5,'Reminiscencia','Hielo','Trazacaminos • <span class=\"path\">Reminiscencia</span> es un personaje 5★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Reminiscencia</span>.<br><br>Una joven o un joven que abordó el Expreso Astral.<br><br>Eligieron viajar con el Expreso Astral para eliminar los peligros planteados por el Estelaron.',3,0,'Rachael Chau | Caleb Yen','Ishikawa Yui (石川 由依) | Enoki Junya (榎木 淳弥)','Chen Tingting (陈婷婷) | Qin Juge (秦且歌)','Kim Ha-ru (김하루) | Kim Myung-jun (김명준)',NULL),('Tribbie',5,'Armonía','Cuántico','Tribbie es un personaje 5★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>La Mensajera parte de esa tierra santa amada por la profecía tripartita, dividiéndose en mil pedazos y emprendiendo su viaje.<br><br>Oh, Tribios, Doncellas Sagradas de Janusopolis, la Heredera de Chrysos que robó la Llama del Núcleo del \"Pasaje\".<br><br>Trabajarás para las masas, llevando la noticia de la liberación a todos los dominios: ve a buscar a los hijos de la humanidad con sangre dorada en sus venas, rompe la oscuridad más profunda de este mundo y camina hacia el mañana donde brillan las estrellas.',3.1,0,NULL,'Tono Hikaru (远野光)','Cai Shujin (蔡书瑾)','Yeon-ji Bang (방연지)',NULL),('Welt',5,'Nihilidad','Imaginario','Welt es un personaje 5★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Nihilidad</span>.<br><br>El sabio y sofisticado exsoberano de Anti-Entropy que heredó el nombre del mundo: Welt.<br><br>Ha salvado a la Tierra de la aniquilación una y otra vez.<br><br>Tras el fin de la calamidad, la pesada carga impuesta por el destino sobre Welt le fue retirada por un tiempo y se convirtió en artista de guiones gráficos de animación.<br><br>Sin embargo, tras el cierre de la conspiración de St.<br><br>Fountain, Welt no tuvo más remedio que aventurarse con el instigador del incidente al otro lado del portal espacial.<br><br>Tal vez ni siquiera él esperaba el nuevo viaje y los compañeros que le aguardaban.',1,1,'Corey Landis','Hosoya Yoshimasa (細谷佳正)','Bo Peng (彭博)','한신',NULL),('Xueyi',4,'Destrucción','Cuántico','Xueyi es un personaje 4★ del elemento <span class=\"element\">Cuántico</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Una de las juezas de la Comisión de los Diez Líderes.<br><br>De los cuatro deberes de un juez (detención, interrogatorio, encarcelamiento y castigo), ella está a cargo de la detención.<br><br>Con cadenas de hierro y un Punzón de la Marasunder en sus manos, rastrea incansablemente a los criminales buscados y los somete.',1.6,0,'Jenny Yokobori','河瀬茉希 (Kawase Maki)','溯浔 (SuXun)','박리나 (Park Ri-na)',NULL),('Yanqing',5,'Cacería','Hielo','Yanqing es un personaje 5★ del elemento <span class=\"element\">Hielo</span> que sigue la Vía de la <span class=\"path\">Cacería</span>.<br><br>El animado teniente del Luofu de Xianzhou y también su espadachín más hábil.<br><br>Nació para las espadas y está obsesionado con ellas.<br><br>Siempre que tiene una espada en la mano, nadie se atreve a subestimar a este genio que aún se encuentra en los primeros días de su juventud.<br><br>Tal vez lo único capaz de desafilar el afilado filo de su preciada hoja sea el tiempo.',1,0,'Amber May','Marina Inoue (井上 麻里奈)','Miaojiang (喵酱)',NULL,NULL),('Yao Guang',5,'Exultación','Físico','Yao Guang es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía del <span class=\"path\">Exultación</span>.<br><br>Sus acciones misteriosas, audaces y radicales fueron tan revolucionarias que dejaron a todos atónitos.<br><br>Ella vio toda la fortuna, buena y mala, a través del \"ojo\" de La <span class=\"path\">Cacería</span>.<br><br>Sin embargo, sabiendo que no se debe desafiar al destino, la Estratega Vidente aún enfrentó el peligro sola.<br><br>Al recibir una fortuna tan maldita...<br><br>¿Cómo puede alguien esperar alterar su destino?',4,0,NULL,'花澤 香菜 (Hanazawa Kana)','秦紫翼 (Qin Ziyi)','이슬 (Lee Seul)',NULL),('Yukong',4,'Armonía','Imaginario','Yukong es un personaje 4★ del elemento <span class=\"element\">Imaginario</span> que sigue la Vía de la <span class=\"path\">Armonía</span>.<br><br>Jefa de la Comisión de Vuelo del Cielo del Luofu de Xianzhou.<br><br>Yukong fue una piloto experimentada y una tiradora de élite.<br><br>Desde que dirige la comisión, ha estado sepultada bajo montañas de papeleo.',1.1,0,'Dawn M. Bennett','冬馬由美 (Yumi Tōma)','钟可 (Zhong Ke)','전숙경 (Jeon Sook-kyung)',NULL),('Yunli',5,'Destrucción','Físico','Yunli es un personaje 5★ del elemento <span class=\"element\">Físico</span> que sigue la Vía de la <span class=\"path\">Destrucción</span>.<br><br>Una cazadora de espadas del Zhuming de Xianzhou y la querida nieta del General Huaiyan, \"el Corazón Llameante\".<br><br>Franca y directa.<br><br>Practicó la esgrima y la forja con Huaiyan desde joven, por lo que es la segunda prodigio más joven entre los maestros espadachines del Octeto de la Rueda de <span class=\"element\">Fuego</span>.<br><br>Impulsada por un intenso odio hacia las espadas malditas que surgieron del Zhuming, juró \"cazar y destruir todas las espadas malditas\".',2.4,0,'Brenna Larsen','Shion Wakayama (若山詩音)','Liu Wen (刘雯)','Lee Ju-eun (이주은)',NULL);
/*!40000 ALTER TABLE `characters` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `eidolons`
--

DROP TABLE IF EXISTS `eidolons`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `eidolons` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `character_id` varchar(100) DEFAULT NULL,
  `lvl` int(11) DEFAULT NULL CHECK (`lvl` between 1 and 6),
  `name` varchar(150) DEFAULT NULL,
  `description` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_eidolons_character_id` (`character_id`),
  CONSTRAINT `fk_eidolons_character_id` FOREIGN KEY (`character_id`) REFERENCES `characters` (`name`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=533 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

