LOCK TABLES `eidolons` WRITE;
/*!40000 ALTER TABLE `eidolons` DISABLE KEYS */;
INSERT INTO `eidolons` VALUES (3,'Acheron',1,'Caída del cielo y comienzo de la verdad','Al infligir daño a enemigos con estados negativos, la Prob. CRIT aumenta en un <span class=\"stat\">18%</span>.'),(4,'Acheron',2,'Trueno silenciado y tempestad calmada','La cantidad de personajes de la Vía de la <span class=\"via\">Nihilidad</span> que se requieren para el valor más alto del Rastro \"El abismo\" se reduce en <span class=\"stat\">1</span>. Al comenzar su propio turno, obtiene <span class=\"stat\">1</span> pt. de Sueños rotos y aplica <span class=\"stat\">1</span> acumulación de Rojo sacrificial al enemigo que más acumulaciones tenga.'),(5,'Acheron',3,'Frío invernal y sueño eterno','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10).'),(6,'Acheron',4,'Llamas del alma reflejada','Cuando el enemigo entra en combate, le aplica Vulnerabilidad a daño de habilidad definitiva, lo que aumenta el daño de habilidad definitiva recibido en un <span class=\"stat\">8%</span>.'),(7,'Acheron',5,'Rocas fragmentadas, almas desplazadas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15).'),(8,'Acheron',6,'Calamidad rompecadenas','La PEN de la RES a todos los tipos del daño de habilidad definitiva infligido por Acheron aumenta en un <span class=\"stat\">20%</span>. El daño infligido por su ATQ básico o habilidad básica se considera daño de habilidad definitiva, y consume la Firmeza del enemigo ignorando sus tipos de Debilidad. Al romper la Debilidad de un enemigo, activa el efecto de Ruptura de <span class=\"elemento\">Rayo</span>.'),(9,'Ashveil',1,'Cuidado: no salgas durante la luna llena','Mientras Ashveil está en el campo de batalla, el daño que reciben todos los enemigos aumenta en un <span class=\"stat\">24%</span>. Cuando el porcentaje de PV actual de un enemigo sea igual o inferior al <span class=\"stat\">50%</span>, el incremento de daño recibido aumenta al <span class=\"stat\">36%</span>.'),(10,'Ashveil',2,'Llamada: risa queda tras la puerta','El límite de acumulaciones de Gula aumenta a <span class=\"stat\">18</span>. Cada vez que Ashveil lanza la versión potenciada del ataque adicional del talento, recupera un <span class=\"stat\">35%</span> de las acumulaciones de Gula eliminadas.'),(11,'Ashveil',3,'Silencio: ensimismamiento entre amigos','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10).'),(12,'Ashveil',4,'Recuerda: la verdad hay que tragarla entera','Cuando Ashveil lanza la habilidad definitiva, su ATQ aumenta en un <span class=\"stat\">40%</span> durante <span class=\"stat\">3</span> turnos.'),(13,'Ashveil',5,'Aviso: el detective puede ser el asesino','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15).'),(14,'Ashveil',6,'Final: y no quedó ninguno','Cuando hay un Cebo en el campo de batalla, la RES a todos los tipos de todos los enemigos se reduce en un <span class=\"stat\">20%</span>. El daño que inflige Ashveil aumenta en un <span class=\"stat\">4%</span> por cada acumulación de Gula obtenida. Este efecto se puede acumular hasta <span class=\"stat\">30</span> veces.'),(15,'Aglaea',1,'Deriva caprichosa de Venus','El daño que recibe el enemigo afectado con Hilván aumenta en un <span class=\"stat\">15%</span>. Cuando Aglaea o el Sastre atacan a ese objetivo, recuperan <span class=\"stat\">20</span> pts. de energía adicionales.'),(16,'Aglaea',2,'Párpados que navegan el destino','Cuando Aglaea o el Sastre actúan, el daño que infligen Aglaea y el Sastre ignora un <span class=\"stat\">14%</span> de la DEF del objetivo. Este efecto se puede acumular hasta <span class=\"stat\">3</span> veces y dura hasta que cualquier unidad que no sea el Sastre o Aglaea lance una habilidad de forma proactiva.'),(17,'Aglaea',3,'Don del rocío bello','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(18,'Aglaea',4,'Destello bajo el mármol','El límite de acumulaciones del efecto de aumento de VEL del talento de mnemoduende aumenta en <span class=\"stat\">1</span>. Después de que Aglaea lance un ataque, el Sastre también obtiene el aumento de VEL del talento de mnemoduende.'),(19,'Aglaea',5,'Tejedora del infortunio','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(20,'Aglaea',6,'Fluctuación en el tapiz del destino','Cuando Aglaea está en el estado de Disposición suprema, su PEN de la RES a <span class=\"elemento\">Rayo</span> y la del Sastre aumentan en un <span class=\"stat\">20%</span>. Cuando la VEL de Aglaea o el Sastre es superior a <span class=\"stat\">160</span>/<span class=\"stat\">240</span>/<span class=\"stat\">320</span> pts., su daño de ataque combinado aumenta en un <span class=\"stat\">10%</span>/<span class=\"stat\">30%</span>/<span class=\"stat\">60%</span> respectivamente.'),(21,'Anaxa',1,'Mago aislado por las estrellas','Recupera <span class=\"stat\">1</span> pt. de habilidad básica tras lanzar la habilidad básica por primera vez. Cuando golpea a un enemigo con la habilidad básica, reduce la DEF del objetivo en un <span class=\"stat\">16%</span> durante <span class=\"stat\">2</span> turnos.'),(22,'Anaxa',2,'Persona de la historia real','Cuando un enemigo entra en la batalla, se activa <span class=\"stat\">1</span> vez el efecto de implantación de Debilidad del talento y la RES a todos los tipos de ese enemigo se reduce en un <span class=\"stat\">20%</span>.'),(23,'Anaxa',3,'Pupilas clavadas en el cosmos','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(24,'Anaxa',4,'Incandescencia despeñada','Al lanzar la habilidad básica, el ATQ aumenta en un <span class=\"stat\">30%</span> durante <span class=\"stat\">2</span> turnos. Este efecto se puede acumular hasta <span class=\"stat\">2</span> veces.'),(25,'Anaxa',5,'Simiente fuera del vórtice','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(26,'Anaxa',6,'El todo alberga el todo','El daño que inflige Anaxa es el <span class=\"stat\">130%</span> del daño original. Los dos efectos del Rastro \"Vacío necesario\" se activan directamente y ya no dependen de la cantidad de personajes de la Vía de la <span class=\"via\">Erudición</span> que haya en el equipo aliado.'),(27,'Archer',1,'Ideal inalcanzable','Tras lanzar la habilidad básica <span class=\"stat\">3</span> veces en un solo turno, los aliados recuperan <span class=\"stat\">2</span> pts. de habilidad básica.'),(28,'Archer',2,'Felicidad frustrada','Al lanzar la habilidad definitiva, la RES a Cuántico del enemigo se reduce en un <span class=\"stat\">20%</span> y se le implanta Debilidad Cuántica durante <span class=\"stat\">2</span> turnos.'),(29,'Archer',3,'Temperamento indomable','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10).'),(30,'Archer',4,'Héroe no reconocido','El daño de habilidad definitiva infligido aumenta en un <span class=\"stat\">150%</span>.'),(31,'Archer',5,'Vigilancia sin nombre','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15).'),(32,'Archer',6,'Peregrinaje interminable','Al comenzar el turno, recupera <span class=\"stat\">1</span> pt. de habilidad básica. El límite de acumulaciones del efecto de incremento de daño de su habilidad básica aumenta en <span class=\"stat\">1</span>. El daño de habilidad básica infligido ignora un <span class=\"stat\">20%</span> de la DEF.'),(33,'Argenti',1,'La falla del reino de la estética','Cada acumulación de Elevación aumenta el Daño CRIT en un <span class=\"stat\">4%</span> de forma adicional.'),(34,'Argenti',2,'Humildad del ágata','Al usar la habilidad definitiva, si el número de enemigos es igual o superior a <span class=\"stat\">3</span>, el ATQ aumenta en un <span class=\"stat\">40%</span> durante <span class=\"stat\">1</span> turno.'),(35,'Argenti',3,'Gloria del camino de espinas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(36,'Argenti',4,'Consagración de la corneta','Argenti obtiene <span class=\"stat\">2</span> acumulaciones de Elevación al comienzo de la batalla y el límite de acumulaciones del efecto de su talento aumenta en <span class=\"stat\">2</span>.'),(37,'Argenti',5,'Nieve en algún lugar del universo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(38,'Argenti',6,'\"Tu\" resplandor','Al usar la habilidad definitiva, se ignora un <span class=\"stat\">30%</span> de la DEF del objetivo.'),(39,'Arlan',1,'Hasta el final','Cuando su porcentaje de PV es igual o inferior al <span class=\"stat\">50%</span>, el daño que inflige su habilidad básica aumenta en un <span class=\"stat\">10%</span>.'),(40,'Arlan',2,'Liberación','Al usar la habilidad básica o la habilidad definitiva, disipa uno de sus estados negativos.'),(41,'Arlan',3,'Esfuerzo sostenido','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(42,'Arlan',4,'Cambio de tornas','Al recibir un golpe letal durante el combate, en vez de caer derrotado, Arlan regenera un <span class=\"stat\">25%</span> de sus PV máx. Este efecto se disipa automáticamente tras activarse <span class=\"stat\">1</span> vez o después de <span class=\"stat\">2</span> turnos.'),(43,'Arlan',5,'Martillo y tenazas','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(44,'Arlan',6,'Autosacrificio','Cuando el porcentaje de PV es igual o inferior al <span class=\"stat\">50%</span>, el daño que inflige la habilidad definitiva aumenta en un <span class=\"stat\">20%</span> y el multiplicador de daño a los enemigos adyacentes aumenta en la misma proporción que el multiplicador de daño al objetivo principal.'),(45,'Asta',1,'Canción estelar sin letra','Al usar la habilidad básica, inflige daño a un enemigo al azar una vez más.'),(46,'Asta',2,'La luna entiende sus ciclos','Al usar su habilidad definitiva, Asta no consumirá ninguna acumulación de Recarga en el siguiente turno.'),(47,'Asta',3,'Cambio en el meteorito eclíptico','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(48,'Asta',4,'Manifestación de la aurora','Cuando hay <span class=\"stat\">2</span> o más acumulaciones de Recarga del talento, la recuperación de energía de Asta aumenta en un <span class=\"stat\">15%</span>.'),(49,'Asta',5,'Misterio de los objetos del espacio profundo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(50,'Asta',6,'Sueño bajo la Vía Láctea','Asta pierde <span class=\"stat\">1</span> acumulación de Recarga menos en cada turno.'),(51,'Aventurine',1,'Dilema del prisionero','El Daño CRIT de los aliados con Apuesta reforzada aumenta en un <span class=\"stat\">20%</span>. Tras usar la habilidad definitiva, proporciona un escudo Apuesta reforzada a todos los aliados. El efecto de escudo es equivalente al <span class=\"stat\">100%</span> del que proporciona la habilidad básica y dura <span class=\"stat\">3</span> turnos.'),(52,'Aventurine',2,'Racionalidad limitada','Al usar el ATQ básico, reduce la RES a todos los tipos del objetivo en un <span class=\"stat\">12%</span> durante <span class=\"stat\">3</span> turnos.'),(53,'Aventurine',3,'Multiplicador máximo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(54,'Aventurine',4,'Paradoja del examen sorpresa','Al activar el ataque adicional del talento, la DEF de Aventurino aumenta primero en un <span class=\"stat\">40%</span> durante <span class=\"stat\">2</span> turnos. Además, los golpes por acción del ataque adicional de su talento aumentan en <span class=\"stat\">3</span>.'),(55,'Aventurine',5,'Aversión a la ambigüedad','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(56,'Aventurine',6,'Caza del ciervo','Por cada aliado que tenga un escudo, el daño que inflige Aventurino aumenta en un <span class=\"stat\">50%</span>, hasta un aumento máximo del <span class=\"stat\">150%</span>.'),(57,'Bailu',1,'Infusión de meridianos: Gotas de ambrosía','Cuando termina el efecto de Vigor, si el aliado objetivo tiene todos sus PV, recupera <span class=\"stat\">8</span> pts. de energía adicionales.'),(58,'Bailu',2,'Tetera del dragón durmiente','Tras usar la habilidad definitiva, la curación realizada por Bailu aumenta en un <span class=\"stat\">15%</span> durante <span class=\"stat\">2</span> turnos.'),(59,'Bailu',3,'Portento enigmático','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(60,'Bailu',4,'Amenaza exorcizada','Cada curación proporcionada por la habilidad básica de Bailu aumenta el daño que inflige el receptor de la curación en un <span class=\"stat\">10%</span>. Se puede acumular hasta <span class=\"stat\">3</span> veces y dura <span class=\"stat\">2</span> turnos.'),(61,'Bailu',5,'Eliminación de preocupaciones terrenales','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(62,'Bailu',6,'Gota de divinidad dracónica','La cantidad de veces que Bailu puede curar durante una batalla a aliados que hayan recibido un golpe letal aumenta en <span class=\"stat\">1</span>.'),(63,'Black Swan',1,'Siete pilares de sabiduría','Cuando Cisne Negro está activa en la batalla, la RES a <span class=\"elemento\">Viento</span>, <span class=\"elemento\">Físico</span>, <span class=\"elemento\">Fuego</span> o <span class=\"elemento\">Rayo</span> de los enemigos afectados por Intemperie, Sangrado, Quemadura o Electrocución, respectivamente, se reduce en un <span class=\"stat\">25%</span>.'),(64,'Black Swan',2,'No llores por mí, cordero','Cuando el enemigo entra en combate, hay una probabilidad base del <span class=\"stat\">100%</span> de aplicarle <span class=\"stat\">50</span> acumulaciones de Arcano.'),(65,'Black Swan',3,'Como arriba, así es abajo','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(66,'Black Swan',4,'Regalo de lágrimas','Los enemigos en el estado de Desvelación reciben un <span class=\"stat\">20%</span> más de daño. Cada vez que un enemigo en este estado comienza su turno o es eliminado, Cisne Negro recupera <span class=\"stat\">8</span> pts. de energía.'),(67,'Black Swan',5,'Estrellas migratorias','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(68,'Black Swan',6,'Dioses buenos, plebe desgraciada','El máximo de acumulaciones de Arcano aumenta en <span class=\"stat\">30</span>.\\nCuando los compañeros de equipo de Cisne Negro atacan a un enemigo, Cisne Negro tiene una probabilidad base del <span class=\"stat\">65%</span> de aplicar 1 acumulación de Arcano a ese objetivo.\\nCada vez que Cisne Negro aplica 1 acumulación de Arcano a un enemigo, la cantidad de acumulaciones aplicadas esta vez aumenta en <span class=\"stat\">1</span>.'),(69,'Blade',1,'La espada que atraviesa el infierno','El daño que infligen el ATQ básico potenciado y la habilidad definitiva de Blade a un enemigo determinado aumenta en una cantidad adicional equivalente al <span class=\"stat\">150%</span> del recuento de PV perdidos de la habilidad definitiva.'),(70,'Blade',2,'Mil pesares por un sueño roto','Cuando Blade está en el estado Panorama infernal, su Prob. CRIT aumenta en un <span class=\"stat\">15%</span>.'),(71,'Blade',3,'Acero templado para sangrar sombras','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(72,'Blade',4,'Rechazado por la muerte, infectado por la vida','Cuando el porcentaje de PV pasa de ser superior al <span class=\"stat\">50%</span> a igual o inferior al <span class=\"stat\">50%</span>, los PV máx. aumentan en un <span class=\"stat\">20%</span>. Este efecto se puede acumular hasta <span class=\"stat\">2</span> veces.'),(73,'Blade',5,'Muerte a ojos de los Diez Líderes','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(74,'Blade',6,'Renacimiento en un cuerpo vacío','El límite de acumulaciones de carga se reduce a <span class=\"stat\">4</span>. El daño infligido por el ataque adicional del talento aumenta en una cantidad equivalente al <span class=\"stat\">50%</span> de los PV máx. de Blade.'),(75,'Boothill',1,'Estrella solitaria del sendero polvoriento','Al inicio de la batalla, obtiene <span class=\"stat\">1</span> acumulación de Ventaja en el bolsillo. Cuando Boothill inflige daño, ignora un <span class=\"stat\">16%</span> de la DEF del objetivo.'),(76,'Boothill',2,'Traficante de hitos','Cuando está en el estado de Duelo a muerte y obtiene Ventaja en el bolsillo, recupera <span class=\"stat\">1</span> pt. de habilidad básica y aumenta su efecto de Ruptura en un <span class=\"stat\">30%</span> durante <span class=\"stat\">2</span> turnos. Este efecto no se puede activar repetidamente en el mismo turno, y también se puede activar al obtener acumulaciones de Ventaja en el bolsillo por encima del límite.'),(77,'Boothill',3,'Guardia del jardín de mármol','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(78,'Boothill',4,'Chef de fiambres','Cuando el enemigo con Duelo a muerte es atacado por Boothill, el daño recibido aumenta un <span class=\"stat\">12%</span> adicional. Cuando Boothill es atacado por un enemigo con Duelo a muerte, el efecto de aumento de daño recibido disminuye en un <span class=\"stat\">12%</span>.'),(79,'Boothill',5,'Discurso en el tocón','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(80,'Boothill',6,'Mapache del hotel Palanca','Cuando inflige Daño de Ruptura activado por el talento, inflige adicionalmente un <span class=\"stat\">40%</span> del multiplicador de Daño de Ruptura al objetivo y un <span class=\"stat\">70%</span> del multiplicador del Daño de Ruptura a los objetivos adyacentes.'),(81,'Bronya',1,'Mejora de fortaleza','Al usar la habilidad básica, hay una probabilidad fija del <span class=\"stat\">50%</span> de recuperar <span class=\"stat\">1</span> pt. de habilidad básica. Este efecto tiene un TdE de <span class=\"stat\">1</span> turno.'),(82,'Bronya',2,'Marcha rápida','Al usar la habilidad básica, cuando el aliado objetivo realiza una acción, su VEL aumenta en un <span class=\"stat\">30%</span> durante <span class=\"stat\">1</span> turno.'),(83,'Bronya',3,'Bombardeo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(84,'Bronya',4,'Por sorpresa','Cuando otro personaje aliado usa su ATQ básico contra un enemigo que tiene Debilidad de <span class=\"elemento\">Viento</span>, Bronya lanza un ataque adicional que inflige un Daño de <span class=\"elemento\">Viento</span> equivalente al <span class=\"stat\">80%</span> del daño de ATQ básico. Este efecto solo se puede activar una vez por turno.'),(85,'Bronya',5,'Imparable','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(86,'Bronya',6,'Arcoíris perforante','El incremento de daño que la habilidad básica de Bronya otorga a un aliado dura <span class=\"stat\">1</span> turno adicional.'),(87,'Cyrene',1,'Epopeya nacida de una página en blanco','Cuando el Demiurgo activa la habilidad de mnemoduende \"Poema del yo verdadero\" para lanzar Danza de flores y flechas, obtiene <span class=\"stat\">6</span> puntos de Remembranza y aumenta en <span class=\"stat\">12</span> la cantidad de rebotes de este ataque.'),(88,'Cyrene',2,'Un mañana en trece reflejos','Al entrar en combate, obtiene <span class=\"stat\">12</span> puntos adicionales de Remembranza. Por cada personaje aliado distinto que reciba un efecto positivo mediante la habilidad de mnemoduende del Demiurgo, el multiplicador del Daño verdadero que infligen los aliados mediante el campo de la habilidad básica aumenta en un <span class=\"stat\">6%</span>, hasta un máximo del <span class=\"stat\">24%</span>.'),(89,'Cyrene',3,'Por ti, tal y como escribí','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(90,'Cyrene',4,'Sigue escribiendo con una sonrisa','Cada vez que el Demiurgo lanza Danza de flores y flechas, el multiplicador del daño de Rebote de la habilidad de mnemoduende \"Poema del yo verdadero\" activada aumenta en un <span class=\"stat\">6%</span> durante la batalla actual. Se puede acumular hasta <span class=\"stat\">24</span> veces.'),(91,'Cyrene',5,'Mirada prendida en las flores de antaño','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(92,'Cyrene',6,'♪ Recuerdos cantados en ondas ♪','Cuando Cirene lanza su habilidad definitiva por primera vez, adelanta la acción de todos los aliados un <span class=\"stat\">100%</span>. Cada vez que el Demiurgo activa la habilidad de mnemoduende \"Poema del yo verdadero\" y lanza Danza de flores y flechas, se obtiene el siguiente efecto según el número de veces que se haya activado en la batalla actual:\n<span class=\"stat\">1</span> vez: cuando el Demiurgo está en el campo de batalla, la DEF de todos los enemigos se reduce en un <span class=\"stat\">20%</span>.\n<span class=\"stat\">2</span> veces o más: la acción de todos los aliados se adelanta un <span class=\"stat\">24%</span>.'),(93,'Cipher',1,'Sonrisa avizora','El daño registrado por Cífer pasa a ser un <span class=\"stat\">150%</span> del daño registrado original. Cuando se lanza el ataque adicional del talento, el ATQ de Cífer aumenta en un <span class=\"stat\">80%</span> durante <span class=\"stat\">2</span> turnos.'),(94,'Cipher',2,'Rapacería bajo presión','Cuando Cífer golpea a un enemigo, tiene una probabilidad base del <span class=\"stat\">120%</span> de hacer que el daño que recibe ese objetivo aumente en un <span class=\"stat\">30%</span> durante <span class=\"stat\">2</span> turnos.'),(95,'Cipher',3,'Prestidigitación indiscernible','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(96,'Cipher',4,'Escapada preparada','Después de que el Cliente habitual reciba un ataque de un aliado, Cífer le inflige un <span class=\"stat\">50%</span> de su ATQ como Daño Cuántico adicional.'),(97,'Cipher',5,'Como la raposa, rauda y mañosa','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(98,'Cipher',6,'A mejor bandida, más desconocida','El daño que inflige el ataque adicional del talento de Cífer aumenta en un <span class=\"stat\">350%</span>. Al registrar el daño, registra además el <span class=\"stat\">16%</span> del daño no excedente infligido con este ataque. Tras reiniciar el contador al lanzar la habilidad definitiva, restablece un <span class=\"stat\">20%</span> del valor que había registrado.'),(99,'Cerydra',1,'Me haré con todas las coronas','Cuando el personaje con Mérito militar inflige daño, ignora el <span class=\"stat\">16%</span> de la DEF de cada objetivo. Si Mérito militar ya ha mejorado a Título nobiliario, el daño de habilidad básica que inflige ese personaje ignora un <span class=\"stat\">20%</span> adicional de la DEF de cada objetivo. Cuando Céridra lanza la habilidad básica, el aliado recupera <span class=\"stat\">2</span> pts. de energía.'),(100,'Cerydra',2,'Forjaré los deseos de todos','El daño que inflige el personaje con Mérito militar aumenta en un <span class=\"stat\">40%</span>. Cuando hay un compañero de equipo con Mérito militar en el campo de batalla, el daño que inflige Céridra aumenta en un <span class=\"stat\">160%</span>.'),(101,'Cerydra',3,'Quemaré las leyes antiguas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(102,'Cerydra',4,'Reharé los reinos mortales','El multiplicador de daño de la habilidad definitiva aumenta en un <span class=\"stat\">240%</span>.'),(103,'Cerydra',5,'Retribuiré favores y afrentas','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(104,'Cerydra',6,'Viajaremos al mar de estrellas','La PEN de la RES a todos los tipos del personaje con Mérito militar aumenta en un <span class=\"stat\">20%</span>, y el multiplicador del daño adicional activado por Mérito militar aumenta en un <span class=\"stat\">300%</span>. Cuando hay un compañero de equipo con Mérito militar en el campo de batalla, la PEN de la RES a todos los tipos de Céridra aumenta en un <span class=\"stat\">20%</span>.'),(105,'Castorice',1,'Doncella nívea y recuerdos amortajados','Cuando los PV actuales del enemigo son iguales o inferiores al <span class=\"stat\">80%</span>/<span class=\"stat\">50%</span> de sus PV máx., el daño que le infligen Garra ósea, abrazo del dragón lóbrego, Garras que rasgan la oscuridad, Aliento que prende las sombras y Alas que abaten las ruinas es un <span class=\"stat\">120%</span>/<span class=\"stat\">140%</span> del daño original.'),(106,'Castorice',2,'Coronación de flores aladas','Tras invocar al mnemoduende Dragón Caído, Castorice obtiene <span class=\"stat\">2</span> acumulaciones de Voluntad ardiente, que se puede acumular hasta <span class=\"stat\">2</span> veces. Voluntad ardiente compensa el consumo de PV del Dragón Caído cuando usa la habilidad de mnemoduende Aliento que prende las sombras y adelanta la acción de Castorice un <span class=\"stat\">100%</span>. Además, Castorice obtiene un <span class=\"stat\">30%</span> de los puntos máximos de Nuevo brote la siguiente vez que lance la habilidad básica potenciada.'),(107,'Castorice',3,'Danza postrera de los devotos','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(108,'Castorice',4,'Descanso arropado en lamentos','Cuando Castorice está en la batalla, los PV regenerados por todos los aliados al recibir curación aumentan en un <span class=\"stat\">20%</span>.'),(109,'Castorice',5,'Capítulos de profecías prístinas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(110,'Castorice',6,'Crisálida que el tiempo romperá','Cuando Castorice o el Dragón Caído infligen daño, la PEN de la RES a Cuántico aumenta en un <span class=\"stat\">20%</span>. Mientras ataca, el Dragón Caído puede reducir la firmeza de los enemigos ignorando sus tipos de Debilidad, y activa el efecto de Ruptura Cuántica cuando rompe su Debilidad. Además, la cantidad de rebotes del talento Alas que abaten las ruinas aumenta adicionalmente en <span class=\"stat\">3</span>.'),(111,'Clara',1,'Alta figura','Al usar la habilidad básica, las Marcas de represalia de los enemigos no se eliminarán.'),(112,'Clara',2,'Abrazo de oso','Tras usar su habilidad definitiva, su ATQ aumenta en un <span class=\"stat\">30%</span> durante <span class=\"stat\">2</span> turnos.'),(113,'Clara',3,'Armadura de frío acero','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(114,'Clara',4,'Calidez familiar','Tras ser atacada, Clara recibe un <span class=\"stat\">30%</span> menos de daño. Este efecto dura hasta que comience su siguiente turno.'),(115,'Clara',5,'Una pequeña promesa','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(116,'Clara',6,'Compañía duradera','Cuando otro aliado recibe un ataque, Svarog tiene una probabilidad fija del <span class=\"stat\">50%</span> de activar un contraataque contra el atacante y marcarlo con Marca de represalia. Al usar la habilidad definitiva, la cantidad de contraataques potenciados aumenta en <span class=\"stat\">1</span>.'),(117,'Dr. Ratio',1,'La calamidad de la arrogancia','El límite de acumulaciones del Rastro Inducción aumenta en <span class=\"stat\">4</span>. Al comenzar el combate, obtienes de inmediato <span class=\"stat\">4</span> acumulaciones de Inducción. Es necesario haber desbloqueado antes el Rastro Inducción.'),(118,'Dr. Ratio',2,'En los detalles está lo divino','Cuando el ataque adicional de su talento golpea a un enemigo, el Dr. Ratio inflige un <span class=\"stat\">20%</span> de su ATQ como Daño <span class=\"elemento\">Imaginario</span> adicional por cada estado negativo que tenga el objetivo. Este efecto se puede activar un máximo de <span class=\"stat\">4</span> veces cada vez que use su ataque adicional.'),(119,'Dr. Ratio',3,'Conócete a ti mismo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(120,'Dr. Ratio',4,'La ignorancia es atrevida','Cuando se activa su talento, el Dr. Ratio recupera <span class=\"stat\">15</span> pts. de energía adicionales.'),(121,'Dr. Ratio',5,'A la deriva en la inmensidad','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(122,'Dr. Ratio',6,'La verdad eterna','Locura de los sabios se puede activar <span class=\"stat\">1</span> vez más. El daño que inflige el ataque adicional del talento aumenta en un <span class=\"stat\">50%</span>.'),(123,'Dan Heng (Imbibitor Lunae)',1,'Amarrado al cielo','Aumenta las acumulaciones posibles de Corazón justo en <span class=\"stat\">4</span>. Además, cada golpe durante un ataque obtiene una acumulación adicional de Corazón justo.'),(124,'Dan Heng (Imbibitor Lunae)',2,'Estandartes de dominación','Tras usar su habilidad definitiva, la acción de Dan Heng • Imbibitor Lunae se adelanta un <span class=\"stat\">100%</span> y consigue <span class=\"stat\">1</span> Escama sacrosanta adicional.'),(125,'Dan Heng (Imbibitor Lunae)',3,'Enseña de cúmulos','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(126,'Dan Heng (Imbibitor Lunae)',4,'Regocijo del céfiro','El efecto positivo de Rugido dominante dura hasta el final de su siguiente turno.'),(127,'Dan Heng (Imbibitor Lunae)',5,'Fin del infortunio','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(128,'Dan Heng (Imbibitor Lunae)',6,'Retorno del reino','Cuando otro personaje aliado usa su habilidad definitiva, la PEN de la RES a <span class=\"elemento\">Imaginario</span> del siguiente Salto fulgurante de Dan Heng - Imbibitor Lunae aumenta en un <span class=\"stat\">20%</span>. Este efecto se puede acumular hasta <span class=\"stat\">3</span> veces.'),(129,'Dan Heng',1,'Cuanto más subes, más dura es la caída','Cuando el porcentaje de PV del objetivo golpeado es igual o superior al <span class=\"stat\">50%</span>, la Prob. CRIT aumenta en un <span class=\"stat\">12%</span>.'),(130,'Dan Heng',2,'Controlar el mal y extinguir la llama','El TdE del talento se reduce en <span class=\"stat\">1</span> turno.'),(131,'Dan Heng',3,'Visto y no visto','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(132,'Dan Heng',4,'Dragón rugiente y sol sofocante','Cuando su habilidad definitiva elimina al objetivo, Dan Heng vuelve a actuar inmediatamente.'),(133,'Dan Heng',5,'Una gota de lluvia alimenta el torrente','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(134,'Dan Heng',6,'Alma atormentada en espera','La Ralentización causada por la habilidad básica reduce la VEL del objetivo en un <span class=\"stat\">8%</span> adicional.'),(135,'Dan Heng (Permansor Terrae)',1,'Muda de escamas antiguas','Cuando Dan Heng - Permansor Terrae lanza la habilidad definitiva, recupera <span class=\"stat\">1</span> pt. de habilidad básica y la PEN de la RES a todos los tipos del Camarada aumenta en un <span class=\"stat\">18%</span> durante <span class=\"stat\">3</span> turnos.'),(136,'Dan Heng (Permansor Terrae)',2,'Guardián trazacaminos','El Espiridraco en estado potenciado de la habilidad definitiva puede actuar <span class=\"stat\">2</span> veces más. Después de que Dan Heng - Permansor Terrae lance la habilidad definitiva, la acción de Espiridraco se adelanta un <span class=\"stat\">100%</span>. Cuando Espiridraco actúa estando potenciado, el daño adicional que inflige el Camarada es un <span class=\"stat\">200%</span> del daño original, y el efecto de escudo otorgado esta vez pasa a ser un <span class=\"stat\">200%</span> del efecto de escudo original.'),(137,'Dan Heng (Permansor Terrae)',3,'Legado de la creación','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(138,'Dan Heng (Permansor Terrae)',4,'Voto de recipiente corpóreo','El daño que recibe el Camarada se reduce en un <span class=\"stat\">20%</span>.'),(139,'Dan Heng (Permansor Terrae)',5,'El largo camino de la Permanencia','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(140,'Dan Heng (Permansor Terrae)',6,'Sueño de naturaleza ubicua','Cuando hay un Camarada en la batalla, el daño que reciben todos los enemigos aumenta en un <span class=\"stat\">20%</span>, y cuando el Camarada inflige daño, ignora un <span class=\"stat\">12%</span> de la DEF del enemigo. Cuando Dan Heng - Permansor Terrae lanza la habilidad definitiva, el Camarada inflige un <span class=\"stat\">330%</span> de su ATQ como daño adicional de su mismo tipo a todos los enemigos.'),(141,'Evernight',1,'Duerme en el sueño de la larga noche','Cuando evernight está en la batalla y hay <span class=\"stat\">4</span> o más/<span class=\"stat\">3</span>/<span class=\"stat\">2</span>/<span class=\"stat\">1</span> enemigos en el campo de batalla, el daño que infligen los mnemoduendes aliados es un <span class=\"stat\">120%</span>/<span class=\"stat\">125%</span>/<span class=\"stat\">130%</span>/<span class=\"stat\">150%</span> del daño original.'),(142,'Evernight',2,'Escucha los susurros adormilados','El Daño CRIT de evernight y el mnemoduende Nox aumenta en un <span class=\"stat\">40%</span>. Cada vez que Larganoche obtiene Memoria, la cantidad de Memoria obtenida aumenta en <span class=\"stat\">2</span> pts. Al lanzar la habilidad definitiva, obtiene <span class=\"stat\">2</span> pts. de carga adicionales de Adivinanza oscura.'),(143,'Evernight',3,'No temas, atrás queda la pesadilla','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(144,'Evernight',4,'Despierta, el mañana es tuyo','Cuando Evernight está en la batalla, la eficiencia de la Ruptura de Debilidad de los mnemoduendes aliados aumenta en un <span class=\"stat\">25%</span>. La eficiencia de la Ruptura de Debilidad del mnemoduende Nox aumenta en un <span class=\"stat\">25%</span> adicional.'),(145,'Evernight',5,'Olvida el yo de los recuerdos','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(146,'Evernight',6,'Así, siempre','Cuando Evernight está en la batalla, la PEN de la RES a todos los tipos de todos los aliados aumenta en un <span class=\"stat\">20%</span>. Después de que el mnemoduende Nox lance Sueños que desaparecen como el rocío, Evernight obtiene el <span class=\"stat\">30%</span> de la Memoria consumida en este ataque.'),(147,'Evanescia',1,'',''),(148,'Evanescia',2,'',''),(149,'Evanescia',3,'','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(150,'Evanescia',4,'',''),(151,'Evanescia',5,'','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(152,'Evanescia',6,'',''),(153,'Fugue',1,'Del suelo al cielo','La eficiencia de la Ruptura de Debilidad de los aliados con Plegaria raposiana aumenta en un <span class=\"stat\">50%</span>.'),(154,'Fugue',2,'De la virtud viene la ventura','Cuando se rompe la Debilidad de un enemigo, Fugue recupera <span class=\"stat\">3</span> pts. de energía. Tras lanzar su habilidad definitiva, la acción de todos los aliados se adelanta un <span class=\"stat\">24%</span>.'),(155,'Fugue',3,'Mi verdadero yo','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(156,'Fugue',4,'Cambio de forma, cambio de nombre','El Daño de Ruptura que infligen los aliados con Plegaria raposiana aumenta en un <span class=\"stat\">20%</span>.'),(157,'Fugue',5,'Nubes auspiciosas','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(158,'Fugue',6,'Clarividencia de fortunas y desgracias','La eficiencia de la Ruptura de Debilidad de Fugue aumenta en un <span class=\"stat\">50%</span>. Cuando Fugue está en el estado de Llama tórrida, el efecto de Plegaria raposiana aplica a todos los aliados.'),(159,'Fu Xuan',1,'Ciclo de vida y muerte','Conocimiento aumenta el Daño CRIT en un <span class=\"stat\">30%</span>.'),(160,'Fu Xuan',2,'Presagio siniestro','Cuando Matriz del Presagio está activa, si un aliado recibe daño letal, todo el daño letal que reciban los aliados durante esa acción no provocará que sean derrotados y regenerarán inmediatamente una cantidad de PV equivalente al <span class=\"stat\">70%</span> de sus PV máx. Este efecto solo se puede activar una vez en cada batalla.'),(161,'Fu Xuan',3,'Talismán vertical','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(162,'Fu Xuan',4,'Estrella favorable','Cuando otros aliados afectados por Matriz del Presagio reciben un ataque, Fu Xuan recupera <span class=\"stat\">5</span> pts. de energía.'),(163,'Fu Xuan',5,'Adivinación veraz','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(164,'Fu Xuan',6,'Salvación','Cuando se activa Matriz del Presagio, se hace un recuento de los PV perdidos por todos los aliados en esta batalla. El daño infligido por la habilidad definitiva de Fu Xuan aumenta en un <span class=\"stat\">200%</span> de este recuento de PV perdidos.\nEl recuento de PV perdidos en esta batalla no puede superar el <span class=\"stat\">120%</span> de los PV máx. de Fu Xuan. Al usar su habilidad definitiva, este recuento se reinicia.'),(165,'Firefly',1,'Dormí plácidamente en la crisálida escarlata','La habilidad básica potenciada ignora un <span class=\"stat\">15%</span> de la DEF de los objetivos y no consume pts. de habilidad básica.'),(166,'Firefly',2,'Me precipito desde el cielo fragmentado','Al usar el ATQ básico potenciado o la habilidad básica potenciada en el estado de Combustión completa, si derrota a un enemigo o lo afecta con Ruptura de Debilidad, SAM obtiene inmediatamente <span class=\"stat\">1</span> turno adicional. Este efecto se puede volver a activar después de <span class=\"stat\">1</span> turno.'),(167,'Firefly',3,'Me abandono a los sueños en la galaxia silenciosa','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(168,'Firefly',4,'Veré la luz de las luciérnagas','En el estado de Combustión completa, la RES a efecto de SAM aumenta en un <span class=\"stat\">50%</span>.'),(169,'Firefly',5,'Me elevo brillante de la larga noche sin sueños','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(170,'Firefly',6,'Brillo hacia el mañana aun después de florecer','Cuando SAM está en el estado de Combustión completa, su PEN de la RES a <span class=\"elemento\">Fuego</span> aumenta en un <span class=\"stat\">20%</span>. Al usar el ATQ básico potenciado o la habilidad básica potenciada, su eficiencia de la Ruptura de Debilidad aumenta en un <span class=\"stat\">50%</span>.'),(171,'Feixiao',1,'Cielo apaciguado','Tras lanzar Danza de cortes relámpago o Aluvión de hachazos hendedores, el daño de habilidad definitiva que inflige Feixiao aumenta adicionalmente en un <span class=\"stat\">10%</span> del daño original. Puede acumularse hasta <span class=\"stat\">5</span> veces y dura hasta que termina la acción de la habilidad definitiva.'),(172,'Feixiao',2,'Rito lunar','En los efectos del talento, cada vez que un objetivo aliado lanza <span class=\"stat\">1</span> ataque adicional, Feixiao gana <span class=\"stat\">1</span> punto de Feihuang. Este efecto solo se puede activar un máximo de <span class=\"stat\">6</span> veces por turno.'),(173,'Feixiao',3,'Estrella del buen augurio','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(174,'Feixiao',4,'Susurro del hielo en la ventisca','La Reducción de Firmeza del ataque adicional del talento aumenta en un <span class=\"stat\">100%</span> y, al ser lanzado, su VEL aumenta en un <span class=\"stat\">8%</span> durante <span class=\"stat\">2</span> turnos.'),(175,'Feixiao',5,'Salto celeste','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(176,'Feixiao',6,'Mirada al origen','La PEN de la RES a todos los tipos del daño de habilidad definitiva que inflige Feixiao aumenta en un <span class=\"stat\">20%</span>. A su vez, el daño de ataque adicional del talento se considera como daño de habilidad definitiva, y su multiplicador de daño aumenta en un <span class=\"stat\">140%</span>.'),(177,'Guinaifen',1,'Comer fideos cabeza abajo','Al usar la habilidad básica, hay una probabilidad base del <span class=\"stat\">100%</span> de reducir la RES a efecto del enemigo que recibe el ataque en un <span class=\"stat\">10%</span> durante <span class=\"stat\">2</span> turnos.'),(178,'Guinaifen',2,'Silbar y cepillarse los dientes a la vez','Cuando el objetivo está afectado por Quemadura, el ATQ básico y la habilidad básica de Guinaifen aumentan el multiplicador de daño de su efecto de Quemadura en un <span class=\"stat\">40%</span>.'),(179,'Guinaifen',3,'Romper una piedra sobre el pecho','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(180,'Guinaifen',4,'Parar una lanza con el cuello','Cada vez que la Quemadura infligida por Guinaifen causa daño, Guinaifen recupera <span class=\"stat\">2</span> pts. de energía.'),(181,'Guinaifen',5,'Tragar sables hasta la empuñadura','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(182,'Guinaifen',6,'Atrapar balas con las manos','Aumenta las acumulaciones posibles de Beso ardiente en <span class=\"stat\">1</span>.'),(183,'Gepard',1,'Diligencia debida','Al usar la habilidad básica, la probabilidad base de afectar con Congelación al enemigo aumenta en un <span class=\"stat\">35%</span>.'),(184,'Gepard',2,'Frío persistente','Cuando se disipa el estado de Congelación causado a un enemigo por la habilidad básica de Gepard, la VEL de ese enemigo se reduce en un <span class=\"stat\">20%</span> durante <span class=\"stat\">1</span> turno.'),(185,'Gepard',3,'Nunca me rendiré','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(186,'Gepard',4,'La fe mueve montañas','Cuando Gepard está en la batalla, la RES a efecto de todos los aliados aumenta en un <span class=\"stat\">20%</span>.'),(187,'Gepard',5,'Férreo puño frío','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(188,'Gepard',6,'Determinación inquebrantable','Cuando se activa el talento, Gepard actúa inmediatamente y regenera una cantidad de PV adicional equivalente al <span class=\"stat\">50%</span> de sus PV máx.'),(189,'Gallagher',1,'Perro salado','Cuando Gallagher entra en combate, recupera <span class=\"stat\">20</span> pts. de energía y su RES a efecto aumenta en un <span class=\"stat\">50%</span>.'),(190,'Gallagher',2,'Cola de león','Al usar la habilidad básica, se disipa <span class=\"stat\">1</span> estado negativo del objetivo aliado y aumenta su RES a efecto en un <span class=\"stat\">30%</span> durante <span class=\"stat\">2</span> turnos.'),(191,'Gallagher',3,'Resucitador','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(192,'Gallagher',4,'Última palabra','La duración del estado de Melopea aplicado por la habilidad definitiva de Gallagher aumenta en <span class=\"stat\">1</span> turno.'),(193,'Gallagher',5,'Muerte en la tarde','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(194,'Gallagher',6,'Sangre y arena','El efecto de Ruptura de Gallagher aumenta en un <span class=\"stat\">20%</span> y su eficiencia de la Ruptura de Debilidad aumenta en un <span class=\"stat\">20%</span>.'),(195,'Huohuo',1,'Poseída por un heliobus','La duración del efecto de Vida sacrificada que genera el talento aumenta en <span class=\"stat\">1</span> turno. Además, cuando Huohuo tiene Vida sacrificada, la VEL de todos los aliados aumenta en un <span class=\"stat\">12%</span>.'),(196,'Huohuo',2,'Talismanes de jueces y espíritu en la cola','Cuando Huohuo tiene Vida sacrificada, si un aliado recibe un golpe letal no cae derrotado, sino que regenera una cantidad de PV equivalente al <span class=\"stat\">50%</span> de sus PV máx. y la duración de Vida sacrificada se reduce en <span class=\"stat\">1</span> turno. Este efecto se puede activar <span class=\"stat\">2</span> veces en cada batalla.'),(197,'Huohuo',3,'Cuerpo del mal, polillas a la luz','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(198,'Huohuo',4,'Siempre juntos y en conflicto','Al curar a un aliado mediante su habilidad básica o el efecto de su talento, la curación realizada de Huohuo aumenta proporcionalmente cuantos menos PV tenga el aliado, hasta un aumento máximo del <span class=\"stat\">80%</span>.'),(199,'Huohuo',5,'Somete todo mal, por decreto de los Diez Líderes','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(200,'Huohuo',6,'Objetivo compartido, destino simbiótico','Al curar a un aliado, el daño infligido por el aliado aumenta en un <span class=\"stat\">50%</span> durante <span class=\"stat\">2</span> turnos.'),(201,'Hook',1,'A la cama temprano','La habilidad básica potenciada inflige un <span class=\"stat\">20%</span> más de daño.'),(202,'Hook',2,'Tripita feliz, persona feliz','La duración del estado de Quemadura causado por la habilidad básica de Hook se alarga en <span class=\"stat\">1</span> turno.'),(203,'Hook',3,'Nada de elegir','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(204,'Hook',4,'No pasa nada si no lo sabes','Al activar el talento, tiene una probabilidad base del <span class=\"stat\">100%</span> de afectar a los enemigos adyacentes al objetivo con una Quemadura equivalente a la de la habilidad básica.'),(205,'Hook',5,'Que todos sepan de las hazañas de Los Topos','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(206,'Hook',6,'Siempre lista para patear traseros','Hook inflige un <span class=\"stat\">20%</span> más de daño a los enemigos afectados por Quemadura.'),(207,'Himeko',1,'Infancia','Cuando se activa Carrera de la victoria, la VEL de Himeko aumenta en un <span class=\"stat\">20%</span> durante <span class=\"stat\">2</span> turnos.'),(208,'Himeko',2,'Convergencia','Cuando el objetivo tiene un porcentaje de PV igual o inferior al <span class=\"stat\">50%</span>, recibe un <span class=\"stat\">15%</span> más de daño.'),(209,'Himeko',3,'','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(210,'Himeko',4,'Dedicación','Cuando Himeko lanza su habilidad básica y rompe la Debilidad de un enemigo, consigue <span class=\"stat\">1</span> carga adicional.'),(211,'Himeko',5,'Aspiraciones','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(212,'Himeko',6,'Trazando caminos','La habilidad definitiva inflige daño <span class=\"stat\">2</span> veces adicionales. Cada vez, inflige a un enemigo al azar un Daño de <span class=\"elemento\">Fuego</span> equivalente al <span class=\"stat\">40%</span> del daño original recibido.'),(213,'Herta',1,'Me regodeo en tu miseria','Al usar el ATQ básico, si el objetivo tiene un porcentaje de PV igual o inferior al <span class=\"stat\">50%</span>, Herta inflige un Daño de <span class=\"elemento\">Hielo</span> adicional equivalente al <span class=\"stat\">40%</span> de su ATQ.'),(214,'Herta',2,'Que no pare la fiesta','Cada vez que se activa el talento, su Prob. CRIT aumenta en un <span class=\"stat\">3%</span>. Este efecto se puede acumular hasta <span class=\"stat\">5</span> veces.'),(215,'Herta',3,'Soy de ese tipo de chicas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(216,'Herta',4,'Donde más duele','Cuando el talento se activa, el daño que inflige Herta aumenta en un <span class=\"stat\">10%</span>.'),(217,'Herta',5,'Insulta a lo grande o no lo hagas','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(218,'Herta',6,'Nadie me puede traicionar','Tras usar la habilidad definitiva, su ATQ aumenta en un <span class=\"stat\">25%</span> durante <span class=\"stat\">1</span> turno.'),(219,'Hanya',1,'Un corazón','Cuando un aliado con el efecto de la habilidad definitiva de Hanya derrota a un enemigo, la acción de Hanya se adelanta un <span class=\"stat\">15%</span>. Este efecto solo puede activarse <span class=\"stat\">1</span> vez por turno.'),(220,'Hanya',2,'Dos vistas','Tras usar su habilidad básica, su VEL aumenta en un <span class=\"stat\">20%</span> durante <span class=\"stat\">1</span> turno.'),(221,'Hanya',3,'Tres tentaciones','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(222,'Hanya',4,'Cuatro verdades','La duración de la habilidad definitiva aumenta en <span class=\"stat\">1</span> turno.'),(223,'Hanya',5,'Cinco agregados','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(224,'Hanya',6,'Seis reverencias','El efecto de aumento de daño del talento aumenta en un <span class=\"stat\">10%</span> adicional.'),(225,'Hysilens',1,'Pregunta por qué mi corazón se aflige','Cuando Hysilens está en el campo de batalla, el Daño con el tiempo que infligen los aliados es un <span class=\"stat\">116%</span> del original. Cuando Hysilens afecta a un enemigo con Intemperie, Sangrado, Quemadura o Electrocución mediante su talento, tiene una probabilidad base del <span class=\"stat\">100%</span> de afectarlo adicionalmente con un estado de Intemperie, Sangrado, Quemadura o Electrocución equivalente al del talento y que puede coexistir con él.'),(226,'Hysilens',2,'Dime por qué las olas rugen','Mientras el campo está activo, el efecto de aumento de daño infligido del Rastro Cuerdas perladas se aplica a todos los aliados.'),(227,'Hysilens',3,'Averigua por qué olvida la llama','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(228,'Hysilens',4,'Observa por qué fluye el tiempo','Mientras dure el campo, la RES a todos los tipos de todos los enemigos se reduce en un <span class=\"stat\">20%</span>.'),(229,'Hysilens',5,'Tarareo mientras me arreglo','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(230,'Hysilens',6,'Cuándo volverás de tu profundo lecho','Mientras el campo está activo, el número máximo de veces que se puede activar el efecto de Daño <span class=\"elemento\">Físico</span> con el tiempo de Hysilens al principio de cada turno o tras cada ataque de un aliado aumenta a <span class=\"stat\">12</span>, y el multiplicador del daño infligido aumenta en un <span class=\"stat\">20%</span>.'),(231,'Hyacine',1,'Protectora de la llama nocturna','Cuando Hyacine está en el estado de Cielo lavado, todos los aliados aumentan sus PV máx. en un <span class=\"stat\">50%</span> adicional y, tras atacar, regeneran inmediatamente una cantidad de PV equivalente al <span class=\"stat\">8%</span> de los PV máx. de Hyacine.'),(232,'Hyacine',2,'Ven a sentarte en mi jardín','Cuando los PV de un aliado se reducen, la VEL aumenta en un <span class=\"stat\">30%</span> durante <span class=\"stat\">2</span> turnos.'),(233,'Hyacine',3,'¡Aventurémonos hacia el sol!','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(234,'Hyacine',4,'Te regalo este ámbar brillante','El Rastro \"Respiro en el vendaval\" se potencia. Por cada <span class=\"stat\">1</span> pt. de VEL de exceso, el Daño CRIT de Hyacine e Ica aumenta en un <span class=\"stat\">2%</span> adicional.'),(235,'Hyacine',5,'Reverso de arrebol marino','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(236,'Hyacine',6,'Cielos, escuchen mi ruego','El porcentaje de curación acumulada que se borra cuando Ica lanza la habilidad de mnemoduende pasa a ser el <span class=\"stat\">12%</span>. Cuando Ica está en el campo de batalla, la PEN de la RES a todos los tipos de todos los aliados aumenta en un <span class=\"stat\">20%</span>.'),(237,'Jingliu',1,'Asalto lunar a las puertas celestiales','Al lanzar la habilidad definitiva o la habilidad básica potenciada, el Daño CRIT de Jingliu aumenta en un <span class=\"stat\">24%</span> durante <span class=\"stat\">1</span> turno. Si solo golpea a 1 enemigo, le inflige de forma adicional un <span class=\"stat\">100%</span> del ATQ de Jingliu como Daño de Hielo.'),(238,'Jingliu',2,'Sombras lunares en Qixing','Tras usar la habilidad definitiva, el daño de la siguiente habilidad básica potenciada aumenta en un <span class=\"stat\">80%</span>.'),(239,'Jingliu',3,'Cuarto creciente vigilante','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(240,'Jingliu',4,'Lucero de la noche','Mientras está en el estado Transmigración espectral, el aumento de ATQ que obtiene cuando consume PV de los aliados se incrementa de forma adicional en un <span class=\"stat\">90%</span> del total de PV consumidos a todos los aliados. El límite de ATQ que se puede obtener de esta forma aumenta en un <span class=\"stat\">30%</span>.'),(241,'Jingliu',5,'Brillo estelar oscurecido','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(242,'Jingliu',6,'Eclipse vacíacuerpo','Cuando Jingliu entra en el estado Transmigración espectral, el límite de acumulaciones de Sizigia aumenta en 1 y obtiene <span class=\"stat\">1</span> acumulación adicional de Sizigia. En el estado Transmigración espectral, el Daño CRIT aumenta en un <span class=\"stat\">50%</span>.'),(243,'Jing Yuan',1,'Corte, acantilados cercenados','Cuando el caballero divino lanza un ataque, el multiplicador de daño que inflige a los enemigos adyacentes al objetivo aumenta adicionalmente en una cantidad equivalente al <span class=\"stat\">25%</span> del multiplicador de daño del objetivo principal.'),(244,'Jing Yuan',2,'Falange, soles bloqueados','Tras la acción del caballero divino, el ATQ básico, la habilidad básica y la habilidad definitiva de Jing Yuan infligen un <span class=\"stat\">20%</span> más de daño durante <span class=\"stat\">2</span> turnos.'),(245,'Jing Yuan',3,'Golpe, luz destrozada','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(246,'Jing Yuan',4,'Espada, estrellas derribadas','Por cada golpe que inflige el caballero divino, Jing Yuan recupera <span class=\"stat\">2</span> pts. de energía.'),(247,'Jing Yuan',5,'Veteranía, muerte conquistada','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(248,'Jing Yuan',6,'Conjuro, enemigos derrotados','Cada golpe que inflige el caballero divino hace que el objetivo enemigo entre en un estado de Vulnerabilidad.\nLos enemigos vulnerables reciben un <span class=\"stat\">12%</span> más de daño hasta que termine el ataque actual del caballero divino. Este efecto se puede acumular hasta <span class=\"stat\">3</span> veces.'),(249,'Jiaoqiu',1,'Transferencia pentapática','El daño que infligen los aliados a los enemigos afectados con Asado al rescoldo aumenta en un <span class=\"stat\">40%</span>. Cada vez que el objetivo es afectado con Asado al rescoldo por la activación del talento, se obtiene <span class=\"stat\">1</span> acumulación adicional del efecto actual de Asado al rescoldo.'),(250,'Jiaoqiu',2,'Del sabor sale el dolor','Cuando un enemigo está en el estado de Asado al rescoldo, el multiplicador del Daño de <span class=\"elemento\">Fuego</span> con el tiempo que le inflige Asado al rescoldo aumenta en un <span class=\"stat\">300%</span>.'),(251,'Jiaoqiu',3,'Armonía de sabor irresistible','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(252,'Jiaoqiu',4,'Serenidad interior y lustre exterior','Mientras el campo está activo, el ATQ de los enemigos se reduce en un <span class=\"stat\">15%</span>.'),(253,'Jiaoqiu',5,'Lucha en la luz y asesta en las sombras','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(254,'Jiaoqiu',6,'Pirovínculo nonomorfo','Cuando un enemigo es derrotado, sus acumulaciones de Asado al rescoldo se agregan al enemigo con menos acumulaciones de Asado al rescoldo en el campo de batalla. El límite de acumulaciones de Asado al rescoldo aumenta a <span class=\"stat\">9</span>. Cada acumulación de Asado al rescoldo reduce la RES a todos los tipos del objetivo en un <span class=\"stat\">3%</span>.'),(255,'Jade',1,'¿Altruismo? Comerciable, no obstante','El daño de ataque adicional del talento de Jade aumenta en un <span class=\"stat\">32%</span>. Si un personaje en el estado de Cobrador de deudas golpea a <span class=\"stat\">2</span>/<span class=\"stat\">1</span> enemigos tras atacar, Jade obtiene <span class=\"stat\">1</span>/<span class=\"stat\">2</span> puntos de carga adicionales respectivamente.'),(256,'Jade',2,'¿Moralidad? Autenticada por la presente','Cuando hay <span class=\"stat\">15</span> acumulaciones de Prenda, la Prob. CRIT de Jade aumenta en un <span class=\"stat\">18%</span>.'),(257,'Jade',3,'¿Franqueza? Pronto será empeñada','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(258,'Jade',4,'¿Sinceridad? Solo con opción de venta','Al usar la habilidad definitiva, el daño que inflige Jade ignora un <span class=\"stat\">12%</span> de la DEF del enemigo durante <span class=\"stat\">3</span> turnos.'),(259,'Jade',5,'¿Esperanza? Dada en pago hace tiempo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(260,'Jade',6,'¿Justicia? Pendiente de patrocinio','Cuando hay personajes en el estado de Cobrador de deudas en el campo de batalla, la PEN de la RES a Cuántico de Jade aumenta en un <span class=\"stat\">20%</span>, y Jade obtiene el estado de Cobrador de deudas.'),(261,'Kafka',1,'Da capo','Al lanzar un ataque, hay un <span class=\"stat\">100%</span> de probabilidad base de que el Daño con el tiempo que recibe el objetivo aumente en un <span class=\"stat\">30%</span> durante <span class=\"stat\">2</span> turnos.'),(262,'Kafka',2,'Fortississimo','Cuando Kafka está en la batalla, el Daño con el tiempo que infligen todos los aliados aumenta en un <span class=\"stat\">25%</span>.'),(263,'Kafka',3,'Capriccio','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(264,'Kafka',4,'Recitativo','Cuando el enemigo recibe daño del estado de Electrocución provocado por Kafka, Kafka recupera <span class=\"stat\">2</span> pts. de energía adicionales.'),(265,'Kafka',5,'Doloroso','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(266,'Kafka',6,'Leggiero','El multiplicador de daño de la Electrocución que aplica a los enemigos la habilidad definitiva, la técnica o el ataque adicional del talento aumenta en un <span class=\"stat\">156%</span> y la duración de Electrocución se alarga en <span class=\"stat\">1</span> turno.'),(267,'Lynx',1,'Mañana de paseo por la nieve','La curación realizada por Lynx aumenta en un <span class=\"stat\">20%</span> para los objetivos aliados que tengan un porcentaje de PV igual o inferior al <span class=\"stat\">50%</span>. También aplica a la curación continua.'),(268,'Lynx',2,'Mediodía de hornillo portátil','Los objetivos con Reacción de supervivencia pueden resistir la aplicación de estados negativos <span class=\"stat\">1</span> vez.'),(269,'Lynx',3,'Tarde de baliza de avalanchas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(270,'Lynx',4,'Atardecer de fuego de campamento','Al obtener Reacción de supervivencia, el ATQ del objetivo aumenta en una cantidad equivalente al <span class=\"stat\">3%</span> de los PV máx. de Lynx durante <span class=\"stat\">1</span> turno.'),(271,'Lynx',5,'Noche de té de la aurora','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(272,'Lynx',6,'Alba del mapa de exploración','El efecto de aumento de los PV máx. de Reacción de supervivencia se incrementa de forma adicional en una cantidad equivalente al <span class=\"stat\">6%</span> de los PV máx. de Lynx. Además, la RES a efecto aumenta en un <span class=\"stat\">30%</span>.'),(273,'Luocha',1,'Ablución de los vivos','Mientras el campo está activo, el ATQ de todos los aliados aumenta en un <span class=\"stat\">20%</span>.'),(274,'Luocha',2,'Concesión inmaculada','Al activar el efecto de la habilidad básica, si el aliado objetivo tiene en ese momento un porcentaje de PV inferior al <span class=\"stat\">50%</span>, la curación realizada por Luocha aumenta en un <span class=\"stat\">30%</span>. Si el aliado tiene un porcentaje de PV igual o superior al <span class=\"stat\">50%</span>, Luocha le otorga un escudo que absorbe un daño equivalente al <span class=\"stat\">18%</span> del ATQ de Luocha + <span class=\"stat\">240</span> durante <span class=\"stat\">2</span> turnos.'),(275,'Luocha',3,'Intento de bobos','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(276,'Luocha',4,'Juicio de espinas','Los enemigos se ven afectados por Debilitación cuando el campo de Luocha está activo y el daño que infligen se reduce en un <span class=\"stat\">12%</span>.'),(277,'Luocha',5,'Marca de sacrificio','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(278,'Luocha',6,'En polvo te convertirás','Al usar la habilidad definitiva, hay una probabilidad fija del <span class=\"stat\">100%</span> de que la RES a todos los tipos de todos los enemigos se reduzca en un <span class=\"stat\">20%</span> durante <span class=\"stat\">2</span> turnos.'),(279,'Luka',1,'Lucha interminable','Cuando Luka realiza una acción, si el objetivo está afectado por Sangrado, el daño que inflige Luka aumenta en un <span class=\"stat\">15%</span> durante <span class=\"stat\">2</span> turnos.'),(280,'Luka',2,'El enemigo es débil, yo soy fuerte','Cuando la habilidad básica golpea a un enemigo con Debilidad Física, Luka obtiene <span class=\"stat\">1</span> acumulación de Voluntad luchadora.'),(281,'Luka',3,'Nacido para el ring','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(282,'Luka',4,'Persistencia implacable','Por cada acumulación de Voluntad luchadora, el ATQ aumenta en un <span class=\"stat\">5%</span>. Este efecto se puede acumular hasta <span class=\"stat\">4</span> veces.'),(283,'Luka',5,'El espíritu de Llamarada','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(284,'Luka',6,'El aplauso del campeón','Tras golpear con el Puño rompecielos de su ATQ básico potenciado a un enemigo afectado por Sangrado, el estado de Sangrado inflige al instante <span class=\"stat\">1</span> vez adicional un daño equivalente al <span class=\"stat\">8%</span> del daño de Sangrado original por cada golpe de Puño certero de ese ATQ básico potenciado.'),(285,'Lingsha',1,'Ramo en flor contra los males','La eficiencia de la Ruptura de Debilidad de Lingsha aumenta en un <span class=\"stat\">50%</span>. Cuando se rompe la Debilidad de un enemigo, reduce su DEF en un <span class=\"stat\">20%</span>.'),(286,'Lingsha',2,'Reposo tras el velo de humo','Al lanzar la habilidad definitiva, el efecto de Ruptura de todos los aliados aumenta en un <span class=\"stat\">40%</span> durante <span class=\"stat\">3</span> turnos.'),(287,'Lingsha',3,'Brillo del pábilo floral','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(288,'Lingsha',4,'Aromas del recuerdo bajo el dosel','Cuando Fuyuan actúa, regenera al objetivo aliado con menos PV actualmente una cantidad de PV equivalente al <span class=\"stat\">40%</span> del ATQ de Lingsha.'),(289,'Lingsha',5,'Compostura ante las vueltas y revueltas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(290,'Lingsha',6,'Reclusión de fragancia acumulada','Cuando Fuyuan está en el campo de batalla, la RES a todos los tipos de todos los enemigos se reduce en un <span class=\"stat\">20%</span>. Cuando Fuyuan ataca, inflige daño <span class=\"stat\">4</span> veces adicionales. Cada vez, inflige un <span class=\"stat\">50%</span> del ATQ de Lingsha como Daño de <span class=\"elemento\">Fuego</span> a un enemigo al azar y causa <span class=\"stat\">5</span> puntos de Reducción de Firmeza. Elige prioritariamente a objetivos con una Firmeza superior a <span class=\"stat\">0</span> y que tengan Debilidad de <span class=\"elemento\">Fuego</span>.'),(291,'Mydei',1,'Espalda por el frío curtida','El multiplicador del daño que Deicidio, ascenso divino inflige al objetivo principal aumenta en un <span class=\"stat\">30%</span>. Deicidio, ascenso divino pasa a infligir a todos los enemigos un Daño <span class=\"elemento\">Imaginario</span> equivalente al multiplicador de daño del objetivo principal.'),(292,'Mydei',2,'Estertor de los muertos del Conflicto','Durante el estado de Venganza de sangre, el daño que inflige Midei ignora un <span class=\"stat\">15%</span> de la DEF de los enemigos. Tras recibir una curación, un <span class=\"stat\">40%</span> de la curación recibida se convierte en carga. La carga convertida acumulada no puede superar <span class=\"stat\">40</span> pts. Después de que cualquier unidad actúe, se restablece la carga que se puede acumular.'),(293,'Mydei',3,'Banquete de gloria inmarcesible','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(294,'Mydei',4,'Cuerno que despierta al león silencioso','Durante el estado de Venganza de sangre, el Daño CRIT aumenta en un <span class=\"stat\">30%</span>. Tras recibir un ataque enemigo, regenera un <span class=\"stat\">10%</span> de sus PV máx.'),(295,'Mydei',5,'Cuerpo por la guerra esculpido','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(296,'Mydei',6,'Montaña de sangre sedimentada','Al entrar en combate, entra inmediatamente en el estado de Venganza de sangre y la carga necesaria para activar Deicidio, ascenso divino se reduce a <span class=\"stat\">100</span> puntos.'),(297,'Moze',1,'Juramento','Tras entrar en combate, Moze recupera <span class=\"stat\">20</span> pts. de energía. Cada vez que se activa el daño adicional del talento, Moze recupera <span class=\"stat\">2</span> pts. de energía.'),(298,'Moze',2,'Castigo','El Daño CRIT que infligen todos los objetivos aliados a los enemigos marcados como Presa aumenta en un <span class=\"stat\">40%</span>.'),(299,'Moze',3,'Persecución','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(300,'Moze',4,'Camuflaje','Al lanzar la habilidad definitiva, el daño que inflige Moze aumenta en un <span class=\"stat\">30%</span> durante <span class=\"stat\">2</span> turnos.'),(301,'Moze',5,'Impostura','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(302,'Moze',6,'Lealtad','El multiplicador de daño del ataque adicional del talento aumenta en un <span class=\"stat\">25%</span>.'),(303,'Misha',1,'Ilusión caprichosa','Al usar la habilidad definitiva, el número de golpes por acción aumenta en <span class=\"stat\">1</span> por cada enemigo que haya en el campo de batalla, hasta un máximo de <span class=\"stat\">5</span> golpes más.'),(304,'Misha',2,'Anhelo de juventud','Antes de que cada golpe de la habilidad definitiva alcance a su objetivo, hay un <span class=\"stat\">24%</span> de probabilidad base de reducir su DEF en un <span class=\"stat\">16%</span> durante <span class=\"stat\">3</span> turnos.'),(305,'Misha',3,'Vestigios de felicidad','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(306,'Misha',4,'Apariencia familiar','Aumenta el multiplicador de daño de cada golpe de la habilidad definitiva en un <span class=\"stat\">6%</span>.'),(307,'Misha',5,'Génesis del amor y la amistad','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(308,'Misha',6,'Deseo del pasado','Al usar la habilidad definitiva, inflige un <span class=\"stat\">30%</span> más de daño hasta que termine su turno. Además, la siguiente vez que use la habilidad básica, los aliados recuperan <span class=\"stat\">1</span> pt. de habilidad básica.'),(309,'March 7 (Preservation)',1,'Tu imagen en el recuerdo','Cada vez que la habilidad definitiva congela a un objetivo, Siete de Marzo recupera <span class=\"stat\">6</span> pts. de energía.'),(310,'March 7 (Preservation)',2,'Su imagen en el recuerdo','Al entrar en combate, el aliado con menor porcentaje de PV obtiene un escudo equivalente al <span class=\"stat\">24%</span> de la DEF de Siete de Marzo + <span class=\"stat\">320</span> durante <span class=\"stat\">3</span> turnos.'),(311,'March 7 (Preservation)',3,'Todo en el recuerdo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(312,'March 7 (Preservation)',4,'No quiero perder','El efecto de contraataque del talento puede activarse una vez más en cada turno. Además, la cantidad de daño que inflige el contraataque aumenta en el equivalente al <span class=\"stat\">30%</span> de la DEF de Siete de Marzo.'),(313,'March 7 (Preservation)',5,'No quiero olvidar','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(314,'March 7 (Preservation)',6,'Así, siempre...','Los aliados protegidos por el escudo de la habilidad básica regeneran un <span class=\"stat\">4%</span> de sus PV máx. + <span class=\"stat\">106</span> PV al principio de cada turno.'),(315,'March 7 (Hunt)',1,'Espada de lustre astral','Cuando el Maestro está en el campo de batalla, la VEL de Siete de Marzo aumenta en un <span class=\"stat\">10%</span>.'),(316,'March 7 (Hunt)',2,'Ágil hoja del agitado oleaje','Después de que el Maestro use el ATQ básico o la habilidad básica para atacar al enemigo, Siete de Marzo lanza inmediatamente un ataque adicional e inflige un Daño <span class=\"elemento\">Imaginario</span> equivalente al <span class=\"stat\">60%</span> de su ATQ al objetivo principal. Además, activa el efecto correspondiente según la Vía del Maestro, y obtiene <span class=\"stat\">1</span> pt. de carga. Si no existe ningún objetivo principal que pueda ser atacado, el ataque adicional se dirige contra un enemigo al azar. Este efecto solo se puede activar una vez en cada turno.'),(317,'March 7 (Hunt)',3,'Agudeza y habilidad a la par','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(318,'March 7 (Hunt)',4,'Quien es divina no desatina','Recupera <span class=\"stat\">5</span> pts. de energía al comienzo del turno.'),(319,'March 7 (Hunt)',5,'Más entreno y menos caramelos','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(320,'March 7 (Hunt)',6,'Una chica sin igual','Tras usar la habilidad definitiva, el Daño CRIT que inflige el siguiente ATQ básico potenciado aumenta en un <span class=\"stat\">50%</span>.'),(321,'Mortenax Blade',1,'',''),(322,'Mortenax Blade',2,'',''),(323,'Mortenax Blade',3,'','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(324,'Mortenax Blade',4,'',''),(325,'Mortenax Blade',5,'','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(326,'Mortenax Blade',6,'',''),(327,'Natasha',1,'Experta en farmacología','Después de recibir un ataque, si su porcentaje de PV es igual o inferior al <span class=\"stat\">30%</span>, Natasha se cura a sí misma una vez por el <span class=\"stat\">15%</span> de sus PV máx. + <span class=\"stat\">400</span>. Este efecto solo se puede activar una vez en cada batalla.'),(328,'Natasha',2,'Estudio clínico','Al usar la habilidad definitiva, proporciona durante <span class=\"stat\">1</span> turno curación continua a los aliados que tengan un porcentaje de PV igual o inferior al <span class=\"stat\">30%</span>. Al comenzar su turno, estos aliados regeneran una cantidad de PV equivalente al <span class=\"stat\">6%</span> de los PV máx. de Natasha + <span class=\"stat\">160</span>.'),(329,'Natasha',3,'El tratamiento correcto','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(330,'Natasha',4,'Cura milagrosa','Al recibir un ataque enemigo, Natasha recupera <span class=\"stat\">5</span> pts. de energía adicionales.'),(331,'Natasha',5,'Tratamiento preventivo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(332,'Natasha',6,'La compasión de la doctora','Al usar el ATQ básico, Natasha inflige un Daño <span class=\"elemento\">Físico</span> extra equivalente al <span class=\"stat\">40%</span> de sus PV máx.'),(333,'Pela',1,'Informe de victoria','Cuando se elimina a un enemigo, Pela recupera <span class=\"stat\">5</span> pts. de energía.'),(334,'Pela',2,'Avance rápido','Cuando la habilidad básica disipa un efecto positivo de un enemigo, la VEL aumenta en un <span class=\"stat\">10%</span> durante <span class=\"stat\">2</span> turnos.'),(335,'Pela',3,'Fuerza supresora','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(336,'Pela',4,'Análisis completo','Al usar la habilidad básica, hay una probabilidad base del <span class=\"stat\">100%</span> de reducir la RES a <span class=\"elemento\">Hielo</span> del enemigo en un <span class=\"stat\">12%</span> durante <span class=\"stat\">2</span> turnos.'),(337,'Pela',5,'Riesgo absoluto','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(338,'Pela',6,'Persecución débil','Al lanzar un ataque, si el objetivo tiene algún estado negativo, Pela le inflige un <span class=\"stat\">40%</span> de su ATQ como Daño de <span class=\"elemento\">Hielo</span> adicional.'),(339,'Qingque',1,'Peón coronado, premio obtenido','El daño que inflige la habilidad definitiva de Qingque aumenta en un <span class=\"stat\">10%</span>.'),(340,'Qingque',2,'Hora de la siesta en las fichas','Cada vez que Qingque roba fichas, recupera inmediatamente <span class=\"stat\">1</span> pt. de energía.'),(341,'Qingque',3,'Confiar en la suerte','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(342,'Qingque',4,'Combo oportuno, la última ficha espera','Tras usar su habilidad básica, Qingque tiene un <span class=\"stat\">24%</span> de probabilidad fija de obtener Autosuficiencia hasta que termine el turno.\nEn el estado de Autosuficiencia, al usar el ATQ básico o el ATQ básico potenciado, se lanza inmediatamente un ataque adicional que inflige al mismo objetivo u objetivos un Daño Cuántico equivalente al <span class=\"stat\">100%</span> del daño de ATQ básico o de ATQ básico potenciado.'),(343,'Qingque',5,'Fichas sacadas, suerte acabada','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(344,'Qingque',6,'Calma y serena, lista para ganar','Tras utilizar el ATQ básico potenciado, recupera <span class=\"stat\">1</span> pt. de habilidad básica.'),(345,'Sushang',6,'Como el agua','El efecto de aumento de VEL del talento se puede acumular hasta <span class=\"stat\">2</span> veces. Además, tras entrar en combate, Sushang obtiene inmediatamente una acumulación del efecto de aumento de VEL del talento.'),(346,'Phainon',1,'Fuego y luz, encarnación del bien y del mal','El porcentaje heredado de la VEL base del turno adicional de Khaslana aumenta al <span class=\"stat\">66%</span> y, por cada enemigo eliminado en una sola batalla, aumenta en un <span class=\"stat\">1.5%</span> de forma adicional, hasta un aumento máximo del <span class=\"stat\">84%</span>.\nAl lanzar la habilidad definitiva, el Daño CRIT aumenta en un <span class=\"stat\">50%</span> durante <span class=\"stat\">3</span> turnos.'),(347,'Phainon',2,'Espuma del cielo y de la tierra','La PEN de la RES a <span class=\"elemento\">Físico</span> de Khaslana aumenta en un <span class=\"stat\">20%</span>. Si al lanzar Pilar: Juicio de la muerte estelar, los pts. de Flagelo consumidos esa vez llegan a <span class=\"stat\">4</span>, obtiene <span class=\"stat\">1</span> turno adicional.'),(348,'Phainon',3,'Quietud recurrente entre las ruinas','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(349,'Phainon',4,'Rostros de Titanes olvidados','Al lanzar Calamidad: Decreto quemaalmas, obtiene <span class=\"stat\">4</span> acumulaciones adicionales de Ardor quemaalmas.'),(350,'Phainon',5,'Manecillas que giran eternamente','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(351,'Phainon',6,'Ascenso de las cenizas ardientes','Los puntos excedentes de Yesca ya no tienen límite máximo. Al comenzar la batalla, obtiene <span class=\"stat\">6</span> pts. de Yesca.\nTras atacar con Pilar: Juicio de la muerte estelar, inflige adicionalmente un <span class=\"stat\">36%</span> del daño total del ataque como Daño verdadero al enemigo que tenga más PV.'),(352,'Ruan Mei',1,'Bordado neuronal','Mientras el campo de la habilidad definitiva está activo, el daño que infligen todos los aliados ignora un <span class=\"stat\">20%</span> de la DEF del objetivo.'),(353,'Ruan Mei',2,'Paseo por los juncos','Cuando Ruan Mei está en la batalla, el ATQ de todos los aliados aumenta en un <span class=\"stat\">40%</span> cuando infligen daño a enemigos con Ruptura de Debilidad.'),(354,'Ruan Mei',3,'Vestida de brocado esmeralda','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(355,'Ruan Mei',4,'Luminosidad reluciente','Cuando un enemigo es afectado por Ruptura de Debilidad, el efecto de Ruptura de Ruan Mei aumenta en un <span class=\"stat\">100%</span> durante <span class=\"stat\">3</span> turnos.'),(356,'Ruan Mei',5,'Horquilla de fabricación exquisita','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(357,'Ruan Mei',6,'Oculta tras el abanico','La duración del campo creado por la habilidad definitiva de Ruan Mei aumenta en <span class=\"stat\">1</span> turno. El multiplicador de Daño de Ruptura del talento aumenta en un <span class=\"stat\">200%</span> adicional.'),(358,'Robin',1,'País de sonrisas','Cuando está en el estado de Concierto, la PEN de la RES a todos los tipos de todos los aliados aumenta en un <span class=\"stat\">24%</span>.'),(359,'Robin',2,'Té de la tarde para dos','Cuando está en el estado de Concierto, la VEL de todos los aliados aumenta en un <span class=\"stat\">16%</span>. El efecto de recuperación de energía del talento aumenta adicionalmente en <span class=\"stat\">1</span> pt.'),(360,'Robin',3,'Afinación inversa','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15).Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). '),(361,'Robin',4,'Llave de lluvia','Al usar su habilidad definitiva, disipa los estados negativos de Control de todos los aliados. Cuando Robin está en el estado de Concierto, la RES a efecto de todos los aliados aumenta en un <span class=\"stat\">50%</span>.'),(362,'Robin',5,'Lamento de la estrella solitaria','Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(363,'Robin',6,'Noche sin luna','Cuando está en el estado de Concierto, el Daño CRIT del Daño <span class=\"elemento\">Físico</span> adicional infligido por la habilidad definitiva aumenta en un <span class=\"stat\">450%</span>. El efecto de Noche sin luna se puede activar hasta <span class=\"stat\">8</span> veces. Cada vez que usa la habilidad definitiva, se reinicia el número de veces que se puede activar.'),(364,'Rappa',1,'Sin pago para el trasbordo, los difuntos regresan','Mientras está en el estado de Forma de sello tras lanzar la habilidad definitiva, el daño que inflige Rappa ignora un <span class=\"stat\">15%</span> de la DEF de los objetivos. Tras salir del estado de Forma de sello, recupera <span class=\"stat\">20</span> pts. de energía.'),(365,'Rappa',2,'Libre es la mente iluminada por haikus','Aumenta en un <span class=\"stat\">50%</span> la Reducción de Firmeza de los <span class=\"stat\">2</span> primeros golpes del ATQ básico potenciado contra el enemigo designado.'),(366,'Rappa',3,'El infierno aguarda por santuarios que haya','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(367,'Rappa',4,'El tiempo devora la vía del ninja','Durante el estado de Forma de sello, la VEL de todos los aliados aumenta en un <span class=\"stat\">12%</span>.'),(368,'Rappa',5,'El cazador decidido no yerra sus flechas','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(369,'Rappa',6,'La justicia nunca se apiada del mal','Al comenzar la batalla, Rappa obtiene <span class=\"stat\">5</span> pts. de carga del talento y el límite de carga aumenta en <span class=\"stat\">5</span> pts. Tras lanzar el tercer golpe de Instrumento ninja: Estrella matademonios, obtiene <span class=\"stat\">5</span> pts. de energía.'),(370,'Sushang',1,'Corte fácil','Recupera <span class=\"stat\">1</span> pt. de habilidad básica tras usar la habilidad básica contra un enemigo afectado por Ruptura de Debilidad.'),(371,'Sushang',2,'Cuerpo entrenado','Tras activar Postura espadachina, el daño que recibe Sushang se reduce en un <span class=\"stat\">20%</span> durante <span class=\"stat\">1</span> turno.'),(372,'Sushang',3,'Antiguo estilo de espada','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(373,'Sushang',4,'Mente aguda','El efecto de Ruptura de Sushang aumenta en un <span class=\"stat\">40%</span>.'),(374,'Sushang',5,'Voluntad de Taixu','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(375,'Sushang',6,'Como el agua','El efecto de aumento de VEL del talento se puede acumular hasta <span class=\"stat\">2</span> veces. Además, tras entrar en combate, Sushang obtiene inmediatamente una acumulación del efecto de aumento de VEL del talento.'),(376,'Sunday',1,'Resurgimiento del milenarismo','Cuando Sunday lanza la habilidad básica, hace que el personaje y la invocación objetivos de la habilidad ignoren respectivamente un <span class=\"stat\">16%</span> y un <span class=\"stat\">40%</span> de la DEF del enemigo al infligir daño durante <span class=\"stat\">2</span> turnos.'),(377,'Sunday',2,'La fe suple los defectos','Recupera <span class=\"stat\">2</span> pts. de habilidad básica después de lanzar la habilidad definitiva por primera vez. El daño que inflige el aliado con Beatitud aumenta en un <span class=\"stat\">30%</span>.'),(378,'Sunday',3,'Cenobio de las espinas','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(379,'Sunday',4,'Preámbulo de la escultura','Recupera <span class=\"stat\">8</span> pts. de energía al comienzo del turno.'),(380,'Sunday',5,'Barquita en el mar de estrellas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(381,'Sunday',6,'Alba del clamor sideral','El efecto de aumento de Prob. CRIT del talento pasa a ser acumulable y se puede acumular hasta <span class=\"stat\">3</span> veces. Además, la duración del talento aumenta en <span class=\"stat\">1</span> turno. Cuando Sunday lanza su habilidad definitiva, también implanta el efecto de aumento de la Prob. CRIT del talento al objetivo. Cuando el efecto de aumento de la Prob. CRIT del talento está activo y la Prob. CRIT del objetivo sobrepasa el <span class=\"stat\">100%</span>, cada <span class=\"stat\">1%</span> de Prob. CRIT excedente aumenta el Daño CRIT en un <span class=\"stat\">2%</span>.'),(382,'Sparkle',1,'Suspensión de la incredulidad','El ATQ de los aliados con Adivinanza aumenta en un <span class=\"stat\">40%</span>. Al comenzar el combate o al lanzar la habilidad básica, la VEL de Sparkle aumenta en un <span class=\"stat\">15%</span> durante <span class=\"stat\">2</span> turnos.'),(383,'Sparkle',2,'Ficción sin fundamento','Por cada acumulación del efecto del talento, la DEF del enemigo se reduce en un <span class=\"stat\">10%</span>.'),(384,'Sparkle',3,'Sueño inalcanzable','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(385,'Sparkle',4,'La vida es un juego','La habilidad definitiva recupera <span class=\"stat\">1</span> pt. de habilidad básica adicional. El talento aumenta el límite de pts. de habilidad básica en <span class=\"stat\">1</span> pt. adicional.'),(386,'Sparkle',5,'Verdad de dos caras','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(387,'Sparkle',6,'Polisemia narrativa','El efecto de aumento de Daño CRIT de la habilidad básica aumenta adicionalmente en una cantidad equivalente al <span class=\"stat\">30%</span> del Daño CRIT de Sparkle. Cuando Sparkle lanza su habilidad básica, el efecto de aumento de Daño CRIT de la habilidad básica se aplica a todos los aliados que tengan Adivinanza. Cuando Sparkle lanza su habilidad definitiva, si un aliado tiene el efecto de aumento de Daño CRIT de la habilidad básica, este efecto se extiende a todos los aliados que tengan Adivinanza.'),(388,'Silver Wolf',1,'Ingeniería social','Tras usar su habilidad definitiva para atacar a los enemigos, Silver Wolf recupera <span class=\"stat\">7</span> pts. de energía por cada estado negativo que tengan los objetivos. Este efecto se puede activar un máximo de <span class=\"stat\">5</span> veces cada vez que ataque con su habilidad definitiva.'),(389,'Silver Wolf',2,'Red zombi','Cuando el objetivo enemigo entra en combate, el daño que recibe aumenta en un <span class=\"stat\">20%</span>. Cuando un enemigo recibe un ataque de un aliado, Silver Wolf tiene una probabilidad base del <span class=\"stat\">100%</span> de implantar un error al azar a ese enemigo.'),(390,'Silver Wolf',3,'Carga útil','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(391,'Silver Wolf',4,'Ataque de rebote','Tras usar su habilidad definitiva para atacar a los enemigos, Silver Wolf inflige un <span class=\"stat\">20%</span> de su ATQ como Daño Cuántico adicional por cada estado negativo que tengan los objetivos. Este efecto se puede activar un máximo de <span class=\"stat\">5</span> veces contra cada objetivo cada vez que ataque con su habilidad definitiva.'),(392,'Silver Wolf',5,'Fuerza bruta','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(393,'Silver Wolf',6,'Red superpuesta','Por cada estado negativo que tenga el objetivo enemigo, el daño que le inflige Silver Wolf aumenta en un <span class=\"stat\">20%</span>, hasta un máximo del <span class=\"stat\">100%</span>.'),(394,'Serval',1,'Cámara de eco','El ATQ básico inflige un Daño de <span class=\"elemento\">Rayo</span> equivalente al <span class=\"stat\">60%</span> del daño de ATQ básico a un enemigo aleatorio adyacente al objetivo.'),(395,'Serval',2,'¡Otra, otra!','Cada vez que el talento inflige daño adicional, Serval recupera <span class=\"stat\">4</span> pts. de energía.'),(396,'Serval',3,'Escucha el latido de los engranajes','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(397,'Serval',4,'¡Hagamos algo de ruido!','Al usar la habilidad definitiva, tiene una probabilidad base del <span class=\"stat\">100%</span> de afectar a los enemigos que no estén ya electrocutados con un estado de Electrocución equivalente al de la habilidad básica.'),(398,'Serval',5,'¡El grito más fuerte de Belobog!','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(399,'Serval',6,'¡Esta canción resuena en el cielo!','El daño que Serval inflige a los enemigos afectados por Electrocución aumenta en un <span class=\"stat\">30%</span>.'),(400,'Seele',1,'Corte total','Cuando inflige daño a un objetivo que tiene un porcentaje de PV igual o inferior al <span class=\"stat\">80%</span>, la Prob. CRIT aumenta en un <span class=\"stat\">15%</span>.'),(401,'Seele',2,'Danza de la mariposa','El efecto de aumento de VEL de la habilidad básica se puede acumular hasta <span class=\"stat\">2</span> veces.'),(402,'Seele',3,'Confusión','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(403,'Seele',4,'Espíritu efímero','Cuando Seele elimina a un enemigo, recupera <span class=\"stat\">15</span> pts. de energía.'),(404,'Seele',5,'Fragmentos punzantes','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(405,'Seele',6,'Caos destructivo','Tras atacar con la habilidad definitiva de Seele, el objetivo entra en el estado de Mariposa desbocada durante <span class=\"stat\">1</span> turno. Cuando un enemigo afectado por Mariposa desbocada es atacado, recibe un Daño Cuántico adicional equivalente al <span class=\"stat\">15%</span> del daño de habilidad definitiva de Seele. Si el enemigo es eliminado por el daño adicional de Mariposa desbocada activado por el ataque de otro aliado, no se activará el talento de Seele.\nCuando Seele sea derrotada, se disipará el estado de Mariposa desbocada infligido a los enemigos.'),(406,'Sampo',1,'Amor en aumento','Al usar la habilidad básica, inflige daño a un enemigo al azar <span class=\"stat\">1</span> vez más.'),(407,'Sampo',2,'Entusiasmo contagioso','Cuando elimina a un enemigo afectado por Intemperie, todos los enemigos tienen una probabilidad base del <span class=\"stat\">100%</span> de recibir <span class=\"stat\">1</span> acumulación del estado de Intemperie equivalente a las del talento.'),(408,'Sampo',3,'¡Mucho dinero!','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(409,'Sampo',4,'Cuánto amor, cuánto odio','Cuando la habilidad básica golpea a un enemigo que tenga <span class=\"stat\">5</span> o más acumulaciones de Intemperie, ese enemigo recibe inmediatamente un <span class=\"stat\">8%</span> del daño de su estado de Intemperie.'),(410,'Sampo',5,'¡Muchísimo dinero!','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(411,'Sampo',6,'Gasto en aumento','El multiplicador de daño del estado de Intemperie aplicado por el talento aumenta en un <span class=\"stat\">15%</span>.'),(412,'Sparxie',1,'#Tendencia: ¿quién es ella?','Al finalizar el Momento Aha, obtiene <span class=\"stat\">5</span> puntos de Chiste. Por cada punto de Chiste que haya actualmente, la PEN de la RES a todos los tipos de todos los aliados aumenta en un <span class=\"stat\">1.5%</span>, hasta un máximo del <span class=\"stat\">15%</span>.'),(413,'Sparxie',2,'#Los ojos del público no mienten','Cuando termina el Momento Aha, Chispa obtiene <span class=\"stat\">1</span> turno adicional y <span class=\"stat\">2</span> Detonaciones. Por cada Detonación consumida, su Daño CRIT aumenta en un <span class=\"stat\">10%</span> durante <span class=\"stat\">2</span> turnos. Se puede acumular hasta <span class=\"stat\">4</span> veces.'),(414,'Sparxie',3,'#Hagan clic: hipervínculo pulsante','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(415,'Sparxie',4,'#¡Miren! Compostura perfecta','Al lanzar la habilidad definitiva, obtiene <span class=\"stat\">5</span> puntos de Chiste extra y su <span class=\"via\">Exultación</span> aumenta en un <span class=\"stat\">36%</span> durante <span class=\"stat\">3</span> turnos.'),(416,'Sparxie',5,'#La chispa que arregla el mundo','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(417,'Sparxie',6,'#¡Tachán! Edición limitada de mí','La PEN de la RES a todos los tipos aumenta en un <span class=\"stat\">20%</span>. La habilidad de <span class=\"via\">Exultación</span> inflige daño una vez más por cada <span class=\"stat\">1</span> punto de Chiste contado, hasta un máximo de <span class=\"stat\">40</span> veces.'),(418,'Silver Wolf (Lvl. 999)',1,'',''),(419,'Silver Wolf (Lvl. 999)',2,'',''),(420,'Silver Wolf (Lvl. 999)',3,'','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(421,'Silver Wolf (Lvl. 999)',4,'',''),(422,'Silver Wolf (Lvl. 999)',5,'','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(423,'Silver Wolf (Lvl. 999)',6,'',''),(424,'Saber',1,'Caída de los muros pálidos','El daño de habilidad definitiva que inflige Saber aumenta en un <span class=\"stat\">60%</span>. Además, después de que Saber lance el ATQ básico o la habilidad básica, obtiene <span class=\"stat\">1</span> pt. de Resonancia del núcleo.'),(425,'Saber',2,'Juramento de la mesa redonda olvidado','Por cada pt. de Resonancia del núcleo obtenido en una batalla, el daño que inflige Saber ignora un <span class=\"stat\">1%</span> de la DEF del objetivo. Este efecto se puede acumular hasta <span class=\"stat\">15</span> veces. Al activar el efecto de aumento del multiplicador de la habilidad básica de Resonancia del núcleo, cada punto de Resonancia del núcleo aumenta el multiplicador de daño de ese uso de la habilidad básica en un <span class=\"stat\">7%</span> adicional.'),(426,'Saber',3,'Búsqueda a lo largo de quince siglos','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(427,'Saber',4,'Saga de dieciséis días invernales','La PEN de la RES a <span class=\"elemento\">Viento</span> de Saber aumenta en un <span class=\"stat\">8%</span>. Tras lanzar la habilidad definitiva, la PEN de la RES a <span class=\"elemento\">Viento</span> de Saber aumenta en un <span class=\"stat\">4%</span>. Este efecto se puede acumular hasta <span class=\"stat\">3</span> veces.'),(428,'Saber',5,'Llegada del amanecer utópico','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(429,'Saber',6,'La larga noche del destino','La PEN de la RES a <span class=\"elemento\">Viento</span> del daño de habilidad definitiva que inflige Saber aumenta en un <span class=\"stat\">20%</span>, y la energía excedente que puede acumular el Rastro \"Bendición del lago\" aumenta a <span class=\"stat\">200</span> pts. Al entrar en combate, después de lanzar la habilidad definitiva por primera vez, Saber recupera <span class=\"stat\">300</span> pts. de energía de forma fija. Este efecto se puede activar <span class=\"stat\">1</span> vez tras cada <span class=\"stat\">3</span> lanzamientos de la habilidad definitiva.'),(430,'Tribbie',1,'Festival de recolecta de azúcar','Después de que un aliado ataque al enemigo mientras el campo está activo, inflige adicionalmente al objetivo que recibe el daño adicional del campo un Daño verdadero equivalente al <span class=\"stat\">24%</span> del daño total del ataque.'),(431,'Tribbie',2,'Guía para visitar sueños','El daño adicional que inflige el campo aumenta al <span class=\"stat\">120%</span> del daño original. Cuando el campo inflige daño adicional, inflige daño adicional <span class=\"stat\">1</span> vez más.'),(432,'Tribbie',3,'Tesoro repleto de auroras','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(433,'Tribbie',4,'Paz de corazones afines','Mientras dura Numinosidad, el daño que infligen todos los aliados ignora un <span class=\"stat\">18%</span> de la DEF del objetivo.'),(434,'Tribbie',5,'Reloj de las maravillas','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(435,'Tribbie',6,'Un mañana de luna y estrellas','Cuando Tribbie usa su habilidad definitiva, lanza el ataque adicional del talento contra todos los enemigos. El daño que inflige el ataque adicional del talento aumenta en un <span class=\"stat\">729%</span>.'),(436,'Trazacaminos (Rememberance)',1,'Narradora/r del presente','La Prob. CRIT del aliado con Apoyo de Mem aumenta en un <span class=\"stat\">10%</span>. Cuando un aliado tiene Apoyo de Mem, el efecto de Apoyo de Mem también se aplica a su mnemoduende o mnemomédium (según corresponda). Este efecto no se puede acumular.'),(437,'Trazacaminos (Rememberance)',2,'Recolectora/r del pasado','Cuando un mnemoduende aliado (que no sea Mem) actúa, la/el Trazacaminos recupera <span class=\"stat\">8</span> pts. de energía. Este efecto se puede activar <span class=\"stat\">1</span> vez como máximo en cada turno. El contador de activaciones se reinicia cuando comienza el turno de la/del Trazacaminos.'),(438,'Trazacaminos (Rememberance)',3,'Rapsoda del futuro','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(439,'Trazacaminos (Rememberance)',4,'Bailarina/rín de las musas','Cuando un aliado cuya energía máxima sea <span class=\"stat\">0</span> lanza una habilidad de forma proactiva, Mem también obtiene un <span class=\"stat\">3%</span> de carga y el multiplicador del Daño verdadero que ese objetivo inflige gracias a Apoyo de Mem aumenta en un <span class=\"stat\">6%</span> adicional.'),(440,'Trazacaminos (Rememberance)',5,'Costurera/o de la poesía','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de talento de mnemoduende <span class=\"stat\">+1</span> (máximo: nivel 10).'),(441,'Trazacaminos (Rememberance)',6,'Portadora/r de la revelación divina','La Prob. CRIT de la habilidad definitiva se fija en el <span class=\"stat\">100%</span>.'),(442,'Trazacaminos (Preservation)',1,'Resonancia con el núcleo terrestre','Cuando la/el Trazacaminos usa su ATQ básico, inflige un Daño de <span class=\"elemento\">Fuego</span> extra equivalente al <span class=\"stat\">25%</span> de su DEF. Cuando usa su ATQ básico potenciado, inflige un Daño de <span class=\"elemento\">Fuego</span> extra equivalente al <span class=\"stat\">50%</span> de su DEF.'),(443,'Trazacaminos (Preservation)',2,'Perseverancia del hierro cósmico','Cuando se activa el talento, el escudo que reciben todos los aliados puede absorber un daño extra equivalente al <span class=\"stat\">2%</span> de la DEF de la/del Trazacaminos + <span class=\"stat\">27</span>.'),(444,'Trazacaminos (Preservation)',3,'Planos para el futuro','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(445,'Trazacaminos (Preservation)',4,'Juramento de la civilización superviviente','Al comenzar la batalla, la/el Trazacaminos obtiene inmediatamente <span class=\"stat\">4</span> acumulaciones de Voluntad magmática.'),(446,'Trazacaminos (Preservation)',5,'Coraje para prender la llama','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(447,'Trazacaminos (Preservation)',6,'Baluarte de la Ciudad Eterna','Tras usar su ATQ básico potenciado o su habilidad definitiva, la DEF de la/del Trazacaminos aumenta en un <span class=\"stat\">10%</span>. Se acumula hasta <span class=\"stat\">3</span> veces.'),(448,'Trazacaminos (Harmony)',1,'El mejor asiento del local','Regenera <span class=\"stat\">1</span> pt. de habilidad básica tras usar la habilidad por primera vez en una batalla.'),(449,'Trazacaminos (Harmony)',2,'Arcoíris fugaprisiones','Al comenzar la batalla, la recuperación de energía de la/del Trazacaminos aumenta en un <span class=\"stat\">25%</span> durante <span class=\"stat\">3</span> turnos.'),(450,'Trazacaminos (Harmony)',3,'Sanatorio del silencio de redonda','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(451,'Trazacaminos (Harmony)',4,'Paloma en la chistera','Mientras la/el Trazacaminos está en el campo de batalla, el efecto de Ruptura de todos los aliados excepto ella/él aumenta en una cantidad equivalente al <span class=\"stat\">15%</span> del efecto de Ruptura de la/del Trazacaminos.'),(452,'Trazacaminos (Harmony)',5,'Poema de viejos ritmos','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(453,'Trazacaminos (Harmony)',6,'Mañana descansaremos bajo los focos','Aumenta el daño extra de la habilidad básica <span class=\"stat\">2</span> veces.'),(454,'Trazacaminos (Destruction)',1,'Estrellas dispersas','Cuando su habilidad definitiva elimina a un enemigo, la/el Trazacaminos recupera <span class=\"stat\">10</span> pts. de energía adicionales. Este efecto solo se puede activar <span class=\"stat\">1</span> vez en cada ataque.'),(455,'Trazacaminos (Destruction)',2,'Anfitriona perfecta/Anfitrión perfecto','Al golpear a un enemigo con Debilidad Física, la/el Trazacaminos regenera una cantidad de PV equivalente al <span class=\"stat\">5%</span> de su ATQ.'),(456,'Trazacaminos (Destruction)',3,'El espíritu que guía','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(457,'Trazacaminos (Destruction)',4,'Contemplación del instante de destrucción','Al golpear a un enemigo con Ruptura de Debilidad, la Prob. CRIT aumenta en un <span class=\"stat\">25%</span>.'),(458,'Trazacaminos (Destruction)',5,'Esperanza de supervivencia','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(459,'Trazacaminos (Destruction)',6,'Voluntad de exploración','El talento de la/del Trazacaminos también se activa cuando elimina a un enemigo.'),(460,'Trazacaminos (Elation)',1,'',''),(461,'Trazacaminos (Elation)',2,'',''),(462,'Trazacaminos (Elation)',3,'','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(463,'Trazacaminos (Elation)',4,'',''),(464,'Trazacaminos (Elation)',5,'','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(465,'Trazacaminos (Elation)',6,'',''),(466,'Topaz & Numby',1,'El mercado del mañana','Cuando un enemigo afectado por Certificado de deuda recibe un ataque adicional, entra en el estado de Endeudamiento. Se puede activar <span class=\"stat\">1</span> vez como máximo por ataque.\nEndeudamiento hace que el Daño CRIT de los ataques adicionales que recibe el objetivo aumente en un <span class=\"stat\">25%</span>. Se puede acumular hasta <span class=\"stat\">2</span> veces. Cuando Certificado de deuda se disipa, Endeudamiento también se elimina.'),(467,'Topaz & Numby',2,'Adquisición de buena fe','Después de que Conti realice una acción y lance un ataque, Topaz recupera <span class=\"stat\">5</span> pts. de energía.'),(468,'Topaz & Numby',3,'Toma lo mucho y deja lo poco','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(469,'Topaz & Numby',4,'Gestión rápida','Cuando comienza el turno de Conti, la acción de Topaz se adelanta un <span class=\"stat\">20%</span>.'),(470,'Topaz & Numby',5,'Demanda creciente','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(471,'Topaz & Numby',6,'Incentivos','Cuando Conti está en el estado de Subida increíble, su cantidad de ataques aumenta en <span class=\"stat\">1</span> y, cuando ataca, su PEN de la RES a <span class=\"elemento\">Fuego</span> aumenta en un <span class=\"stat\">10%</span>.'),(472,'Tingyun',1,'Fortuna de la primavera','Cuando el aliado con la Gracia usa la habilidad definitiva, su VEL aumenta en un <span class=\"stat\">20%</span> durante <span class=\"stat\">1</span> turno.'),(473,'Tingyun',2,'Beneficiario agradecido','Cuando el aliado con la Gracia elimina a un enemigo, recupera <span class=\"stat\">5</span> pts. de energía. Este efecto solo se puede activar <span class=\"stat\">1</span> vez por turno.'),(474,'Tingyun',3,'Herencia del pasado','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(475,'Tingyun',4,'Versatilidad jovial','El multiplicador de daño de la Gracia aumenta en un <span class=\"stat\">20%</span>.'),(476,'Tingyun',5,'Coquetería de paseo','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(477,'Tingyun',6,'La armonía trae la prosperidad','La habilidad definitiva hace que el objetivo aliado recupere <span class=\"stat\">10</span> pts. de energía adicionales.'),(478,'The Herta',1,'Noche de estrellas fugaces','Cuando la habilidad básica potenciada calcula las acumulaciones de Interpretación, se calculan adicionalmente un <span class=\"stat\">50%</span> de las acumulaciones de Interpretación del objetivo que más acumulaciones tenga de entre el objetivo principal y los objetivos adyacentes. Cuando se restablecen las acumulaciones de Interpretación al lanzar la habilidad básica potenciada, estas acumulaciones se restablecen a <span class=\"stat\">15</span> en su lugar.'),(479,'The Herta',2,'El viento por la cerradura','Al entrar en combate y tras lanzar la habilidad definitiva, la Sra. Herta obtiene <span class=\"stat\">1</span> acumulación adicional de Inspiración. Tras lanzar la habilidad básica potenciada, la siguiente acción de la Sra. Herta se adelanta un <span class=\"stat\">35%</span>.'),(480,'The Herta',3,'Puerta al verano','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(481,'The Herta',4,'La decimosexta llave','Aumenta en un <span class=\"stat\">12%</span> la VEL de los personajes del equipo que siguen la Vía de la <span class=\"via\">Erudición</span>.'),(482,'The Herta',5,'Las verdades duelen','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(483,'The Herta',6,'El embrujo de las respuestas','La PEN de la RES a <span class=\"elemento\">Hielo</span> de la Sra. Herta aumenta en un <span class=\"stat\">20%</span>. Si hay <span class=\"stat\">3</span> (o más)/<span class=\"stat\">2</span>/<span class=\"stat\">1</span> enemigos en el campo de batalla, el multiplicador de daño de la habilidad definitiva aumenta en un <span class=\"stat\">140%</span>/<span class=\"stat\">250%</span>/<span class=\"stat\">400%</span>.'),(484,'The Dahlia',1,'Una flor por abrirse, morosa','El multiplicador del Daño de Ultrarruptura que el talento otorga a cada Pareja de baile pasa a tener efecto en todos los personajes aliados, y el multiplicador de cada Pareja de baile aumenta en un <span class=\"stat\">40%</span> adicional. Después de que una Pareja de baile ataque, los objetivos atacados reciben una reducción de Firmeza fija equivalente al <span class=\"stat\">25%</span> de su Firmeza máxima (<span class=\"stat\">10</span> puntos como mínimo y <span class=\"stat\">300</span> como máximo). Este efecto solo puede activarse una vez en cada enemigo. Después de que un enemigo reciba un golpe letal, se restablece su contador de activaciones.'),(485,'The Dahlia',2,'Fresca, etérea y amada','Cuando la Dalia está en la batalla, la RES a todos los tipos de todos los enemigos se reduce en un <span class=\"stat\">20%</span>. Cuando un enemigo entra en combate, es afectado inmediatamente con el estado de Derrota marchita durante <span class=\"stat\">3</span> turnos.'),(486,'The Dahlia',3,'Lástima de pétalos delicados','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(487,'The Dahlia',4,'Lástima de pistilo agusanado','El ataque adicional del talento inflige daño <span class=\"stat\">5</span> veces más. Al lanzarse, aumenta en un <span class=\"stat\">12%</span> el daño que reciben todos los enemigos durante <span class=\"stat\">2</span> turnos.'),(488,'The Dahlia',5,'Marchita, podrida y odiada','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(489,'The Dahlia',6,'Pero siempre mortalmente hermosa','El efecto de Ruptura de las Parejas de baile aumenta en un <span class=\"stat\">150%</span>. Al lanzar el ataque adicional del talento, adelanta un <span class=\"stat\">20%</span> la siguiente acción de todas las Parejas de baile.'),(490,'Welt',1,'Legado de honor','Tras usar su habilidad definitiva, Welt obtiene una potenciación: las <span class=\"stat\">2</span> siguientes veces que ataque usando el ATQ básico o la habilidad básica, inflige daño adicional a los objetivos <span class=\"stat\">1</span> vez. El daño adicional que inflige el ATQ básico es igual al <span class=\"stat\">50%</span> del multiplicador del daño de ATQ básico, y el daño adicional que inflige la habilidad básica es igual al <span class=\"stat\">80%</span> del multiplicador del daño de habilidad básica.'),(491,'Welt',2,'Fusión de estrellas','Cuando su talento se activa, Welt recupera <span class=\"stat\">3</span> pts. de energía.'),(492,'Welt',3,'Oración por la paz','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(493,'Welt',4,'Apelación por la justicia','Al usar la habilidad básica, la probabilidad base de reducir la VEL del objetivo aumenta en un <span class=\"stat\">35%</span>.'),(494,'Welt',5,'El poder de la bondad','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(495,'Welt',6,'Perspectivas luminosas','Al usar la habilidad básica, inflige daño a un enemigo al azar una vez más.'),(496,'Xueyi',1,'Inhibición del dvesha','El daño que inflige el ataque adicional del talento aumenta en un <span class=\"stat\">40%</span>.'),(497,'Xueyi',2,'Fisura del klesha','El ataque adicional del talento ignora los tipos de Debilidad y reduce la Firmeza del enemigo. A su vez, Xueyi regenera una cantidad de PV equivalente al <span class=\"stat\">5%</span> de sus PV máx. Al romper la Debilidad de un enemigo, activa el efecto de Ruptura Cuántica.'),(498,'Xueyi',3,'Cese del dukkha','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(499,'Xueyi',4,'Ruptura del karma','Al usar la habilidad definitiva, su efecto de Ruptura aumenta en un <span class=\"stat\">40%</span> durante <span class=\"stat\">2</span> turnos.'),(500,'Xueyi',5,'Fascinación del deva','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(501,'Xueyi',6,'Dominio del samsara','Las acumulaciones máximas de Karma disminuyen a <span class=\"stat\">6</span>.'),(502,'Yunli',1,'Espada curtida libre de mácula','El daño que infligen Capción: Sajadura y Capción: Exterminio aumenta en un <span class=\"stat\">20%</span>, y las veces adicionales que Capción: Exterminio inflige daño aumentan en <span class=\"stat\">3</span>.'),(503,'Yunli',2,'Primer lustre al romper el alba','Cuando inflige daño con un contraataque, ignora un <span class=\"stat\">20%</span> de la DEF del enemigo.'),(504,'Yunli',3,'Diez palmos de maestría','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(505,'Yunli',4,'Tintineo del maestro herrero','Después de lanzar Capción: Sajadura o Capción: Exterminio, su RES a efecto aumenta en un <span class=\"stat\">50%</span> durante <span class=\"stat\">1</span> turno.'),(506,'Yunli',5,'Vieja amiga para siempre','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(507,'Yunli',6,'Temple de acero, corazón de coplero','Si el enemigo lanza una habilidad por iniciativa propia mientras dura el estado de Bloqueo, Capción: Exterminio se activa independientemente de si ataca a Yunli o no, y el efecto de Bloqueo se disipa. Cuando inflige daño al lanzar Capción: Exterminio o Capción: Sajadura, su Prob. CRIT aumenta en un <span class=\"stat\">15%</span> y su PEN de la RES a <span class=\"elemento\">Físico</span> aumenta en un <span class=\"stat\">20%</span>.'),(508,'Yukong',1,'Exploradora alada','Al entrar en combate, la VEL de todos los aliados aumenta en un <span class=\"stat\">10%</span> durante <span class=\"stat\">2</span> turnos.'),(509,'Yukong',2,'Orden del firmamento','Cuando la energía de un aliado es igual a su energía máxima, Yukong recupera <span class=\"stat\">5</span> pts. de energía adicionales. Este efecto solo se puede activar una vez por cada aliado. Cuando Yukong utiliza la habilidad definitiva, se reinicia el contador de activaciones.'),(510,'Yukong',3,'Descarga torrencial','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(511,'Yukong',4,'Ecos del céfiro','Cuando tiene Sonido de cuerda, el daño que inflige Yukong aumenta en un <span class=\"stat\">30%</span>.'),(512,'Yukong',5,'Rápida y precisa','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(513,'Yukong',6,'Arco fuerte','Cuando Yukong usa su habilidad definitiva, obtiene <span class=\"stat\">1</span> acumulación de Sonido de cuerda.'),(514,'Yanqing',1,'Hoja pulcra','Si el enemigo al que ataca Yanqing está afectado por Congelación, le inflige inmediatamente un <span class=\"stat\">60%</span> del ATQ de Yanqing como Daño de <span class=\"elemento\">Hielo</span> adicional.'),(515,'Yanqing',2,'Mente despejada','Cuando Estocada empática está activa, la recuperación de energía aumenta en un <span class=\"stat\">10%</span> adicional.'),(516,'Yanqing',3,'Espadachín nato','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). '),(517,'Yanqing',4,'Relente perforante','Cuando el porcentaje de PV es igual o superior al <span class=\"stat\">80%</span>, su PEN de la RES a <span class=\"elemento\">Hielo</span> aumenta en un <span class=\"stat\">12%</span>.'),(518,'Yanqing',5,'Nacido para luchar','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). '),(519,'Yanqing',6,'Juego de pies','Si tiene efectos positivos de Estocada empática o la habilidad definitiva al eliminar a un enemigo, la duración de dichos efectos se alarga en <span class=\"stat\">1</span> turno.'),(520,'Yao Guang',1,'El jade tintinea risueño','La cantidad de Chiste que se cuenta en el turno adicional de Aha activado por la habilidad definitiva aumenta a <span class=\"stat\">40</span>. El Daño de <span class=\"via\">Exultación</span> que infligen todos los aliados ignora el <span class=\"stat\">20%</span> de la DEF del enemigo.'),(521,'Yao Guang',2,'Las flechas vuelan sin ojos','Mientras el campo está activo, la VEL de todos los aliados aumenta en un <span class=\"stat\">12%</span> y la <span class=\"via\">Exultación</span> aumenta en un <span class=\"stat\">16%</span> adicional.'),(522,'Yao Guang',3,'El cosmos se refleja en los signos','Niv. de habilidad básica <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de ATQ básico <span class=\"stat\">+1</span> (máximo: nivel 10). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(523,'Yao Guang',4,'Motearé el lienzo del destino','Durante el turno adicional de Aha activado por la habilidad definitiva de Yao Guang, el daño que infligen las habilidades de <span class=\"via\">Exultación</span> de todos los personajes aliados es el <span class=\"stat\">150%</span> del daño original.'),(524,'Yao Guang',5,'Pura como cristal engarzado','Niv. de habilidad definitiva <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de talento <span class=\"stat\">+2</span> (máximo: nivel 15). Niv. de habilidad de Exultación <span class=\"stat\">+1</span> (máximo: nivel 15).'),(525,'Yao Guang',6,'Halaré los astros colgantes','El Daño de <span class=\"via\">Exultación</span> de todos los aliados aumenta su gracia en un <span class=\"stat\">25%</span>. El multiplicador de daño de la habilidad de <span class=\"via\">Exultación</span> de Yao Guang aumenta en un <span class=\"stat\">100%</span> del multiplicador original.');
