--
-- Table structure for table `skills`
--

DROP TABLE IF EXISTS `skills`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `skills` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `character_id` varchar(100) DEFAULT NULL,
  `type` varchar(50) DEFAULT NULL,
  `enchanced` tinyint(1) DEFAULT NULL,
  `memosprite` tinyint(1) DEFAULT NULL,
  `energy` int(11) DEFAULT NULL,
  `target` varchar(100) DEFAULT NULL,
  `name` varchar(150) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `energy_gain` int(11) DEFAULT NULL,
  `break` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_skills_character_id` (`character_id`),
  CONSTRAINT `fk_skills_character_id` FOREIGN KEY (`character_id`) REFERENCES `characters` (`name`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=185 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

