LOCK TABLES `skills` WRITE;
/*!40000 ALTER TABLE `skills` DISABLE KEYS */;
INSERT INTO `skills` VALUES (58,'Acheron','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Cruce marchito trilateral','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> a un enemigo.',0,'ATQ individual : 30'),(59,'Acheron','Habilidad Básica',NULL,NULL,NULL,'Ráfaga','Diluvio de cortes','Obtiene <span class=\"stat\">1</span> pt. de Sueños rotos. Aplica <span class=\"stat\">1</span> acumulación de Rojo sacrificial a un enemigo, le inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> e inflige un <span class=\"stat\">{stat_2}%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> a los enemigos adyacentes.',0,'ATQ individual : 60 / Ráfaga : 30'),(60,'Acheron','Definitiva',NULL,NULL,9,'ATQ AdE','Sueño destrozado, lágrimas escarlata','Lanza Pluviespada <span class=\"stat\">3</span> veces y Resurgimiento estigio <span class=\"stat\">1</span> vez e inflige hasta un <span class=\"stat\">{stat_1}%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> a un enemigo. También inflige hasta un <span class=\"stat\">{stat_2}%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> a los demás enemigos.<br>Pluviespada: inflige un <span class=\"stat\">{stat_3}%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> a un enemigo y elimina hasta <span class=\"stat\">3</span> acumulaciones de Rojo sacrificial del objetivo. Cuando se elimina Rojo sacrificial, inflige a todos los enemigos un <span class=\"stat\">{stat_4}%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> y, por cada acumulación de Rojo sacrificial eliminada, el multiplicador de daño de este ataque aumenta de forma adicional hasta un máximo del <span class=\"stat\">{stat_5}%</span>.<br>Resurgimiento estigio: inflige un <span class=\"stat\">{stat_6}%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> a todos los enemigos y elimina todas las acumulaciones de Rojo sacrificial.<br>Mientras se usa la habilidad definitiva, no se puede aplicar Rojo sacrificial a los enemigos.',0,'0'),(61,'Acheron','Talento',NULL,NULL,NULL,'Potenciación','Hojas otoñales, vacío colosal','La habilidad definitiva se puede activar cuando Sueños rotos alcanza <span class=\"stat\">9</span> pts. Mientras dura la habilidad definitiva, se ignora el tipo de Debilidad y se consume la Firmeza de los enemigos, y además la RES a todos los tipos de todos los enemigos se reduce en un <span class=\"stat\">{stat_1}%</span> hasta que finalice la habilidad definitiva.<br>Si cualquier unidad lanza una habilidad y afecta con un estado negativo a un enemigo, Acheron obtiene <span class=\"stat\">1</span> pt. de Sueños rotos y aplica <span class=\"stat\">1</span> acumulación de Rojo sacrificial a un objetivo. Si afecta con estados negativos a más de un enemigo, aplica <span class=\"stat\">1</span> acumulación de Rojo sacrificial al enemigo que tenga más acumulaciones. Este efecto se puede activar <span class=\"stat\">1</span> vez por acción.<br>Cuando Acheron esté en la batalla y un enemigo abandone la batalla o sea derrotado por cualquier unidad, las acumulaciones de Rojo sacrificial se traspasarán al objetivo que tenga más acumulaciones de Rojo sacrificial.',0,'0'),(62,'Acheron','Técnica',NULL,NULL,NULL,'No especificado','Influjo tetravalente','Ataca al enemigo inmediatamente. Al comienzo de cada oleada, obtiene Influjo tetravalente, inflige un <span class=\"stat\">200%</span> del ATQ de Acheron como Daño de <span class=\"element\">Rayo</span> a todos los enemigos y reduce su Firmeza ignorando sus tipos de Debilidad. Al infligir Ruptura de Debilidad, activa el efecto de Ruptura de <span class=\"element\">Rayo</span>.<br>Influjo tetravalente: tras lanzar la habilidad definitiva, Acheron obtiene <span class=\"stat\">1</span> pt. de Sueños rotos y aplica <span class=\"stat\">1</span> acumulación de Rojo sacrificial a un enemigo al azar.<br>Si ataca a un enemigo normal, lo derrota directamente y no entra en combate. Si el ataque no acierta a un enemigo, no se consume el punto de técnica.',0,'ATQ individual : 60'),(63,'Aglaea','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Miel con espinas','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Aglaea como Daño de <span class=\"element\">Rayo</span> a un enemigo.',20,'ATQ individual : 30'),(64,'Aglaea','Habilidad Básica',NULL,NULL,NULL,'Invocación','Álzate, renombre sublime','Regenera un <span class=\"stat\">{stat_1}%</span> de los PV máx. del Sastre. Si el Sastre no está en el campo de batalla, invoca al mnemoduende Sastre y vuelve a actuar inmediatamente.<br>Regenera los PV del Sastre. Cuando el Sastre no está en la batalla, invoca al mnemoduende Sastre y vuelve a actuar inmediatamente.',20,'0'),(65,'Aglaea','Definitiva',NULL,NULL,350,'Potenciación','Bailemos, sastre del destino','Invoca al mnemoduende Sastre. Si el Sastre ya está en el campo de batalla, sus PV se regeneran al máximo. Aglaea entra en el estado de Disposición suprema y vuelve a actuar inmediatamente.<br>En el estado de Disposición suprema, Aglaea obtiene las acumulaciones de aumento de VEL del talento de mnemoduende del Sastre. Cada acumulación aumenta su VEL en un <span class=\"stat\">{stat_1}%</span>. El ataque básico se convierte en Mil besos afilados y no puede lanzar su habilidad básica. El Sastre es inmune a los estados negativos de Control.<br>En el orden de acción aparece una cuenta regresiva con una VEL fija de <span class=\"stat\">100</span>. Mientras está la cuenta regresiva, lanzar de nuevo la habilidad definitiva restablece dicha cuenta, y cuando comienza su turno, el Sastre se autodestruye. Cuando el Sastre desaparece, se disipa el estado de Disposición suprema de Aglaea.',5,'0'),(66,'Aglaea','Técnica',NULL,NULL,NULL,'No especificado','Perforación meteórica','Invoca al mnemoduende Sastre y ambos atacan a la vez hacia adelante. Tras entrar en combate, recupera <span class=\"stat\">30</span> pts. de energía, inflige un <span class=\"stat\">100%</span> del ATQ de Aglaea como Daño de <span class=\"element\">Rayo</span> a todos los enemigos y afecta con Hilván a un enemigo al azar.',0,'ATQ individual : 60'),(67,'Aglaea','Ataque Básico',NULL,NULL,NULL,'Ráfaga','Mil besos afilados','Aglaea y el Sastre lanzan un ataque combinado contra el objetivo e infligen respectivamente un <span class=\"stat\">{stat_1}%</span> del ATQ de Aglaea y un <span class=\"stat\">{stat_2}%</span> del ATQ del Sastre como Daño de <span class=\"element\">Rayo</span>. Además, infligen un <span class=\"stat\">{stat_3}%</span> del ATQ de Aglaea y un <span class=\"stat\">{stat_4}%</span> del ATQ del Sastre como Daño de <span class=\"element\">Rayo</span> a los objetivos adyacentes.<br>Mil besos afilados no puede recuperar pts. de habilidad básica.',20,'ATQ individual : 60 / Ráfaga : 30'),(68,'Aglaea','Talento',NULL,NULL,NULL,'Potenciación','Dedos de rosa','Inicialmente, el mnemoduende Sastre tiene una VEL equivalente al <span class=\"stat\">35%</span> de la VEL de Aglaea y unos PV máx. equivalentes al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Aglaea + <span class=\"stat\">{stat_2}</span>. Cuando Aglaea ataca mientras el Sastre está en la batalla, afecta con Hilván al objetivo. Tras atacar a un objetivo en el estado de Hilván, inflige adicionalmente un <span class=\"stat\">{stat_3}%</span> del ATQ de Aglaea como Daño de <span class=\"element\">Rayo</span> adicional. Hilván solo afecta al último enemigo al que se le haya aplicado.',10,'0'),(69,'Aglaea','Habilidad del Mnemoduende',NULL,NULL,NULL,'Ráfaga','Trampa punzante','Inflige un <span class=\"stat\">{stat_1}%</span> de su ATQ como Daño de <span class=\"element\">Rayo</span> a un enemigo y un <span class=\"stat\">{stat_2}%</span> de su ATQ como Daño de <span class=\"element\">Rayo</span> a los objetivos adyacentes.',10,'ATQ individual : 30 / Ráfaga : 15'),(70,'Aglaea','Talento del Mnemoduende',NULL,NULL,NULL,'Potenciación','Cuerpo forjado de lágrimas','Tras atacar a un enemigo en el estado de Hilván, su VEL aumenta en <span class=\"stat\">{stat_1}</span> pts. Este efecto puede acumularse hasta <span class=\"stat\">6</span> veces. Cuando el Sastre actúa, lanza automáticamente Trampa punzante, priorizando al enemigo en el estado de Hilván.',0,'0'),(71,'Aglaea','Talento del Mnemoduende',NULL,NULL,NULL,'Potenciación','Estío fugaz','Cuando el Sastre es invocado, su acción se adelanta un <span class=\"stat\">100%</span>.<br>Cuando es invocado, su acción se adelanta.',0,'0'),(72,'Aglaea','Talento del Mnemoduende',NULL,NULL,NULL,'Potenciación','Profusión de hierbas secas','Cuando el Sastre desaparece, Aglaea recupera <span class=\"stat\">20</span> pts. de energía.<br>Cuando desaparece, Aglaea recupera energía.',0,'0'),(73,'Archer','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Kanshou y Bakuya','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Archer como Daño Cuántico a un enemigo.',20,'ATQ individual : 30'),(74,'Archer','Habilidad Básica',NULL,NULL,NULL,'ATQ individual','Caladbolg II: Espada espiral falsa','Entra en el estado Conexión de circuitos. Archer inflige un <span class=\"stat\">{stat_1}%</span> de su ATQ como Daño Cuántico a un enemigo. Tras lanzar la habilidad básica durante el estado Conexión de circuitos, el turno no termina y el daño que inflige la habilidad básica de Archer aumenta en un <span class=\"stat\">{stat_2}%</span>. Este efecto se puede acumular hasta <span class=\"stat\">2</span> veces y dura hasta que salga del estado Conexión de circuitos. Cuando la habilidad básica se haya lanzado <span class=\"stat\">5</span> veces de forma activa o no haya suficientes pts. de habilidad básica para volver a lanzarla, sale del estado Conexión de circuitos. Cuando todos los enemigos de una oleada hayan sido eliminados, sale del estado Conexión de circuitos.',30,'ATQ individual : 60'),(75,'Archer','Definitiva',NULL,NULL,220,'ATQ individual','Unlimited Blade Works','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Archer como Daño Cuántico a un enemigo y obtiene <span class=\"stat\">2</span> pts. de carga (puede tener hasta <span class=\"stat\">4</span> pts. de carga).',5,'ATQ individual : 90'),(76,'Archer','Talento',NULL,NULL,NULL,'ATQ individual','Ojo de la mente (verdadero)','Después de que un compañero de equipo de Archer ataque a un enemigo, Archer consume <span class=\"stat\">1</span> pt. de carga y lanza al objetivo principal un ataque adicional que inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Archer como Daño Cuántico. Además, recupera <span class=\"stat\">1</span> pt. de habilidad básica. Si el objetivo es eliminado antes de lanzar este ataque adicional, entonces lo lanza contra un enemigo al azar.',5,'ATQ individual : 30'),(77,'Archer','Técnica',NULL,NULL,NULL,'No especificado','Clarividencia','Ataca inmediatamente al enemigo y entra en combate. Inflige un <span class=\"stat\">200%</span> del ATQ de Archer como Daño Cuántico a todos los enemigos y obtiene <span class=\"stat\">1</span> pt. de carga.',0,'ATQ individual : 60'),(78,'Archer','Habilidad Básica',NULL,NULL,NULL,'No especificado','Finalización','Sale del estado Conexión de circuitos y termina el turno.',0,'0'),(79,'Anaxa','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Verdad destilada del dolor','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Anaxa como Daño de <span class=\"element\">Viento</span> a un enemigo.',20,'ATQ individual : 30'),(80,'Anaxa','Habilidad Básica',NULL,NULL,NULL,'Rebote','Fractales que expulsan lo falso','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Anaxa como Daño de <span class=\"element\">Viento</span> a un enemigo y después inflige daño <span class=\"stat\">4</span> veces más. Cada vez, inflige un <span class=\"stat\">{stat_2}%</span> del ATQ de Anaxa como Daño de <span class=\"element\">Viento</span> a un enemigo al azar y prioriza rebotar en los enemigos que no hayan sido golpeados por la habilidad básica en ese ataque.<br>Al lanzar la habilidad básica, el daño que inflige esa vez aumenta en un <span class=\"stat\">20%</span> por cada enemigo que pueda ser atacado en el campo de batalla.',6,'ATQ individual : 30'),(81,'Anaxa','Definitiva',NULL,NULL,140,'ATQ AdE','Tierra de verdor esculpida','Afecta con Sublimación a todos los enemigos y acto seguido les inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_1}%</span> del ATQ de Anaxa.<br>En el estado de Sublimación, los objetivos adquieren simultáneamente Debilidad Física, de Fuego, de Hielo, de Rayo, de <span class=\"element\">Viento</span>, Cuántica e Imaginaria hasta que comience su turno. Los objetivos sin RES a Control no pueden actuar en el estado de Sublimación.<br>Aplica Sublimación a todos los enemigos y les inflige Daño de <span class=\"element\">Viento</span>. A los objetivos en el estado de Sublimación se les implantan simultáneamente <span class=\"stat\">7</span> tipos de Debilidad y no pueden actuar si no tienen RES a Control.',5,'ATQ AdE : 60'),(82,'Anaxa','Talento',NULL,NULL,NULL,'Alteracíon','Sabiduría tres veces grande','Cada vez que Anaxa golpea una vez a un enemigo, le implanta un tipo de Debilidad al azar durante <span class=\"stat\">3</span> turnos, priorizando los tipos de Debilidad que no tenga el objetivo actualmente.<br>Cuando Anaxa está en el campo de batalla, afecta con Desvelación cualitativa a los enemigos que tengan al menos <span class=\"stat\">5</span> tipos de Debilidad distintos. Anaxa inflige un <span class=\"stat\">{stat_1}%</span> más de daño a los objetivos con Desvelación cualitativa y, tras lanzarles su ATQ básico o habilidad básica, les lanza <span class=\"stat\">1</span> vez más su habilidad básica. Esta habilidad básica adicional no consume pts. de habilidad básica y no puede volver a activar este efecto. Si el objetivo es eliminado antes de que se pueda lanzar la habilidad básica adicional, se lanza contra un enemigo al azar.',0,'0'),(83,'Anaxa','Técnica',NULL,NULL,NULL,'Alteracíon','Pupila prismática','Tras usar la técnica, los enemigos de un área determinada son afectados con Aterrorizado. Los enemigos aterrorizados huyen de Anaxa durante <span class=\"stat\">10</span> segundos. Cuando los aliados atacan activamente a enemigos aterrorizados, siempre se considera que entran en combate atacando la Debilidad del enemigo. Tras entrar en combate, Anaxa implanta a cada enemigo una Debilidad del mismo tipo que el atacante durante <span class=\"stat\">3</span> turnos.<br>Afecta a los enemigos cercanos con Aterrorizado. Al atacar a un enemigo aterrorizado, se considera que se entra en combate atacando su Debilidad y se implanta a todos los enemigos una Debilidad del mismo tipo que el atacante.',0,'0'),(84,'Argenti','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Fragancia fugaz','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Argenti como Daño <span class=\"element\">Físico</span> a un enemigo.',20,'ATQ individual : 30'),(85,'Argenti','Habilidad Básica',NULL,NULL,NULL,'ATQ AdE','Florecimiento de la justicia','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Argenti como Daño <span class=\"element\">Físico</span> a todos los enemigos.',30,'ATQ AdE : 30'),(86,'Argenti','Definitiva',NULL,NULL,180,'ATQ AdE','Este jardín otorga la belleza suprema','Consume <span class=\"stat\">90</span> pts. de energía e inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Argenti como Daño <span class=\"element\">Físico</span> a todos los enemigos.',5,'ATQ AdE : 60'),(87,'Argenti','Talento',NULL,NULL,NULL,'Potenciación','Objeto sublime','Por cada enemigo que golpee con su ATQ básico, habilidad básica o habilidad definitiva, Argenti recupera <span class=\"stat\">3</span> pts. de energía y obtiene <span class=\"stat\">1</span> acumulación de Elevación, que aumenta su Prob. CRIT en un <span class=\"stat\">{stat_1}%</span>. Este efecto se puede acumular hasta <span class=\"stat\">10</span> veces.<br>Al usar el ATQ básico, la habilidad básica o la habilidad definitiva, por cada enemigo golpeado Argenti recupera energía y aumenta su Prob. CRIT.',0,'0'),(88,'Argenti','Técnica',NULL,NULL,NULL,'Alteracíon','Manifiesto de la virtud pura','Tras usar la técnica, los enemigos de una zona determinada quedan afectados por Mareo durante <span class=\"stat\">10</span> s, lo que les impide atacar activamente a los aliados.<br>Al entrar en combate tras atacar a un enemigo mareado, inflige a todos los enemigos un Daño <span class=\"element\">Físico</span> equivalente al <span class=\"stat\">80%</span> del ATQ de Argenti y recupera <span class=\"stat\">15</span> pts. de energía.',0,'0'),(89,'Argenti','Definitiva',NULL,NULL,180,'ATQ AdE','Mérito otorgado en \"mi\" jardín','Consume <span class=\"stat\">180</span> pts. de energía e inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Argenti como Daño <span class=\"element\">Físico</span> a todos los enemigos. Además, inflige daño <span class=\"stat\">6</span> veces más, y cada vez inflige un Daño <span class=\"element\">Físico</span> equivalente al <span class=\"stat\">{stat_2}%</span> del ATQ de Argenti a un enemigo al azar.',5,'ATQ individual : 15 / ATQ AdE : 60'),(90,'Arlan','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Velocidad del rayo','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Arlan como Daño de <span class=\"element\">Rayo</span> a un enemigo.',20,'ATQ individual : 30'),(91,'Arlan','Habilidad Básica',NULL,NULL,NULL,'ATQ individual','Rompeataduras','Arlan consume una cantidad de PV equivalente al <span class=\"stat\">15%</span> de sus PV máx. e inflige un <span class=\"stat\">{stat_1}%</span> de su ATQ como Daño de <span class=\"element\">Rayo</span> a un enemigo. Si no hay suficientes PV, al usar la habilidad básica los PV actuales de Arlan se reducen a <span class=\"stat\">1</span>.<br>Consume una parte de sus PV para infligir Daño de <span class=\"element\">Rayo</span> a un enemigo.',30,'ATQ individual : 60'),(92,'Arlan','Definitiva',NULL,NULL,110,'Ráfaga','Castigo furibundo','Arlan inflige un <span class=\"stat\">{stat_1}%</span> de su ATQ como Daño de <span class=\"element\">Rayo</span> a un enemigo y un <span class=\"stat\">{stat_2}%</span> de su ATQ como Daño de <span class=\"element\">Rayo</span> a los enemigos adyacentes.',5,'ATQ individual : 60 / Ráfaga : 60'),(93,'Arlan','Talento',NULL,NULL,NULL,'Potenciación','Ira y dolor','Arlan obtiene una bonificación de daño según el porcentaje de PV que haya perdido hasta el momento. Como máximo puede infligir un <span class=\"stat\">{stat_1}%</span> más de daño.<br>Aumenta el daño según el porcentaje de PV que haya perdido hasta el momento.',0,'0'),(94,'Arlan','Técnica',NULL,NULL,NULL,'','Cosecha rápida','Ataca inmediatamente al enemigo y entra en combate. Inflige un <span class=\"stat\">80%</span> del ATQ de Arlan como Daño de <span class=\"element\">Rayo</span> a todos los enemigos.',0,'ATQ individual : 60'),(95,'Ashveil','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Garra para enseñar modales','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Ashveil como Daño de <span class=\"element\">Rayo</span> a un enemigo.',20,'ATQ individual : 30'),(96,'Ashveil','Habilidad Básica',NULL,NULL,NULL,'ATQ individual','Latigazo para subyugar el mal','Marca a un enemigo como Cebo y le inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Ashveil como Daño de <span class=\"element\">Rayo</span>. Si el objetivo ya está marcado como Cebo, le inflige adicionalmente un <span class=\"stat\">{stat_2}%</span> del ATQ de Ashveil como Daño de <span class=\"element\">Rayo</span> y recupera <span class=\"stat\">1</span> pt. de habilidad básica. Cuando hay un Cebo en el campo de batalla, la DEF de todos los enemigos se reduce en un <span class=\"stat\">{stat_3}%</span>.<br>Si no hay ningún Cebo en el campo de batalla, Ashveil marca inmediatamente como Cebo al enemigo con menos PV actuales en el campo de batalla. El estado de Cebo solo tiene efecto sobre el último objetivo al que se le aplicó.',30,'ATQ individual : 60'),(97,'Ashveil','Definitiva',NULL,NULL,150,'ATQ individual','Banquete para un hambre insaciable','Marca a un enemigo como Cebo y le inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Ashveil como Daño de <span class=\"element\">Rayo</span>. A continuación, lanza inmediatamente una vez una versión potenciada del ataque adicional del talento contra el Cebo y Ashveil obtiene <span class=\"stat\">3</span> pts. de carga.<br>Este ataque adicional potenciado del talento no consume carga. Cada vez que tenga <span class=\"stat\">4</span> o más acumulaciones de Gula, consume <span class=\"stat\">4</span> acumulaciones de Gula para infligir adicionalmente una vez un <span class=\"stat\">{stat_2}%</span> del ATQ de Ashveil como Daño de <span class=\"element\">Rayo</span>. Si inflige un golpe letal al objetivo durante este ataque adicional, seguirá infligiendo daño a un nuevo Cebo hasta que tenga menos de <span class=\"stat\">4</span> acumulaciones de Gula. Si todos los enemigos actualmente en el campo de batalla reciben un golpe letal, el ataque adicional potenciado del talento finaliza inmediatamente.',5,'ATQ individual : 90'),(98,'Ashveil','Talento',NULL,NULL,NULL,'ATQ individual','Colmillo para cobrar venganza','Ashveil inicialmente tiene <span class=\"stat\">2</span> pts. de carga y puede tener hasta <span class=\"stat\">3</span> pts. como máximo. Después de que el Cebo sea atacado por otro aliado, Ashveil recupera <span class=\"stat\">8</span> pts. fijos de energía, consume <span class=\"stat\">1</span> pt. de carga para lanzar un ataque adicional contra el Cebo que le inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Ashveil como Daño de <span class=\"element\">Rayo</span>, y a continuación obtiene <span class=\"stat\">2</span> acumulaciones de Gula, que se puede acumular hasta <span class=\"stat\">12</span> veces.',5,'ATQ individual : 15'),(99,'Ashveil','Técnica',NULL,NULL,NULL,'Alteracíon','Mano para devorarlo todo','Tras usar la técnica, los enemigos de una zona determinada quedan afectados por Mareo durante <span class=\"stat\">10</span> s, lo que les impide atacar activamente a los aliados.<br>Al entrar en combate tras atacar a un enemigo mareado, inflige a todos los enemigos un Daño de <span class=\"element\">Rayo</span> equivalente al <span class=\"stat\">100%</span> del ATQ de Ashveil y Ashveil obtiene <span class=\"stat\">1</span> pt. de carga.',0,''),(100,'Asta','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Haz espectral','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Asta como Daño de <span class=\"element\">Fuego</span> a un enemigo.',20,'ATQ individual : 30'),(101,'Asta','Habilidad Básica',NULL,NULL,NULL,'Rebote','Tormenta de meteoritos','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Asta como Daño de <span class=\"element\">Fuego</span> a un enemigo y después inflige daño <span class=\"stat\">4</span> veces más. Cada golpe inflige un <span class=\"stat\">62.5%</span> del ATQ de Asta como Daño de <span class=\"element\">Fuego</span> a un enemigo al azar.',6,'ATQ individual : 30'),(102,'Asta','Definitiva',NULL,NULL,120,'Apoyo','Bendición astral','La VEL de todos los aliados aumenta en <span class=\"stat\">{stat_1}</span> pts. durante <span class=\"stat\">2</span> turnos.<br>Aumenta la VEL de todos los aliados.',5,''),(103,'Asta','Talento',NULL,NULL,NULL,'Apoyo','Astrometría','Obtiene una acumulación de Recarga por cada objetivo distinto golpeado. Si el objetivo tiene Debilidad de <span class=\"element\">Fuego</span>, obtiene una acumulación adicional.<br>Por cada acumulación de Recarga que tenga Asta, el ATQ de todos los aliados aumenta en un <span class=\"stat\">{stat_1}%</span>. Este efecto se puede acumular hasta <span class=\"stat\">5</span> veces.<br>A partir de su segundo turno, Asta pierde <span class=\"stat\">3</span> acumulaciones de Recarga al principio de cada turno.',0,''),(104,'Asta','Técnica',NULL,NULL,NULL,'','Destello milagroso','Ataca inmediatamente al enemigo y entra en combate. Inflige un <span class=\"stat\">50%</span> del ATQ de Asta como Daño de <span class=\"element\">Fuego</span> a todos los enemigos.',0,'ATQ individual : 60'),(105,'Aventurine','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Apuesta directa','Inflige un <span class=\"stat\">{stat_1}%</span> de la DEF de Aventurino como Daño <span class=\"element\">Imaginario</span> a un enemigo.',20,'ATQ individual : 30'),(106,'Aventurine','Habilidad Básica',NULL,NULL,NULL,'Defensa','Piedra angular de la prosperidad','Otorga a todos los aliados un escudo Apuesta reforzada que absorbe un daño equivalente al <span class=\"stat\">{stat_1}%</span> de la DEF de Aventurino + <span class=\"stat\">{stat_2}</span> durante <span class=\"stat\">3</span> turnos. Al obtener Apuesta reforzada varias veces, el efecto de escudo se puede acumular hasta un máximo del <span class=\"stat\">200%</span> del efecto de escudo que proporciona la habilidad básica actual.',30,''),(107,'Aventurine','Definitiva',NULL,NULL,110,'ATQ individual','Prodigio de la ruleta','Obtiene de <span class=\"stat\">1</span> a <span class=\"stat\">7</span> pts. de Apuesta ciega al azar y después aplica Sobresalto a un enemigo durante <span class=\"stat\">3</span> turnos. Además, inflige al enemigo un <span class=\"stat\">{stat_1}%</span> de la DEF de Aventurino como Daño <span class=\"element\">Imaginario</span>. Cuando un objetivo aliado golpea a un enemigo con Sobresalto, el Daño CRIT infligido aumenta en un <span class=\"stat\">{stat_2}%</span>.<br>Obtiene Apuesta ciega al azar y afecta con Sobresalto a un enemigo. Además, inflige Daño <span class=\"element\">Imaginario</span> al objetivo. Cuando un aliado ataca a un enemigo con Sobresalto, el Daño CRIT que inflige aumenta.',5,'ATQ individual : 90'),(108,'Aventurine','Talento',NULL,NULL,NULL,'Rebote','Bala cargada a la derecha','La RES a efecto de un aliado con Apuesta reforzada aumenta en un <span class=\"stat\">{stat_1}%</span>, y cuando ese aliado recibe un ataque, Aventurino obtiene <span class=\"stat\">1</span> pt. de Apuesta ciega. Aventurino es inmune a los estados negativos de Control cuando tiene Apuesta reforzada. Este efecto se puede activar de nuevo después de <span class=\"stat\">2</span> turnos, y al recibir un ataque obtiene adicionalmente <span class=\"stat\">1</span> pt. de Apuesta ciega. Tras alcanzar <span class=\"stat\">7</span> pts. de Apuesta ciega, Aventurino los consume y lanza un ataque adicional de <span class=\"stat\">7</span> golpes. Cada golpe inflige a un enemigo aleatorio un <span class=\"stat\">{stat_2}%</span> de la DEF de Aventurino como Daño <span class=\"element\">Imaginario</span>. Apuesta ciega puede acumular <span class=\"stat\">10</span> pts. como máximo.',1,'ATQ individual : 10'),(109,'Aventurine','Técnica',NULL,NULL,NULL,'Defensa','Rojo o negro','Tras usar la técnica, se obtiene <span class=\"stat\">1</span> de los siguientes efectos:<br>Probabilidad de aumentar la DEF en un <span class=\"stat\">24%</span>.<br>Gran probabilidad de aumentar la DEF en un <span class=\"stat\">36%</span>.<br>Pequeña probabilidad de aumentar la DEF en un <span class=\"stat\">60%</span>.<br>Si se usa repetidas veces, solo se conserva el efecto con el valor más alto.<br>Cuando comienza la siguiente batalla, la DEF de todos los aliados aumenta en la cantidad correspondiente durante <span class=\"stat\">3</span> turnos.<br>Al usar la técnica se obtiene <span class=\"stat\">1</span> de <span class=\"stat\">3</span> posibles efectos de aumento de DEF al azar. Al entrar en el siguiente combate, la DEF de todos los aliados aumenta en la cantidad correspondiente.',0,''),(110,'Bailu','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Patada diagnóstica','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Bailu como Daño de <span class=\"element\">Rayo</span> a un enemigo.',20,'ATQ individual : 30'),(111,'Bailu','Habilidad Básica',NULL,NULL,NULL,'Regeneración','Cantando entre las nubes','Cura a un aliado con una cantidad de PV equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Bailu + <span class=\"stat\">{stat_2}</span>. Después, Bailu cura <span class=\"stat\">2</span> veces a aliados al azar. Cada vez que cura, los PV que regenera la siguiente curación realizada se reducen en un <span class=\"stat\">15%</span>.<br>Regenera PV a un aliado y después cura a aliados al azar.',30,''),(112,'Bailu','Definitiva',NULL,NULL,100,'Regeneración','Salto del dragón del marjal','Cura a todos los aliados con una cantidad de PV equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Bailu + <span class=\"stat\">{stat_2}</span>.<br>Aplica Vigor a los aliados que no lo tienen y alarga el efecto en <span class=\"stat\">1</span> turno a los que lo tienen.<br>Vigor dura <span class=\"stat\">2</span> turnos y no se puede acumular.<br>Regenera PV a todos los aliados y les aplica Vigor o extiende su duración.',5,''),(113,'Bailu','Talento',NULL,NULL,NULL,'Regeneración','Calabaza de elixir','Cuando un aliado con Vigor recibe un ataque, regenera una cantidad de PV equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Bailu + <span class=\"stat\">{stat_2}</span>. Este efecto se puede activar <span class=\"stat\">2</span> veces.<br>Cuando un aliado de Bailu recibe un golpe letal, no es derrotado, sino que Bailu lo cura inmediatamente con una cantidad de PV equivalente al <span class=\"stat\">{stat_3}%</span> de los PV máx. de Bailu + <span class=\"stat\">{stat_4}</span>. Este efecto se puede activar una vez en cada batalla.<br>Los aliados con Vigor regeneran PV tras recibir un ataque.',0,''),(114,'Bailu','Técnica',NULL,NULL,NULL,'Regeneración','Paseando bajo la lluvia','Tras usar la técnica, al comenzar la siguiente batalla, todos los aliados obtienen Vigor durante <span class=\"stat\">2</span> turnos.',0,''),(115,'Blade','Ataque Básico',1,NULL,NULL,'ATQ individual','Espada fragmentada','Inflige un <span class=\"stat\">{stat_1}%</span> de los PV máx. de Blade como Daño de <span class=\"element\">Viento</span> a un enemigo.',20,'ATQ individual : 30'),(116,'Blade','Habilidad Básica',1,NULL,NULL,'Potenciación','Panorama infernal','Consume un <span class=\"stat\">30%</span> de los PV máx. de Blade y entra en el estado Panorama infernal.<br>En el estado Panorama infernal no puede lanzar la habilidad básica y el daño que inflige Blade aumenta en un <span class=\"stat\">{stat_1}%</span>. Además, aumenta en gran medida la probabilidad de recibir ataques de los enemigos. El ATQ básico Espada fragmentada se potencia y se transforma en Bosque de espadas durante <span class=\"stat\">3</span> turnos.<br>Si Blade no tiene suficientes PV, al usar la habilidad básica sus PV se reducen a <span class=\"stat\">1</span>.<br>Esta habilidad básica no puede recuperar energía. Tras usar esta habilidad básica, el turno no termina.<br>Consume sus PV, obtiene un ATQ básico potenciado y aumenta la probabilidad de recibir ataques. El turno no termina.',0,''),(117,'Blade','Definitiva',1,NULL,130,'Ráfaga','Sentencia de muerte','Los PV actuales de Blade se establecen en el <span class=\"stat\">50%</span> de sus PV máx. e inflige a un enemigo un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Blade + <span class=\"stat\">{stat_2}%</span> del recuento de PV que ha perdido en esta batalla. También inflige a los objetivos adyacentes un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_3}%</span> de los PV máx. de Blade + <span class=\"stat\">{stat_4}%</span> del recuento de PV que ha perdido en esta batalla.<br>El recuento de PV perdidos en esta batalla no puede superar el <span class=\"stat\">90%</span> de los PV máx. de Blade. Al lanzar su habilidad definitiva, este recuento se reinicia.',5,'ATQ individual : 60 / Ráfaga : 60'),(118,'Blade','Talento',1,NULL,NULL,'ATQ AdE','Regalo de Shuhu','Cuando Blade recibe daño o consume PV, obtiene <span class=\"stat\">1</span> acumulación de carga, hasta un máximo de <span class=\"stat\">5</span> acumulaciones. Cada vez que recibe un ataque obtiene <span class=\"stat\">1</span> acumulación como máximo gracias a este efecto.<br>Cuando las acumulaciones llegan al máximo, lanza un ataque adicional a todos los enemigos que inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Blade. Además, Blade regenera el <span class=\"stat\">25%</span> de sus PV máx. Tras lanzar el ataque adicional se consumen todas las acumulaciones de carga.<br>Cuando Blade pierde PV, obtiene <span class=\"stat\">1</span> acumulación de carga. Cuando la carga llega al máximo, lanza un ataque adicional que inflige Daño de <span class=\"element\">Viento</span> a todos los enemigos y regenera PV, lo que consume todas las acumulaciones.',10,'ATQ AdE : 30'),(119,'Blade','Técnica',1,NULL,NULL,'','Viento kármico','Ataca inmediatamente al enemigo y entra en combate. Blade consume una cantidad de PV equivalente al <span class=\"stat\">20%</span> de sus PV máx. e inflige un <span class=\"stat\">40%</span> de sus PV máx. como Daño de <span class=\"element\">Viento</span> a todos los enemigos.<br>Si no tiene suficientes PV, al usar la técnica los PV de Blade se reducen a <span class=\"stat\">1</span>.<br>Ataca al enemigo y entra en combate. Consume sus PV e inflige Daño de <span class=\"element\">Viento</span> a todos los enemigos.',0,'ATQ individual : 60'),(120,'Blade','Ataque Básico',1,NULL,NULL,'Ráfaga','Bosque de espadas','Consume el <span class=\"stat\">10%</span> de los PV máx. de Blade e inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Blade a un enemigo. También inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_2}%</span> de los PV máx. de Blade a los objetivos adyacentes.<br>Si Blade no tiene suficientes PV, tras lanzar Bosque de espadas sus PV se reducen a <span class=\"stat\">1</span>.<br>Bosque de espadas no puede recuperar pts. de habilidad básica.',30,'ATQ individual : 60 / Ráfaga : 30'),(121,'Blade','Ataque Básico',NULL,0,NULL,'ATQ individual','Espada fragmentada','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Blade como Daño de <span class=\"element\">Viento</span> a un enemigo.',20,'ATQ individual : 30'),(122,'Blade','Habilidad Básica',NULL,0,NULL,'Potenciación','Panorama infernal','Consume un <span class=\"stat\">30%</span> de los PV máx. de Blade y entra en el estado Panorama infernal.<br>En el estado Panorama infernal no se puede usar la habilidad básica y el daño que inflige Blade aumenta en un <span class=\"stat\">{stat_1}%</span>. El ATQ básico Espada fragmentada se potencia y se transforma en Bosque de espadas durante <span class=\"stat\">3</span> turnos.<br>Si Blade no tiene suficientes PV, al usar la habilidad básica sus PV se reducen a <span class=\"stat\">1</span>.<br>Esta habilidad básica no recupera energía. Tras usar esta habilidad básica, el turno no termina.',0,NULL),(123,'Blade','Definitiva',NULL,0,130,'Ráfaga','Sentencia de muerte','Los PV actuales de Blade se establecen en el <span class=\"stat\">50%</span> de sus PV máx. e inflige a un enemigo un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_2}%</span> del ATQ de Blade + <span class=\"stat\">{stat_3}%</span> de sus PV máx. + <span class=\"stat\">{stat_4}%</span> del recuento de PV que ha perdido en esta batalla. También inflige a los enemigos adyacentes un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_5}%</span> del ATQ de Blade + <span class=\"stat\">{stat_6}%</span> de sus PV máx. + <span class=\"stat\">{stat_7}%</span> del recuento de PV que ha perdido en esta batalla.<br>El recuento de PV perdidos en esta batalla no puede superar el <span class=\"stat\">90%</span> de los PV máx. de Blade. Al usar su habilidad definitiva, este recuento se reinicia.',5,'ATQ individual : 60 / Ráfaga : 60'),(124,'Blade','Talento',NULL,0,NULL,'ATQ AdE','Regalo de Shuhu','Cuando Blade recibe daño o consume PV, obtiene <span class=\"stat\">1</span> acumulación de carga, hasta un máximo de <span class=\"stat\">5</span> acumulaciones. Cada vez que recibe un ataque obtiene <span class=\"stat\">1</span> acumulación como máximo gracias a este efecto.<br>Cuando las acumulaciones llegan al máximo, lanza un ataque adicional a todos los enemigos que inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_1}%</span> del ATQ de Blade + <span class=\"stat\">{stat_2}%</span> de sus PV máx. Además, Blade regenera el <span class=\"stat\">25%</span> de sus PV máx. Tras lanzar el ataque adicional se consumen todas las acumulaciones de carga.',10,'ATQ AdE : 30'),(125,'Blade','Técnica',NULL,0,NULL,NULL,'Viento kármico','Ataca inmediatamente al enemigo y entra en combate. Blade consume una cantidad de PV equivalente al <span class=\"stat\">20%</span> de sus PV máx. e inflige un <span class=\"stat\">40%</span> de sus PV máx. como Daño de <span class=\"element\">Viento</span> a todos los enemigos.<br>Si no tiene suficientes PV, al usar la técnica los PV de Blade se reducen a <span class=\"stat\">1</span>.',NULL,'ATQ individual : 60'),(126,'Blade','Ataque Básico',NULL,0,NULL,'Ráfaga','Bosque de espadas','Consume el <span class=\"stat\">10%</span> de los PV máx. de Blade e inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_1}%</span> del ATQ de Blade + <span class=\"stat\">{stat_2}%</span> de sus PV máx. a un enemigo. También inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_3}%</span> del ATQ de Blade + <span class=\"stat\">{stat_4}%</span> de sus PV máx. a los enemigos adyacentes.<br>Si Blade no tiene suficientes PV, tras usar Bosque de espadas sus PV se reducen a <span class=\"stat\">1</span>.<br>Bosque de espadas no puede recuperar pts. de habilidad básica.',30,'ATQ individual : 60 / Ráfaga : 30'),(127,'Black Swan','Ataque Básico',1,NULL,NULL,'ATQ individual','Discernimiento, alba silenciosa','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Cisne Negro como Daño de <span class=\"element\">Viento</span> a un enemigo.',20,'ATQ individual : 30'),(128,'Black Swan','Habilidad Básica',1,NULL,NULL,'Ráfaga','Decadencia, falso crepúsculo','Inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_1}%</span> del ATQ de Cisne Negro a un enemigo y a los enemigos adyacentes. Tiene una probabilidad base del <span class=\"stat\">100%</span> de reducir la DEF del objetivo y los objetivos adyacentes en un <span class=\"stat\">{stat_2}%</span> durante <span class=\"stat\">3</span> turnos.',30,'ATQ individual : 60 / Ráfaga : 30'),(129,'Black Swan','Definitiva',1,NULL,120,'ATQ AdE','Regocijo en el abrazo de otro mundo','Afecta con Desvelación a todos los enemigos durante <span class=\"stat\">2</span> turnos. A continuación, inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Cisne Negro como Daño de <span class=\"element\">Viento</span> a todos los enemigos.<br>En el estado de Desvelación, el daño que reciben los enemigos aumenta en un <span class=\"stat\">{stat_2}%</span>. Por cada acumulación de Arcano aplicada, hay una probabilidad fija del <span class=\"stat\">50%</span> de aplicar <span class=\"stat\">1</span> acumulación más. Además, después de que Arcano inflija daño al principio del turno, las acumulaciones no se reducen a la mitad.<br>Aplica Desvelación a todos los enemigos, con lo que aumenta el daño que reciben los objetivos y hay una probabilidad de obtener más acumulaciones de Arcano en esta ocasión. Además, después de que Arcano inflija daño al principio del siguiente turno, las acumulaciones no se reducen a la mitad. Inflige Daño de <span class=\"element\">Viento</span> a todos los enemigos.',5,'ATQ AdE : 60'),(130,'Black Swan','Talento',1,NULL,NULL,'Alteracíon','Telar del capricho del destino','Cada vez que un enemigo recibe Daño con el tiempo, hay una probabilidad base del <span class=\"stat\">{stat_1}%</span> de que reciba <span class=\"stat\">1</span> acumulación de Arcano.<br>Cuando un enemigo está afectado con Arcano, se considera que también está afectado con Intemperie, Sangrado, Quemadura y Electrocución, y recibe un Daño de <span class=\"element\">Viento</span> con el tiempo equivalente al <span class=\"stat\">{stat_2}%</span> del ATQ de Cisne Negro al comienzo de cada turno. Después, las acumulaciones se reducen a la mitad. Cada acumulación de Arcano aumenta este multiplicador de daño en un <span class=\"stat\">{stat_3}%</span>. Arcano puede acumularse hasta <span class=\"stat\">50</span> veces y puede seguir acumulándose tras exceder este límite, pero las acumulaciones excedentes se eliminan tras infligir daño.<br>El daño infligido por Arcano ignora el <span class=\"stat\">20%</span> de la DEF del objetivo. Solo cuando Arcano inflige daño al comenzar el turno del enemigo, los objetivos adyacentes también reciben una vez un <span class=\"stat\">{stat_4}%</span> del ATQ de Cisne Negro como Daño de <span class=\"element\">Viento</span> con el tiempo.<br>Cuando un enemigo recibe Daño con el tiempo, hay una probabilidad de afectarlo con Arcano. Arcano se considera equivalente a Intemperie, Sangrado, Quemadura y Electrocución, e inflige Daño de <span class=\"element\">Viento</span> con el tiempo en cada turno del objetivo afectado. Además, inflige Daño de <span class=\"element\">Viento</span> con el tiempo a los objetivos adyacentes solo cuando dicho enemigo comienza su turno.<br>Arcano puede seguir acumulándose incluso después de alcanzar el límite de acumulaciones. Tras infligir daño, se disipan las acumulaciones que excedan el límite.',0,'0'),(131,'Black Swan','Técnica',1,NULL,NULL,'Potenciación','De la apariencia a la verdad','Tras usar la técnica, al comenzar la siguiente batalla, hay una probabilidad base del <span class=\"stat\">150%</span> de aplicar <span class=\"stat\">1</span> acumulación de Arcano a cada enemigo. Por cada aplicación de Arcano a un objetivo, aplica otra acumulación de Arcano al mismo objetivo. Este efecto se repite hasta que no se logre aplicar Arcano a ese objetivo. Cada vez, la probabilidad base de aplicar Arcano a ese objetivo es equivalente al <span class=\"stat\">50%</span> de la probabilidad base de la aplicación anterior de Arcano a ese objetivo.',0,'0'),(132,'Black Swan','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Discernimiento, alba silenciosa','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Cisne Negro como Daño de <span class=\"element\">Viento</span> a un enemigo y tiene una probabilidad base del <span class=\"stat\">{stat_2}%</span> de aplicar <span class=\"stat\">1</span> acumulación de Arcano al objetivo golpeado. Tras golpear a un objetivo afectado por Intemperie, Sangrado, Quemadura o Electrocución, cada uno de estos estados tiene una probabilidad base del <span class=\"stat\">{stat_3}%</span> de aplicar <span class=\"stat\">1</span> acumulación adicional de Arcano al objetivo.',20,'ATQ individual : 30'),(133,'Black Swan','Habilidad Básica',NULL,NULL,NULL,'Ráfaga','Decadencia, falso crepúsculo','Inflige un Daño de <span class=\"element\">Viento</span> equivalente al <span class=\"stat\">{stat_1}%</span> del ATQ de Cisne Negro a un enemigo y a los enemigos adyacentes. Tiene una probabilidad base del <span class=\"stat\">100%</span> de aplicar <span class=\"stat\">1</span> acumulación de Arcano al objetivo y a los objetivos adyacentes y una probabilidad base del <span class=\"stat\">100%</span> de reducir la DEF del objetivo y los objetivos adyacentes en un <span class=\"stat\">{stat_2}%</span> durante <span class=\"stat\">3</span> turnos.',30,'ATQ individual : 60 / Ráfaga : 30'),(134,'Black Swan','Definitiva',NULL,NULL,NULL,'ATQ AdE','Regocijo en el abrazo de otro mundo','Afecta con Desvelación a todos los enemigos durante <span class=\"stat\">2</span> turnos.<br>En el estado de Desvelación, el daño que reciben los objetivos durante su propio turno aumenta en un <span class=\"stat\">{stat_1}%</span>, y mientras el objetivo está afectado por Arcano, se considera que también está afectado por Intemperie, Sangrado, Quemadura y Electrocución. Además, después de que Arcano inflija daño al principio de cada turno, no se restablecen las acumulaciones. Mientras dure Desvelación, este efecto para no restablecer las acumulaciones de Arcano se puede activar <span class=\"stat\">1</span> vez como máximo. El contador de activaciones se actualiza cuando se vuelve a aplicar Desvelación.<br>Inflige un <span class=\"stat\">{stat_2}%</span> del ATQ de Cisne Negro como Daño de <span class=\"element\">Viento</span> a todos los enemigos.<br>Aplica Desvelación a todos los enemigos, que hace que aumente el daño que recibe el objetivo durante su turno, y Arcano se considera equivalente a Intemperie, Sangrado, Quemadura y Electrocución. Además, después de que Arcano inflija daño al principio del siguiente turno, no se restablecen las acumulaciones. Inflige Daño de <span class=\"element\">Viento</span> a todos los enemigos.',5,'ATQ AdE : 60'),(135,'Black Swan','Talento',NULL,NULL,NULL,'Alteracíon','Telar del capricho del destino','Cada vez que un objetivo enemigo recibe Daño con el tiempo al inicio de cada turno, hay una probabilidad base del <span class=\"stat\">{stat_1}%</span> de que reciba <span class=\"stat\">1</span> acumulación de Arcano.<br>Los enemigos afectados por Arcano reciben un Daño de <span class=\"element\">Viento</span> con el tiempo equivalente al <span class=\"stat\">{stat_2}%</span> del ATQ de Cisne Negro al comienzo de cada turno. Cada acumulación de Arcano aumenta este multiplicador de daño en un <span class=\"stat\">{stat_3}%</span> y después las acumulaciones se restablecen a <span class=\"stat\">1</span>. Arcano se puede acumular hasta <span class=\"stat\">50</span> veces.<br>Solo cuando Arcano inflige daño al inicio del turno del objetivo enemigo, Cisne Negro activa efectos adicionales según la cantidad de acumulaciones de Arcano que tenga el enemigo:<br>Si tiene <span class=\"stat\">3</span> o más acumulaciones, inflige un Daño de <span class=\"element\">Viento</span> con el tiempo equivalente al <span class=\"stat\">{stat_4}%</span> del ATQ de Cisne Negro a los objetivos adyacentes. Además, tiene una probabilidad base del <span class=\"stat\">{stat_5}%</span> de aplicarles <span class=\"stat\">1</span> acumulación de Arcano.<br>Si tiene <span class=\"stat\">7</span> o más acumulaciones, el Daño con el tiempo infligido esta vez ignora un <span class=\"stat\">20%</span> de la DEF del objetivo y de los objetivos adyacentes.',0,'0'),(137,'Boothill','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Espuelas rompetestas','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Boothill como Daño <span class=\"element\">Físico</span> a un enemigo.',20,'ATQ individual : 30'),(138,'Boothill','Habilidad Básica',NULL,NULL,NULL,'Alteracíon','Tango de las brasas ardientes','Hace que Boothill y un enemigo entren en el estado de Duelo a muerte. El ATQ básico de Boothill se potencia y no puede usar la habilidad básica durante <span class=\"stat\">2</span> turnos. Esta duración se reduce en <span class=\"stat\">1</span> al comienzo del turno de Boothill.<br>El objetivo enemigo con Duelo a muerte es afectado con Provocación. Cuando el enemigo/Boothill reciben un ataque uno del otro, el daño recibido aumenta en un <span class=\"stat\">{stat_1}%</span>/<span class=\"stat\">15%</span>.<br>Después de que este enemigo sea derrotado o se rompa su Debilidad, Boothill obtiene <span class=\"stat\">1</span> acumulación de Ventaja en el bolsillo y luego disipa Duelo a muerte.<br>Esta habilidad básica no puede recuperar energía y el turno no termina.<br>Inicia Duelo a muerte. Después de que el objetivo de Duelo a muerte sea derrotado o se rompa su Debilidad, Boothill obtiene Ventaja en el bolsillo y disipa Duelo a muerte. Potencia su ATQ básico y el turno no termina.',0,'0'),(139,'Boothill','Definitiva',NULL,NULL,115,'ATQ individual','Rodeo vespertino del diablo de polvo','Aplica Debilidad Física a un enemigo durante <span class=\"stat\">2</span> turnos.<br>Además, inflige al enemigo un Daño <span class=\"element\">Físico</span> equivalente al <span class=\"stat\">{stat_1}%</span> del ATQ de Boothill y retrasa su acción en un <span class=\"stat\">{stat_2}%</span>.',5,'ATQ individual : 90'),(140,'Boothill','Talento',NULL,NULL,NULL,'Potenciación','Cinco guisantes en la vaina','Cada acumulación de Ventaja en el bolsillo aumenta la Reducción de Firmeza del ATQ básico potenciado en un <span class=\"stat\">50%</span>, hasta un máximo de <span class=\"stat\">3</span> acumulaciones.<br>Si el enemigo está afectado por Ruptura de Debilidad cuando usa el ATQ básico potenciado, inflige a ese enemigo un Daño de Ruptura equivalente al <span class=\"stat\">{stat_1}%</span>/<span class=\"stat\">{stat_2}%</span>/<span class=\"stat\">{stat_3}%</span> del Daño de Ruptura <span class=\"element\">Físico</span> de Boothill, en función de las acumulaciones de Ventaja en el bolsillo. La Firmeza máxima calculada para este daño no puede superar <span class=\"stat\">16</span> veces la Reducción de Firmeza de base que tiene el ATQ básico \"Espuelas rompetestas\".<br>Tras ganar el combate, Boothill mantiene Ventaja en el bolsillo para el siguiente combate.<br>Ventaja en el bolsillo hace que el ATQ básico potenciado tenga más Reducción de Firmeza e inflija Daño de Ruptura <span class=\"element\">Físico</span> extra al enemigo afectado por Ruptura de Debilidad. Tras ganar el combate, Ventaja en el bolsillo se mantiene para el siguiente combate.',0,'0'),(141,'Boothill','Técnica',NULL,NULL,NULL,'Potenciación','Sonrisa 3×9','La primera vez que use la habilidad básica en el siguiente combate después de usar la técnica, afecta al objetivo con una Debilidad Física equivalente a la de la habilidad definitiva durante <span class=\"stat\">2</span> turnos.<br>Tras usar la técnica, aplica Debilidad Física a un enemigo la primera vez que use la habilidad básica en el siguiente combate.',0,'0'),(142,'Boothill','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Percutor de repetición','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Boothill como Daño <span class=\"element\">Físico</span> a un enemigo.<br>El ATQ básico potenciado no recupera pts. de habilidad básica y solo puede tener como objetivo al enemigo que tenga Duelo a muerte.<br>Inflige Daño <span class=\"element\">Físico</span> a un enemigo. Solo puede atacar al enemigo con Duelo a muerte.',30,'ATQ individual : 60'),(143,'Bronya','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Bala del vendaval','Inflige un <span class=\"stat\">{stat_1}%</span> del ATQ de Bronya como Daño de <span class=\"element\">Viento</span> a un enemigo.',20,'ATQ individual : 30'),(144,'Bronya','Habilidad Básica',NULL,NULL,NULL,'Apoyo','Reorganización del combate','Elimina un estado negativo de un aliado, hace que realice una acción inmediatamente y aumenta el daño que inflige en un <span class=\"stat\">{stat_1}%</span> durante <span class=\"stat\">1</span> turno.<br>Si utiliza esta habilidad consigo misma, no se activará la acción inmediata.<br>Elimina <span class=\"stat\">1</span> estado negativo de un aliado, aumenta el daño que inflige y hace que realice una acción inmediatamente.',30,'0'),(145,'Bronya','Definitiva',NULL,NULL,120,'Apoyo','Marcha de Belobog','El ATQ de todos los aliados aumenta en un <span class=\"stat\">{stat_1}%</span> y el Daño CRIT se incrementa en un <span class=\"stat\">{stat_2}%</span> del Daño CRIT de Bronya + <span class=\"stat\">{stat_3}%</span> durante <span class=\"stat\">2</span> turnos.<br>Aumenta el ATQ y el Daño CRIT de todos los aliados.',5,'0'),(146,'Bronya','Talento',NULL,NULL,NULL,'Potenciación','Liderazgo','Tras usar el ATQ básico, la siguiente acción de Bronya se adelanta un <span class=\"stat\">{stat_1}%</span>.',5,'ATQ individual : 30'),(147,'Bronya','Técnica',NULL,NULL,NULL,'Apoyo','Estandarte de mando','Tras usar la técnica, al comenzar la siguiente batalla, el ATQ de todos los aliados aumenta en un <span class=\"stat\">15%</span> durante <span class=\"stat\">2</span> turnos.',0,'0'),(148,'Castorice','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Santuario de la crisálida lunar','Tras obtener a Castorice o cuando Castorice está en el equipo actual, se obtiene este efecto: en el combate, si un personaje aliado recibe un golpe letal, todos los personajes aliados que reciban un golpe letal en esa acción entran en el estado Crisálida lunar. Este estado pospone que sean derrotados y les permite actuar de forma normal. Después de esa acción, si sus PV actuales aumentan u obtienen un escudo antes del siguiente turno, se disipa el estado Crisálida lunar. De lo contrario, los personajes son derrotados inmediatamente. Este efecto solo se puede activar <span class=\"stat\">1</span> vez por batalla.',0,'0'),(149,'Castorice','Ataque Básico',NULL,NULL,NULL,'ATQ individual','Lamentos, olas del mar muerto','Inflige un Daño Cuántico equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Castorice a un enemigo.',0,'ATQ individual : 30'),(150,'Castorice','Habilidad Básica',NULL,NULL,NULL,'Ráfaga','Silencio, caricia de la mariposa elegíaca','Castorice consume un <span class=\"stat\">30%</span> de los PV actuales de todos los aliados e inflige un <span class=\"stat\">{stat_1}%</span> de sus PV máx. como Daño Cuántico a un enemigo y un <span class=\"stat\">{stat_2}%</span> de sus PV máx. como Daño Cuántico a los objetivos adyacentes.<br>Si los PV actuales son insuficientes, se reducen a <span class=\"stat\">1</span>.<br>Si el Dragón Caído está en el campo de batalla, la habilidad básica se convierte en Garra ósea, abrazo del dragón lóbrego.',0,'ATQ individual : 60 / Ráfaga : 30'),(151,'Castorice','Talento',NULL,NULL,NULL,'Potenciación','Desolación, de palmas derramada','El máximo de Nuevo brote se basa en el nivel de todos los personajes en el campo de batalla. Castorice obtiene <span class=\"stat\">1</span> punto de Nuevo brote por cada PV perdido por todos los aliados. Cuando Nuevo brote llega al máximo, se activa la habilidad definitiva. Además, cuando los aliados pierden PV, el daño que infligen Castorice y el Dragón Caído aumenta en un <span class=\"stat\">{stat_1}%</span>. Este efecto se puede acumular hasta <span class=\"stat\">3</span> veces y dura <span class=\"stat\">3</span> turnos.<br>Mientras el Dragón Caído está en el campo de batalla, no se puede obtener Nuevo brote mediante el talento. Además, los PV que pierdan todos los aliados (excepto el Dragón Caído) se convierten en la misma cantidad de PV para el Dragón Caído.<br>Cuando un aliado pierde PV, Castorice obtiene Nuevo brote, y aumenta el daño que infligen Castorice y el Dragón Caído. Cuando Nuevo brote llega al máximo, se activa la habilidad definitiva. Mientras el Dragón Caído está en el campo de batalla, los PV que pierdan los aliados (excepto el Dragón Caído) se convierten en la misma cantidad de PV para el Dragón Caído.',0,'0'),(152,'Castorice','Técnica',NULL,NULL,NULL,'No especificado','Clamor, heraldo de muerte','Tras usar la técnica, entra en el estado de Vastedad lúgubre durante <span class=\"stat\">20</span> s. Mientras el estado de Vastedad lúgubre está activo, los enemigos no pueden acercarse por iniciativa propia a Castorice.<br>Al atacar en el estado de Vastedad lúgubre, todos los enemigos en el área entran en combate y Castorice invoca al mnemoduende Dragón Caído. A su vez, adelanta la acción del Dragón Caído un <span class=\"stat\">100%</span> y despliega el Territorio Inframundo perdido. El Dragón Caído empieza con unos PV actuales equivalentes al <span class=\"stat\">50%</span> del límite máximo de Nuevo brote. Tras entrar en combate, se consume un <span class=\"stat\">40%</span> de los PV actuales de todos los aliados (excepto del Dragón Caído).<br>Tras entrar en combate y antes de invocar al Dragón Caído, Castorice obtiene una cantidad de Nuevo brote equivalente al <span class=\"stat\">30%</span> del límite máximo.<br>Entra en el estado de Vastedad lúgubre, y los enemigos no pueden acercarse por iniciativa propia a Castorice.<br>Al atacar en el estado de Vastedad lúgubre, hace que todos los enemigos en el área entren en combate e invoca al mnemoduende Dragón Caído, el cual adelanta su acción un <span class=\"stat\">100%</span>. Al entrar en combate, se consumen PV de todos los aliados (excepto del Dragón Caído).',0,'0'),(153,'Castorice','Habilidad Básica',NULL,NULL,NULL,'ATQ AdE','Garra ósea, abrazo del dragón lóbrego','Consume un <span class=\"stat\">40%</span> de los PV actuales de todos los aliados (excepto el Dragón Caído). Castorice y el Dragón Caído lanzan un ataque combinado que inflige a todos los enemigos un Daño Cuántico equivalente al <span class=\"stat\">{stat_1}%</span> y el <span class=\"stat\">{stat_2}%</span> de los PV máx. de Castorice.<br>Si los PV actuales son insuficientes, se reducen a <span class=\"stat\">1</span>.<br>Consume PV de todos los aliados. Castorice y el Dragón Caído lanzan un ataque combinado que inflige Daño Cuántico a todos los enemigos.',0,'ATQ AdE : 60'),(154,'Castorice','Definitiva',NULL,NULL,NULL,'Invocación','Estertor, tintineo del renacer','Invoca al mnemoduende Dragón Caído y adelanta la acción de este un <span class=\"stat\">100%</span>. Además, despliega el Territorio Inframundo perdido, que reduce la RES a todos los tipos de todos los enemigos en un <span class=\"stat\">{stat_1}%</span>. Si Castorice tiene el efecto de aumento de daño del talento, este efecto se extiende también al Dragón Caído. El Dragón Caído tiene inicialmente <span class=\"stat\">165</span> puntos de VEL y unos PV máx. fijos equivalentes al <span class=\"stat\">100%</span> del límite de Nuevo brote.<br>El Dragón Caído desaparece después de <span class=\"stat\">3</span> turnos o cuando sus PV llegan a <span class=\"stat\">0</span>. Cuando desaparece, el Territorio Inframundo perdido se disipa.<br>Invoca al mnemoduende Dragón Caído y adelanta la acción de este un <span class=\"stat\">100%</span>. A su vez, despliega un Territorio que reduce la RES a todos los tipos de todos los enemigos.',0,'0'),(155,'Castorice','Habilidad del Mnemoduende',NULL,NULL,NULL,'ATQ AdE','Garras que rasgan la oscuridad','Inflige un Daño Cuántico equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Castorice a todos los enemigos.',0,'ATQ AdE : 30'),(156,'Castorice','Habilidad del Mnemoduende',NULL,NULL,NULL,'ATQ AdE','Aliento que prende las sombras','Al lanzar Aliento que prende las sombras, consume un <span class=\"stat\">25%</span> de los PV máx. del Dragón Caído e inflige a todos los enemigos un Daño Cuántico equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Castorice.<br>Puede lanzar repetidamente Aliento que prende las sombras en un ataque. Al lanzarlo repetidamente, el multiplicador de daño aumenta sucesivamente hasta el <span class=\"stat\">{stat_2}%</span>/<span class=\"stat\">{stat_3}%</span>. Tras alcanzar el <span class=\"stat\">{stat_4}%</span>, ya no sigue aumentando. El efecto de aumento del multiplicador de daño no disminuye hasta que el Dragón Caído desaparezca.<br>Si los PV actuales del Dragón Caído son iguales o inferiores al <span class=\"stat\">25%</span> de sus PV máx. al lanzar esta habilidad, los PV se reducen a <span class=\"stat\">1</span> y se activa un efecto de habilidad equivalente al de Alas que abaten las ruinas del talento de mnemoduende.',0,'ATQ AdE : 30'),(157,'Castorice','Talento del Mnemoduende',NULL,NULL,NULL,'Apoyo','Cuerpo oculto en la crisálida','Cuando está en el campo de batalla, el Dragón Caído actúa de Refuerzo de los aliados. Los PV actuales de los aliados pueden reducirse hasta un mínimo de <span class=\"stat\">1</span> al recibir daño o consumir PV, tras lo cual el Dragón Caído recibe el daño o consume PV en su lugar en una proporción del <span class=\"stat\">500%</span> del valor original, hasta que el Dragón Caído desaparezca.',0,'0'),(158,'Castorice','Talento del Mnemoduende',NULL,NULL,NULL,'Apoyo','Rugido que estremece el páramo','Cuando el Dragón Caído es invocado, el daño que infligen todos los aliados aumenta en un <span class=\"stat\">10%</span> durante <span class=\"stat\">3</span> turnos.<br>Al ser invocado, el daño que infligen todos los aliados aumenta.',0,'0'),(159,'Castorice','Talento del Mnemoduende',NULL,NULL,NULL,'Rebote','Alas que abaten las ruinas','Cuando el Dragón Caído desaparece, inflige daño <span class=\"stat\">6</span> veces. Cada vez inflige a un enemigo al azar un Daño Cuántico equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. de Castorice. Además, regenera a todos los aliados una cantidad de PV equivalente al <span class=\"stat\">{stat_2}%</span> de los PV máx. de Castorice + <span class=\"stat\">{stat_3}</span>.',0,'ATQ individual : 15'),(160,'Cyrene','Ataque Básico',NULL,NULL,NULL,'ATQ individual','¡Mira, el comienzo de la esperanza!','Obtiene <span class=\"stat\">1</span> punto de Remembranza e inflige un <span class=\"stat\">{stat_1}%</span> de los PV máx. de Cirene como Daño de <span class=\"element\">Hielo</span> a un enemigo.',0,'ATQ individual : 30'),(161,'Cyrene','Habilidad Básica',NULL,NULL,NULL,'Apoyo','Florece, paraíso del más allá','Obtiene <span class=\"stat\">3</span> puntos de Remembranza y despliega un campo que dura <span class=\"stat\">2</span> turnos. La duración del campo se reduce en <span class=\"stat\">1</span> al inicio de cada turno de Cirene. Mientras el campo está activo, cada vez que cualquier aliado inflige daño, inflige adicionalmente un <span class=\"stat\">{stat_1}%</span> del daño original como Daño verdadero. Si Cirene es derrotada, el campo se disipa.<br>Obtiene Remembranza y despliega un campo. Inflige Daño verdadero extra después de que cualquier aliado inflija daño.',0,'0'),(162,'Cyrene','Talento',NULL,NULL,NULL,'Potenciación','Deseos confluyentes','Al comenzar la batalla o después de que Cirene actúe, otros personajes del equipo con cualquier estado y sus mnemoduendes obtienen Futuro, independientemente del estado en que estén. Cuando un aliado con Futuro actúa, consume Futuro y otorga <span class=\"stat\">1</span> punto de Remembranza a Cirene. Cirene activa su habilidad definitiva y disipa todos sus estados negativos cuando tiene <span class=\"stat\">24</span> puntos de Remembranza. Si está en el estado de Ondas del pasado, Cirene puede activar su habilidad definitiva con <span class=\"stat\">12</span> puntos de Remembranza. Tras alcanzar el límite, los puntos pueden seguir acumulándose hasta llegar a <span class=\"stat\">27</span>. Cuando Cirene está en el campo de batalla, el daño que infligen todos los aliados aumenta en un <span class=\"stat\">{stat_1}%</span>.',0,'0'),(163,'Cyrene','Técnica',NULL,NULL,NULL,'Apoyo','Paz eterna al final del céfiro','Tras usar la técnica, crea una zona especial a su alrededor que dura <span class=\"stat\">30</span> s. Dentro de esta zona especial, los enemigos son afectados con el estado Momento eterno, con lo que detienen todas sus acciones, y los personajes aliados aumentan su VEL de movimiento en un <span class=\"stat\">50%</span>. Tras entrar en combate mientras la zona está activa, despliega el campo de la habilidad básica. Solo puede haber una zona especial creada por los aliados a la vez.<br>Crea una zona especial a su alrededor. Dentro de esta zona, los enemigos son afectados con el estado Momento eterno, y los personajes aliados aumentan su VEL de movimiento. Despliega el campo de la habilidad básica al entrar en combate.',0,'0'),(164,'Cyrene','Ataque Básico',NULL,NULL,NULL,'ATQ AdE','♪ Por el amor y el mañana ♪','Cirene obtiene <span class=\"stat\">3</span> puntos de Remembranza e inflige un <span class=\"stat\">{stat_1}%</span> y luego un <span class=\"stat\">{stat_2}%</span> de sus PV máx. como Daño de <span class=\"element\">Hielo</span> a un enemigo y a todos los enemigos respectivamente.<br>♪ Por el amor y el mañana ♪ no recupera pts. de habilidad básica.<br>Obtiene Remembranza e inflige Daño de <span class=\"element\">Hielo</span> a todos los enemigos.',0,'ATQ individual : 30 / ATQ AdE : 15'),(165,'Cyrene','Definitiva',NULL,NULL,NULL,'Potenciación','Como la primera vez','El Demiurgo obtiene inmediatamente <span class=\"stat\">1</span> turno adicional.',0,'0'),(166,'Cyrene','Definitiva',NULL,NULL,NULL,'Invocación','◦ de versos, ∞ de votos','Invoca al mnemoduende Demiurgo, le otorga inmediatamente un turno adicional y activa la habilidad definitiva de todos los compañeros de equipo. A continuación entra en el estado Ondas del pasado, potencia su ATQ básico a ♪ Por el amor y el mañana ♪ y solo puede usar este ATQ básico. La Prob. CRIT de Cirene y del Demiurgo aumenta en un <span class=\"stat\">{stat_1}%</span> y despliega el campo de la habilidad básica sin límite de duración.<br>Solo se puede lanzar <span class=\"stat\">1</span> vez por combate. Los PV iniciales del Demiurgo son equivalentes al <span class=\"stat\">100%</span> de los PV máx. de Cirene.',0,'0'),(167,'Cyrene','Habilidad del Mnemoduende',NULL,NULL,NULL,'ATQ AdE','Danza de flores y flechas','Inflige un Daño de <span class=\"element\">Hielo</span> equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. del Demiurgo a todos los enemigos.<br>Inflige Daño de <span class=\"element\">Hielo</span> a todos los enemigos.',0,'ATQ individual : 5 / ATQ AdE : 30'),(168,'Cyrene','Habilidad del Mnemoduende',NULL,NULL,NULL,'Apoyo','Poesía dedicada a la vida','Aplica un efecto positivo a un personaje aliado. Si ese personaje es un Heredero de Crisos, le otorga un efecto especial. Si ese personaje no es un Heredero de Crisos, el daño que inflige aumenta en un <span class=\"stat\">{stat_1}%</span> durante <span class=\"stat\">2</span> turnos. También tiene efecto en su mnemoduende.',0,'0'),(169,'Cyrene','Talento del Mnemoduende',NULL,NULL,NULL,'Potenciación','Espera en todos los pasados','El Demiurgo mantiene en <span class=\"stat\">0</span> su VEL y no aparece en el orden de acción. Mientras está en el campo de batalla, se considera como fuera de límites. Cuando el porcentaje de PV de Cirene sufre algún cambio, el porcentaje de PV del Demiurgo también cambia. Mientras el Demiurgo esté en el campo de batalla, los PV máx. de Cirene y el Demiurgo aumentan en un <span class=\"stat\">{stat_1}%</span>. Después de que el Demiurgo lance una habilidad, la duración de todos sus efectos continuos se reduce en <span class=\"stat\">1</span> turno.<br>Cuando los PV de Cirene cambian, los PV del Demiurgo también cambian. Cuando el Demiurgo está en el campo de batalla, los PV máx. de Cirene aumentan.',0,'0'),(170,'Cyrene','Talento del Mnemoduende',NULL,NULL,NULL,'Potenciación','♪ Hola, mundo ♪','Cuando el Demiurgo es invocado, disipa estados negativos de Control de todos los aliados.<br>Al ser invocado, disipa estados negativos de Control de todos los aliados.',0,'0'),(171,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema de la Creación','Efectivo durante toda la batalla. Al lanzarse sobre la(el) Trazacaminos (<span class=\"path\">Reminiscencia</span>), el ATQ y la Prob. CRIT de esta(e) aumentan respectivamente en una cantidad equivalente al <span class=\"stat\">{stat_1}%</span> de los PV máx. y el <span class=\"stat\">{stat_2}%</span> de la Prob. CRIT del Demiurgo. Este efecto también se aplica a Mem. Durante esta batalla, después de que la(el) Trazacaminos (<span class=\"path\">Reminiscencia</span>) lance un ATQ básico potenciado, el Demiurgo obtiene inmediatamente <span class=\"stat\">1</span> turno adicional y lanza automáticamente Danza de flores y flechas. Si el objetivo es eliminado antes de lanzarse, se lanza contra un nuevo enemigo que haya entrado a la batalla.',0,'0'),(172,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema del Romance','Efectivo una vez. Al lanzarse sobre Aglaea, Aglaea obtiene Romance y aumentan inmediatamente al máximo las acumulaciones del efecto de aumento de VEL del talento de mnemoduende del Sastre. Después de que Aglaea o el Sastre ataquen, Aglaea consume Romance y recupera <span class=\"stat\">70</span> pts. de energía. El daño que infligen Aglaea y el Sastre aumenta en un <span class=\"stat\">{stat_1}%</span> e ignora el <span class=\"stat\">{stat_2}%</span> de la DEF del objetivo hasta que Aglaea salga del estado de Disposición suprema.',0,'0'),(173,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema de las Sendas','Efectivo durante toda la batalla. Al lanzarse sobre Tribbie, hace que el daño que inflige ignore un <span class=\"stat\">{stat_1}%</span> de la DEF del enemigo. Cuando el ataque adicional de Tribbie activa el daño adicional de su campo, inflige daño adicional <span class=\"stat\">1</span> vez más.',0,'0'),(174,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema del Conflicto','Efectivo una vez. Al lanzarse sobre Midei, disipa todos los estados negativos de Control que tenga Midei. Si Midei está en el estado Venganza de sangre, lanza automáticamente \"Deicidio, ascenso divino\" <span class=\"stat\">1</span> vez sin consumir carga y su Daño CRIT en este ataque aumenta en un <span class=\"stat\">{stat_1}%</span> (si el objetivo es eliminado antes de lanzarse, se lanza contra un nuevo enemigo que haya entrado a la batalla). Si Midei no está en el estado de Venganza de sangre, su acción se adelanta un <span class=\"stat\">100%</span>.',0,'0'),(175,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema de la Muerte','Efectivo durante toda la batalla. Al lanzarse sobre Castorice, Nuevo brote puede tener un excedente de hasta el <span class=\"stat\">200%</span>. Al invocar al Dragón Caído, se consume todo el exceso de Nuevo brote. Por cada <span class=\"stat\">1%</span> de exceso consumido, aumenta en un <span class=\"stat\">{stat_1}%</span> el multiplicador del daño que inflige el Dragón Caído invocado esta vez al activar el efecto del talento \"Alas que abaten las ruinas\". Si en el campo de batalla hay <span class=\"stat\">2</span> enemigos o menos al invocarlo, el multiplicador de daño aumenta adicionalmente en un <span class=\"stat\">{stat_2}%</span>.',0,'0'),(176,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema de la Razón','Efectivo una vez. Al lanzarse sobre Anaxa, los aliados recuperan <span class=\"stat\">1</span> pt. de habilidad básica. Anaxa actúa inmediatamente y su habilidad básica inflige daño <span class=\"stat\">3</span> veces más durante <span class=\"stat\">1</span> turno. La siguiente vez que Anaxa lanza el ATQ básico o la habilidad básica, obtiene Sabiduría verdadera, con lo que el ATQ y el daño de habilidad básica infligido de todos los personajes de la Vía de la <span class=\"path\">Erudición</span> aumentan en un <span class=\"stat\">{stat_1}%</span> y un <span class=\"stat\">{stat_2}%</span> respectivamente hasta que comience el siguiente turno de Anaxa.',0,'0'),(177,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema del Cielo','Cuando el Demiurgo lanza su habilidad de mnemoduende, Hyacine obtiene <span class=\"stat\">2</span> acumulaciones de Poema del Cielo. Al lanzarse sobre Hyacine, Hyacine recupera <span class=\"stat\">{stat_1}</span> pts. de energía. Cuando Hyacine tiene Poema del Cielo y proporciona curación, el valor de curación de la habilidad de mnemoduende de Ica aumenta adicionalmente en un <span class=\"stat\">{stat_2}%</span> del valor de curación de esa vez. Después de que Hyacine lance su habilidad básica/definitiva, consume <span class=\"stat\">1</span> acumulación de Poema del Cielo.',0,'0'),(178,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema del Engaño','Efectivo durante toda la batalla. Al lanzarse sobre Cífer, el daño que inflige Cífer aumenta en un <span class=\"stat\">{stat_1}%</span> y la DEF del Cliente habitual se reduce en un <span class=\"stat\">{stat_2}%</span>. La DEF de los enemigos que no sean el Cliente habitual se reduce en un <span class=\"stat\">{stat_3}%</span>.',0,'0'),(179,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema del Sostén del Mundo','Efectivo durante toda la batalla. Tras lanzarse sobre Fainón, Fainón recibe <span class=\"stat\">6</span> pts. de Yesca y obtiene Combustión perpetua al transformarse. Si al transformarse tiene más de <span class=\"stat\">12</span> pts. de Yesca, por cada pt. excedente el Daño CRIT de Khaslana aumenta en un <span class=\"stat\">{stat_1}%</span>, hasta un máximo del <span class=\"stat\">{stat_2}%</span>. Cuando tiene Combustión perpetua, la Prob. CRIT de Khaslana aumenta en un <span class=\"stat\">{stat_3}%</span>, la transformación no termina cuando se agotan los turnos adicionales de Khaslana, sino que se restauran todos los turnos adicionales de Khaslana, y obtiene <span class=\"stat\">4</span> pts. de Flagelo. Cuando comienza un turno adicional, Khaslana consume un <span class=\"stat\">15%</span> de sus PV actuales. Tras atacar, inflige daño adicional <span class=\"stat\">5</span> veces, infligiendo cada vez un Daño de <span class=\"element\">Fuego</span> adicional equivalente al <span class=\"stat\">{stat_4}%</span> del ATQ de Khaslana a un enemigo al azar.',0,'0'),(180,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema del Océano','Efectivo una vez. Al lanzarse sobre Hysilens, Hysilens obtiene Torrente de calidez. Después de atacar, Hysilens consume Torrente de calidez y recupera <span class=\"stat\">60</span> pts. de energía. Durante esta batalla, el daño que inflige Hysilens aumenta en un <span class=\"stat\">{stat_1}%</span>. Después de lanzar un ATQ básico/habilidad básica contra el enemigo, todos los estados de Daño con el tiempo que tengan los enemigos atacados infligen un <span class=\"stat\">{stat_2}%</span>/<span class=\"stat\">{stat_3}%</span> del daño original.',0,'0'),(181,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema de la Ley','Efectivo durante toda la batalla. Tras lanzarse sobre Céridra, el Daño CRIT del personaje con Mérito militar aumenta en un <span class=\"stat\">{stat_1}%</span>. Cuando termina Ataque sorpresa, Céridra obtiene <span class=\"stat\">1</span> punto de carga.',0,'0'),(182,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema del Tiempo','Efectivo durante toda la batalla. Tras lanzarse sobre Larganoche, el daño que inflige Nox cuando lanza la habilidad de mnemoduende \"Sueños que desaparecen como el rocío\" aumenta en un <span class=\"stat\">{stat_1}%</span>. Después de que Larganoche lance su habilidad básica/habilidad definitiva, obtiene <span class=\"stat\">1</span> pt. de Memoria adicional. El efecto de aumento de Daño CRIT de la habilidad básica de Larganoche aumenta adicionalmente en una cantidad equivalente al <span class=\"stat\">{stat_2}%</span> del Daño CRIT de Larganoche.',0,'0'),(183,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema de la Tierra','Cuando el Demiurgo lanza su habilidad de mnemoduende, Dan Heng - Permansor Terrae obtiene Poema de la Tierra y los siguientes <span class=\"stat\">3</span> ataques de Espiridraco infligen un daño adicional del mismo tipo que el Camarada equivalente al <span class=\"stat\">{stat_1}%</span> del efecto de escudo del Camarada. Cuando Dan Heng - Permansor Terrae tiene Poema de la Tierra, el daño que inflige el Camarada aumenta en un <span class=\"stat\">{stat_2}%</span>. Al lanzarse sobre Dan Heng - Permansor Terrae, el Espiridraco adelanta su acción un <span class=\"stat\">100%</span>, en su siguiente acción obtiene el efecto de potenciación de la habilidad definitiva de Dan Heng - Permansor Terrae y el efecto de escudo proporcionado es un <span class=\"stat\">150%</span> del efecto de escudo original. Además, no consume potenciaciones de la habilidad definitiva de Dan Heng - Permansor Terrae.',0,'0'),(184,'Cyrene','Habilidad Exclusiva',NULL,NULL,NULL,'Apoyo','Poema del yo verdadero','Por cada compañero de equipo distinto (excepto el Demiurgo) del que Cirene haya recibido Remembranza, cuando el Demiurgo lanza Danza de flores y flechas, inflige una vez adicional un <span class=\"stat\">{stat_1}%</span> de sus PV máx. como Daño de <span class=\"element\">Hielo</span> a un enemigo al azar. Después de que Cirene lance la habilidad definitiva o al invocar al Demiurgo, el Demiurgo obtiene inmediatamente <span class=\"stat\">1</span> punto de Historia. Cuando tiene <span class=\"stat\">3</span> puntos de Historia, los consume todos, obtiene inmediatamente <span class=\"stat\">1</span> turno adicional y lanza automáticamente Danza de flores y flechas.',0,'0');
